modal_dialog_open = False

def _wrap_modal_dialog(fn):
    def _wrapped(*args, **kwargs):
        global modal_dialog_open
        modal_dialog_open = True
        try:
            return fn(*args, **kwargs)
        finally:
            modal_dialog_open = False
    return _wrapped

messagebox.showinfo = _wrap_modal_dialog(messagebox.showinfo)
messagebox.showwarning = _wrap_modal_dialog(messagebox.showwarning)
messagebox.showerror = _wrap_modal_dialog(messagebox.showerror)
messagebox.askyesno = _wrap_modal_dialog(messagebox.askyesno)
messagebox.askokcancel = _wrap_modal_dialog(messagebox.askokcancel)
messagebox.askretrycancel = _wrap_modal_dialog(messagebox.askretrycancel)
messagebox.askquestion = _wrap_modal_dialog(messagebox.askquestion)
messagebox.askyesnocancel = _wrap_modal_dialog(messagebox.askyesnocancel)
simpledialog.askstring = _wrap_modal_dialog(simpledialog.askstring)
simpledialog.askinteger = _wrap_modal_dialog(simpledialog.askinteger)
simpledialog.askfloat = _wrap_modal_dialog(simpledialog.askfloat)


# =========================================
#      *MPV DLL AUTO-DOWNLOAD + IMPORT
# =========================================

MPV_DLL_NAME = "libmpv-2.dll"
_MPV_RELEASE_API = "https://api.github.com/repos/zhongfly/mpv-winbuild/releases/latest"

def _get_app_dir():
    """Return the directory containing the running exe (frozen) or script (dev)."""
    if getattr(sys, 'frozen', False):
        return os.path.dirname(sys.executable)
    try:
        return os.path.dirname(os.path.abspath(__file__))
    except NameError:
        return os.path.dirname(os.path.abspath(sys.argv[0]))

def _mpv_dll_path():
    return os.path.join(_get_app_dir(), MPV_DLL_NAME)

def ensure_mpv_dll():
    """Return path to mpv-2.dll, downloading it automatically if missing.

    Safe to call before the Tk root window exists: creates a transient hidden
    root if needed and cleans it up afterwards.
    """
    import io as _io
    import queue as _queue
    import shutil as _shutil
    import subprocess as _subprocess
    import tempfile as _tempfile

    dll = _mpv_dll_path()
    if os.path.exists(dll):
        return dll

    # ── ensure there is a Tk root so messagebox / Toplevel work ──────────────
    _temp_root = None
    try:
        if tk._default_root is None:
            _temp_root = tk.Tk()
            _temp_root.withdraw()
    except Exception:
        pass

    try:
        if not messagebox.askyesno(
            "mpv not found",
            f"{MPV_DLL_NAME} was not found in the application folder.\n\n"
            "Download it automatically from GitHub? (~30 MB)\n\n"
            "This is required to play media.",
            icon="warning"
        ):
            messagebox.showerror(
                "Cannot continue",
                f"{MPV_DLL_NAME} is required. Exiting."
            )
            sys.exit(1)

        # ── progress dialog ───────────────────────────────────────────────────
        dlg = tk.Toplevel()
        dlg.title("Downloading mpv…")
        dlg.resizable(False, False)
        dlg.attributes("-topmost", True)
        dlg.protocol("WM_DELETE_WINDOW", lambda: None)   # block accidental close
        tk.Label(dlg, text=f"Downloading {MPV_DLL_NAME}, please wait…",
                 font=("Arial", 11)).pack(padx=24, pady=(16, 4))
        status_var = tk.StringVar(value="Connecting…")
        tk.Label(dlg, textvariable=status_var, font=("Arial", 9), fg="#aaa").pack(padx=24)
        pb = ttk.Progressbar(dlg, length=360, mode="determinate")
        pb.pack(padx=24, pady=(6, 18))
        dlg.update_idletasks()
        sw, sh = dlg.winfo_screenwidth(), dlg.winfo_screenheight()
        dlg.geometry(f"410x115+{(sw-410)//2}+{(sh-115)//2}")
        dlg.update()

        q = _queue.Queue()
        err_ref = [None]
        ok_ref  = [None]

        def _worker():
            try:
                q.put(("status", "Fetching release info…"))
                resp = requests.get(
                    _MPV_RELEASE_API, timeout=15,
                    headers={"User-Agent": "GuessTheAnime/auto-mpv-dl"}
                )
                resp.raise_for_status()
                assets = resp.json().get("assets", [])

                # Prefer mpv-dev-x86_64-*.7z (no lgpl, no v3, no debug)
                asset_url = None
                for a in assets:
                    n = a["name"]
                    if (n.startswith("mpv-dev-x86_64-") and n.endswith(".7z")
                            and "lgpl" not in n and "v3" not in n):
                        asset_url = a["browser_download_url"]
                        break
                if not asset_url:
                    names = [a['name'] for a in assets]
                    raise RuntimeError(
                        "No mpv-dev-x86_64 .7z found in the latest GitHub release.\n"
                        f"Available assets: {names}\n"
                        "https://github.com/zhongfly/mpv-winbuild/releases"
                    )

                q.put(("status", f"Downloading {os.path.basename(asset_url)}…"))
                resp = requests.get(
                    asset_url, stream=True, timeout=180,
                    headers={"User-Agent": "GuessTheAnime/auto-mpv-dl"}
                )
                resp.raise_for_status()
                total = int(resp.headers.get("content-length", 0))
                buf = _io.BytesIO()
                downloaded = 0
                for chunk in resp.iter_content(chunk_size=131072):
                    if chunk:
                        buf.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            q.put(("progress", downloaded, total))

                q.put(("status", "Extracting libmpv-2.dll…"))
                buf.seek(0)
                tmp_dir = _tempfile.mkdtemp(prefix="gta_mpv_")
                try:
                    tmp_7z_path = os.path.join(tmp_dir, "mpv-dev.7z")
                    with open(tmp_7z_path, "wb") as _f:
                        _f.write(buf.read())

                    # Find 7-Zip (installed) or download 7zr.exe (standalone, ~400 KB)
                    exe_7z = (_shutil.which("7z") or _shutil.which("7za") or
                              next((p for p in [
                                  r"C:\Program Files\7-Zip\7z.exe",
                                  r"C:\Program Files (x86)\7-Zip\7z.exe",
                              ] if os.path.exists(p)), None))
                    if not exe_7z:
                        q.put(("status", "Downloading 7zr.exe (one-time, ~400 KB)…"))
                        exe_7z = os.path.join(tmp_dir, "7zr.exe")
                        r7z = requests.get(
                            "https://www.7-zip.org/a/7zr.exe",
                            timeout=30,
                            headers={"User-Agent": "GuessTheAnime/auto-mpv-dl"}
                        )
                        r7z.raise_for_status()
                        with open(exe_7z, "wb") as _f:
                            _f.write(r7z.content)

                    q.put(("status", "Extracting libmpv-2.dll…"))
                    out_dir = os.path.dirname(dll)
                    result = _subprocess.run(
                        [exe_7z, "e", tmp_7z_path, MPV_DLL_NAME,
                         f"-o{out_dir}", "-y"],
                        capture_output=True, text=True
                    )
                    if result.returncode != 0:
                        raise RuntimeError(
                            f"7-Zip extraction failed (code {result.returncode}):\n"
                            f"{result.stderr or result.stdout}"
                        )
                finally:
                    _shutil.rmtree(tmp_dir, ignore_errors=True)
                if os.path.exists(dll):
                    ok_ref[0] = dll
                if not ok_ref[0]:
                    raise RuntimeError(
                        f"{MPV_DLL_NAME} was not found inside the downloaded archive."
                    )
                q.put(("done", dll))
            except Exception as exc:
                err_ref[0] = str(exc)
                q.put(("error", str(exc)))

        def _poll():
            try:
                while True:
                    msg = q.get_nowait()
                    kind = msg[0]
                    if kind == "progress":
                        _, dl, tot = msg
                        pb["value"] = dl / tot * 100
                        status_var.set(f"{dl/1048576:.1f} / {tot/1048576:.1f} MB")
                    elif kind == "status":
                        status_var.set(msg[1])
                    elif kind in ("done", "error"):
                        dlg.destroy()
                        return
            except Exception:
                pass
            dlg.after(80, _poll)

        threading.Thread(target=_worker, daemon=True).start()
        dlg.after(80, _poll)
        dlg.wait_window()

        if err_ref[0]:
            messagebox.showerror(
                "Download failed",
                f"Could not download {MPV_DLL_NAME}:\n\n{err_ref[0]}\n\n"
                "Please download it manually and place it next to the exe:\n"
                "https://github.com/zhongfly/mpv-winbuild/releases\n"
                "(get mpv-dev-x86_64-*.7z, extract mpv-2.dll)"
            )
            sys.exit(1)

        return dll

    finally:
        if _temp_root:
            try:
                _temp_root.destroy()
            except Exception:
                pass


# Ensure libmpv-2.dll is present, then import
ensure_mpv_dll()
# Add app dir to PATH so python-mpv can find the DLL via ctypes
_app_dir = _get_app_dir()
if _app_dir not in os.environ.get("PATH", ""):
    os.environ["PATH"] = _app_dir + os.pathsep + os.environ.get("PATH", "")
try:
    import mpv as _mpv_module
    mpv = _mpv_module
except Exception as _mpv_err:
    try:
        messagebox.showerror(
            "mpv load error",
            f"Failed to load mpv:\n\n{_mpv_err}\n\n"
            "Please ensure libmpv-2.dll is in the application folder."
        )
    except Exception:
        print(f"FATAL: Failed to load mpv: {_mpv_err}")
    sys.exit(1)


# =========================================
#      *MEDIA PLAYER WRAPPER
# =========================================

class MediaPlayer:
    """
    Unified media-player abstraction - Phase 2: mpv backend.

    All time values are in milliseconds (consistent with the rest of the app).
    Volume uses the 0-200 scale that the app has always used (mpv 0-100 is doubled).
    """

    def __init__(self, mpv_player):
        self._p = mpv_player          # underlying mpv.MPV instance
        # Register double-click to toggle fullscreen (mirrors Player default behaviour)
        try:
            self._p.command('keybind', 'MBTN_LEFT_DBL', 'cycle fullscreen')
        except Exception:
            pass
        # Close button stops playback (hides window) without destroying the player instance
        try:
            self._p.command('keybind', 'CLOSE_WIN', 'stop')
        except Exception:
            pass

    # ---- Core playback ----
    def play(self):
        """Resume playback (does NOT load a new file)."""
        try:
            self._p.pause = False
        except Exception:
            pass

    def pause(self):
        try:
            self._p.pause = True
        except Exception:
            pass

    def stop(self):
        try:
            self._p.stop()
        except Exception:
            pass

    def is_playing(self) -> bool:
        try:
            return (not self._p.pause) and (not self._p.core_idle) and (self._p.time_pos is not None)
        except Exception:
            return False

    # ---- Time (all in milliseconds) ----
    def get_time_ms(self) -> int:
        try:
            return max(0, int((self._p.time_pos or 0) * 1000))
        except Exception:
            return 0

    def set_time_ms(self, ms: int):
        try:
            self._p.seek(ms / 1000.0, 'absolute+exact')
        except Exception:
            pass

    def get_length_ms(self) -> int:
        try:
            return max(0, int((self._p.duration or 0) * 1000))
        except Exception:
            return 0

    # ---- Time: compat shims (same unit — ms) ----
    def get_time(self) -> int:    return self.get_time_ms()
    def set_time(self, ms: int):  self.set_time_ms(ms)
    def get_length(self) -> int:  return self.get_length_ms()

    # ---- Volume: 0-200 scale (app convention) ----
    def set_volume(self, v: int):
        try:
            self._p.volume = max(0.0, min(100.0, v / 2.0))
        except Exception:
            pass

    def get_volume(self) -> int:
        try:
            return int((self._p.volume or 0) * 2)
        except Exception:
            return 0

    # ---- Volume: compat shims ----
    def audio_set_volume(self, v: int):    self.set_volume(v)
    def audio_get_volume(self) -> int:     return self.get_volume()

    def audio_set_mute(self, muted: bool):
        try:
            self._p.mute = bool(muted)
        except Exception:
            pass

    def audio_get_mute(self) -> bool:
        try:
            return bool(self._p.mute)
        except Exception:
            return False

    # ---- Speed ----
    def set_speed(self, rate: float):
        try:
            self._p.speed = rate
        except Exception:
            pass

    def set_rate(self, rate: float):  self.set_speed(rate)  # compat

    # ---- Fullscreen ----
    def set_fullscreen(self, b: bool):
        try:
            self._p.fullscreen = bool(b)
        except Exception:
            pass

    def toggle_fullscreen(self):
        try:
            self._p.fullscreen = not self._p.fullscreen
        except Exception:
            pass

    # ---- Video info ----
    def get_video_size(self) -> tuple:
        try:
            w, h = self._p.width, self._p.height
            if w and h:
                return (w, h)
        except Exception:
            pass
        return (0, 0)

    def video_get_size(self, track=0) -> tuple:
        return self.get_video_size()

    # ---- Media loading ----
    def load(self, path: str, opts: list = None):
        """Load and play a file/URL. opts is ignored (mpv handles format detection)."""
        self.set_media(path)

    def unload(self):
        """Stop and clear current media."""
        try:
            self._p.stop()
        except Exception:
            pass

    def get_path(self) -> str:
        """Return the path/URL of the currently loaded file, or None."""
        try:
            return self._p.path
        except Exception:
            return None

    def set_media(self, path_or_none):
        """Load path/URL and start playing, or stop if None."""
        if path_or_none is None:
            self.unload()
        else:
            try:
                self._p.play(str(path_or_none))
            except Exception:
                pass

    def get_media(self):
        """Return the currently loaded path string (compat shim)."""
        return self.get_path()

    # ---- State compat (no-op with mpv) ----
    def get_state(self):
        return None

    # ---- Window embedding (Phase 3) ----
    def set_hwnd(self, hwnd: int):
        try:
            self._p.wid = str(hwnd)
        except Exception:
            pass


player = None

def _mpv_opts(**extra):
    """Return common mpv.MPV constructor keyword arguments."""
    return dict(
        keep_open='yes',
        idle='yes',
        input_default_bindings=False,
        input_vo_keyboard=False,
        osc=False,
        force_media_title='Guess the Anime! - Playlist Tool',
        auto_window_resize='no',
        **extra
    )

# Create the main mpv player instance
try:
    player = MediaPlayer(mpv.MPV(**_mpv_opts(force_window='no')))
    # When mpv goes idle without Python having called stop() (e.g. user closes the
    # window via CLOSE_WIN → mpv stop), schedule our Python stop() on the main thread.
    # Debounced: ignore transient idle-active=True flips that occur during seeks.
    _idle_stop_after_id = None
    def _on_player_idle(name, is_idle):
        global _idle_stop_after_id
        if is_idle and globals().get('currently_playing'):
            # Snapshot currently_playing now (on mpv thread) so the 400ms callback
            # isn't fooled by later state changes.
            _cp_snapshot = globals().get('currently_playing')
            def _do_idle_stop(snapshot=_cp_snapshot):
                global _idle_stop_after_id
                _idle_stop_after_id = None
                # Only call stop() if currently_playing hasn't changed since we fired
                # (i.e. stop() wasn't already called by something else).
                if globals().get('currently_playing') is snapshot and snapshot:
                    try:
                        globals()['stop']()
                    except Exception:
                        pass
            try:
                root = globals().get('root')
                if root:
                    _idle_stop_after_id = root.after(200, _do_idle_stop)
            except Exception:
                pass
        elif not is_idle:
            # idle-active went False (seek completed / playback resumed) — cancel pending stop
            try:
                root = globals().get('root')
                if root and _idle_stop_after_id is not None:
                    root.after_cancel(_idle_stop_after_id)
                    _idle_stop_after_id = None
            except Exception:
                pass
    player._p.observe_property('idle-active', _on_player_idle)

    def _on_fullscreen_change(name, is_fs):
        # Sync autoplay_fullscreen when the user toggles fullscreen in mpv while a video
        # is actively playing (double-click, TAB, etc.). Do NOT sync during startup or
        # shutdown — mpv exits fullscreen on close which would poison the saved preference.
        # Use time_pos instead of is_playing() so a momentary pause (e.g. from the click
        # handler firing on the first half of a double-click) doesn't block the sync.
        try:
            root = globals().get('root')
            p = globals().get('player')
            if root and p and p._p.time_pos is not None:
                root.after(0, lambda: globals().update({'autoplay_fullscreen': bool(is_fs)}))
        except Exception:
            pass
    player._p.observe_property('fullscreen', _on_fullscreen_change)

    def _on_osd_width_change(name, new_w):
        """Re-render the coming-up PIL image overlay when the OSD is resized."""
        try:
            if not globals().get('_coming_up_osd_visible'):
                return
            frame = globals().get('_coming_up_current_frame')
            if not frame:
                return
            title_text, details, pil_image = frame
            osd_w, osd_h = int(player._p.osd_width or 0), int(player._p.osd_height or 0)
            if not osd_w or not osd_h:
                return
            target_y = max(4, round(osd_h * 0.014))
            _root = globals().get('root')
            if _root:
                _root.after(0, lambda: _render_coming_up_frame(
                    title_text, details, pil_image, target_y, osd_w, osd_h, 1.0))
        except Exception:
            pass
    player._p.observe_property('osd-width', _on_osd_width_change)

    @player._p.event_callback('playback-restart')
    def _on_playback_restart(_):
        """Fired once per file load when the first frame is ready and OSD dims are valid.
        Reapplies blind/reveal overlays that may have been lost during the mpv OSD reset."""
        try:
            _root = globals().get('root')
            if not _root:
                return
            def _reapply():
                _bo = globals().get('black_overlay')
                _cache = globals().get('_blind_osd_color_cache', 'black')
                # Reapply blind OSD (covers blind rounds AND the pre-load cover for reveal rounds)
                if _bo:
                    _set_blind_osd_alpha(_cache, 255)
                # For non-lightning reveal rounds: reapply active peek overlay then lift blind
                if not globals().get('light_mode') and not globals().get('light_round_started'):
                    _fvf = globals().get('filter_vf_active')
                    _fvf_var = globals().get('_filter_vf_variant')
                    _eo = globals().get('edge_overlay_box')
                    _po = globals().get('peek_overlay1')
                    _go = globals().get('grow_overlay_boxes')
                    # Reapply ASS-based overlays (osd dims are now valid)
                    if _fvf and _fvf_var:
                        toggle_filter_vf(_fvf_var, globals().get('_filter_vf_last_progress', [0.0])[0])
                    if _eo:
                        toggle_edge_overlay(block_percent=99)
                    if _po:
                        toggle_peek_overlay()
                    # If any peek overlay is active and we put up a pre-load black screen, lift it
                    if _bo and (_fvf or _eo or _po or _go):
                        _root.after(50, lambda: set_black_screen(False))
            _root.after(0, _reapply)
        except Exception:
            pass

    def _on_eof_reached(name, value):
        """Observed property: fires when eof-reached changes.
        Only True on natural playback end (keep_open=yes pauses at last frame).
        Does NOT fire for stop(), player.stop(), or window close."""
        try:
            if not value:
                return
            _root = globals().get('root')
            if _root:
                _root.after(0, _handle_video_end)
        except Exception:
            pass
    player._p.observe_property('eof-reached', _on_eof_reached)

    # Click inside the mpv window → play/pause (Windows API window subclassing).
    # player._p.window_id gives the HWND once mpv creates its window.
    # We subclass the window proc to intercept WM_LBUTTONDOWN/WM_LBUTTONUP.
    # Time-based detection: clicks < 300 ms; drags take longer.
    _mpv_wndproc_refs = {}  # hwnd → (new_proc, original_proc); keeps ctypes objects alive
    _mpv_click_queue   = queue.Queue()  # thread-safe click signals from mpv wndproc → main thread
    _playpause_pending = [None]          # root.after ID for deferred play_pause (double-click guard)

    def _setup_mpv_click_handler(hwnd):
        import ctypes, ctypes.wintypes, time as _time
        if not hwnd or hwnd in _mpv_wndproc_refs:
            return
        GWL_WNDPROC = -4
        WM_LBUTTONDOWN   = 0x0201
        WM_LBUTTONUP     = 0x0202
        WM_LBUTTONDBLCLK = 0x0203
        _press_time       = [None]
        _last_down_time   = [0.0]
        _is_double_press  = [False]
        # System double-click interval (ms → s); used to detect the second press
        # when the window class does NOT have CS_DBLCLKS (no WM_LBUTTONDBLCLK).
        _DBLCLK_S = ctypes.windll.user32.GetDoubleClickTime() / 1000.0
        # Must set restype to c_ssize_t; default c_int truncates 64-bit pointers.
        _GetWindowLongPtrW = ctypes.windll.user32.GetWindowLongPtrW
        _GetWindowLongPtrW.restype = ctypes.c_ssize_t
        _SetWindowLongPtrW = ctypes.windll.user32.SetWindowLongPtrW
        _SetWindowLongPtrW.restype = ctypes.c_ssize_t
        _CallWindowProcW = ctypes.windll.user32.CallWindowProcW
        _CallWindowProcW.restype = ctypes.c_ssize_t
        _CallWindowProcW.argtypes = [
            ctypes.c_ssize_t, ctypes.wintypes.HWND, ctypes.wintypes.UINT,
            ctypes.wintypes.WPARAM, ctypes.wintypes.LPARAM,
        ]
        original = _GetWindowLongPtrW(hwnd, GWL_WNDPROC)
        WNDPROC = ctypes.WINFUNCTYPE(
            ctypes.c_ssize_t,
            ctypes.wintypes.HWND, ctypes.wintypes.UINT,
            ctypes.wintypes.WPARAM, ctypes.wintypes.LPARAM,
        )
        def _wndproc(h, msg, wp, lp):
            if msg == WM_LBUTTONDOWN:
                now = _time.monotonic()
                _is_double_press[0] = (now - _last_down_time[0]) < _DBLCLK_S
                _last_down_time[0] = now
                _press_time[0] = now
            elif msg == WM_LBUTTONUP:
                pt = _press_time[0]
                _press_time[0] = None
                if pt is not None and _time.monotonic() - pt < 0.3:
                    if _is_double_press[0]:
                        # Second UP of double-click (no-CS_DBLCLKS case) — cancel first.
                        _mpv_click_queue.put_nowait(None)
                    else:
                        # Normal single click — queue it for deferred processing.
                        # Do NOT call root.after() here: this callback runs on mpv's
                        # window thread and touching the Tcl/Tk lock deadlocks when
                        # the main thread holds it.
                        _mpv_click_queue.put_nowait(True)
            elif msg == WM_LBUTTONDBLCLK:
                # CS_DBLCLKS IS set: replaces the second WM_LBUTTONDOWN.
                # Cancel the first click and reset state so the following LBUTTONUP
                # and the next single-click are not misidentified as doubles.
                _mpv_click_queue.put_nowait(None)
                _press_time[0] = None    # suppress the upcoming LBUTTONUP
                _last_down_time[0] = 0.0  # prevent next click being flagged as double
            return _CallWindowProcW(original, h, msg, wp, lp)
        new_proc = WNDPROC(_wndproc)
        _SetWindowLongPtrW(hwnd, GWL_WNDPROC, new_proc)
        _mpv_wndproc_refs[hwnd] = (new_proc, original)

    def _on_mpv_window_id(name, value):
        try:
            hwnd = int(value or 0)
            if hwnd:
                # Call directly — SetWindowLongPtrW is thread-safe and
                # _setup_mpv_click_handler no longer touches Tcl/Tk.
                # Also works before root exists (at startup).
                _setup_mpv_click_handler(hwnd)
        except Exception:
            pass

    player._p.observe_property('window-id', _on_mpv_window_id)

except Exception as _e:
    try:
        messagebox.showerror("mpv error", f"Failed to create mpv player:\n{_e}")
    except Exception:
        print(f"FATAL: Failed to create mpv player: {_e}")
    sys.exit(1)

def _poll_mpv_clicks():
    """Main-thread poller that drains _mpv_click_queue and calls play_pause().

    The mpv wndproc callback runs on mpv's window thread and cannot safely call
    root.after() (which acquires the Tcl/Tk interpreter lock).  Instead it puts
    a sentinel on _mpv_click_queue; this function polls that queue every 50 ms
    from the main thread where Tk calls are safe.
    """
    try:
        while not _mpv_click_queue.empty():
            item = _mpv_click_queue.get_nowait()
            if item is True:
                # Defer play_pause by 200 ms.  This gives the cancel sentinel from
                # the second click of a double-click time to arrive and abort the
                # timer before it fires, without any perceptible lag on single clicks.
                if _playpause_pending[0] is None:
                    def _fire(_pending=_playpause_pending):
                        _pending[0] = None
                        if not (globals().get('grow_overlay_boxes') or (
                                globals().get('filter_vf_active') and
                                globals().get('_filter_vf_variant') == 'zoom')):
                            play_pause()
                    _playpause_pending[0] = root.after(200, _fire)
            elif item is None:
                # Cancel any pending deferred play_pause.
                if _playpause_pending[0] is not None:
                    root.after_cancel(_playpause_pending[0])
                    _playpause_pending[0] = None
    except Exception:
        pass
    root.after(50, _poll_mpv_clicks)

