def _migrate_old_file_structure():
    """One-time migration from the legacy 'files/' folder to the new folder layout.

    Explicit files:
      files/config.json          → config/config.json
      files/cache_metadata.json  → themes_cache/cache_metadata.json
      files/censors.json         → censors/censors.json
      files/ramuns_censors.json  → censors/ramuns_censors.json

    All *.json files in files/ ending with 'rules.json' (case-insensitive) → rules/

    After migration, removes 'files/' if it is empty.

    Preset migration (saved_lightning_mode_settings / saved_infinite_settings) always
    runs against config/config.json so it works even if files/ was already removed.
    """
    if os.path.exists("files"):
        explicit = [
            (os.path.join("files", "config.json"),         CONFIG_FILE),
            (os.path.join("files", "cache_metadata.json"), CACHE_METADATA_FILE),
            (os.path.join("files", "censors.json"),        CENSOR_JSON_FILE),
            (os.path.join("files", "ramuns_censors.json"), os.path.join(CENSORS_FOLDER, "ramuns_censors.json")),
        ]
        for src, dst in explicit:
            if os.path.exists(src) and not os.path.exists(dst):
                os.makedirs(os.path.dirname(dst) or ".", exist_ok=True)
                os.replace(src, dst)
                print(f"Migrated {src} → {dst}")

        # Move all rules files (any *.json ending with 'rules.json') to rules/
        try:
            for fname in os.listdir("files"):
                if fname.lower().endswith("rules.json") and os.path.isfile(os.path.join("files", fname)):
                    dst = os.path.join(RULES_FOLDER, fname)
                    if not os.path.exists(dst):
                        os.makedirs(RULES_FOLDER, exist_ok=True)
                        os.replace(os.path.join("files", fname), dst)
                        print(f"Migrated files/{fname} → {dst}")
        except Exception as e:
            print(f"Warning: rules migration error: {e}")

        # Remove files/ if now empty (ignoring subdirectories)
        try:
            remaining = [f for f in os.listdir("files") if os.path.isfile(os.path.join("files", f))]
            if not remaining:
                # Only remove the folder itself if there are no subdirectories either
                if not any(os.path.isdir(os.path.join("files", d)) for d in os.listdir("files")):
                    os.rmdir("files")
                    print("Removed empty 'files/' folder.")
        except Exception:
            pass

    # Migrate saved_lightning_mode_settings and saved_infinite_settings from config.json.
    # This runs unconditionally so it works even when files/ was already removed in a prior run.
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r", encoding="utf-8") as f:
                old_config = json.load(f)
            for name, diff in old_config.get("saved_lightning_mode_settings", {}).items():
                dst = os.path.join(LIGHTNING_SETTINGS_FOLDER, f"{name}.json")
                if not os.path.exists(dst):
                    os.makedirs(LIGHTNING_SETTINGS_FOLDER, exist_ok=True)
                    with open(dst, "w", encoding="utf-8") as f:
                        json.dump(diff, f, indent=4)
                    print(f"Migrated lightning preset '{name}' \u2192 {dst}")
            for name, diff in old_config.get("saved_infinite_settings", {}).items():
                dst = os.path.join(INFINITE_SETTINGS_FOLDER, f"{name}.json")
                if not os.path.exists(dst):
                    os.makedirs(INFINITE_SETTINGS_FOLDER, exist_ok=True)
                    with open(dst, "w", encoding="utf-8") as f:
                        json.dump(diff, f, indent=4)
                    print(f"Migrated infinite preset '{name}' \u2192 {dst}")
    except Exception as e:
        print(f"Warning: preset migration error: {e}")

def _migrate_playlist_names():
    """Rename legacy system playlist files: 'Peek Themes' → 'Reveal Themes',
    'Mute Peek Themes' → 'Mute Reveal Themes'."""
    renames = [
        ("Peek Themes.json",      "Reveal Themes.json"),
        ("Mute Peek Themes.json", "Mute Reveal Themes.json"),
    ]
    for old_name, new_name in renames:
        old_path = os.path.join(PLAYLISTS_FOLDER, old_name)
        new_path = os.path.join(PLAYLISTS_FOLDER, new_name)
        if os.path.exists(old_path) and not os.path.exists(new_path):
            try:
                os.replace(old_path, new_path)
                print(f"Migrated playlist '{old_name}' \u2192 '{new_name}'")
            except Exception as e:
                print(f"Warning: could not rename playlist '{old_name}': {e}")

_load_settings_presets = utils._load_settings_presets

def _load_popout_layout_presets():
    """Return {name: {layout: [...], columns: N}} for all saved popout layout presets."""
    presets = {}
    if not os.path.exists(POPOUT_LAYOUTS_FOLDER):
        return presets
    for fname in sorted(os.listdir(POPOUT_LAYOUTS_FOLDER)):
        if fname.endswith(".json"):
            name = fname[:-5]
            try:
                with open(os.path.join(POPOUT_LAYOUTS_FOLDER, fname), "r", encoding="utf-8") as f:
                    presets[name] = json.load(f)
            except Exception as e:
                print(f"Failed to load popout layout preset '{fname}': {e}")
    return presets

def _save_popout_layout_preset(name, layout_list, columns):
    """Write a single popout layout preset to POPOUT_LAYOUTS_FOLDER/<name>.json."""
    os.makedirs(POPOUT_LAYOUTS_FOLDER, exist_ok=True)
    path = os.path.join(POPOUT_LAYOUTS_FOLDER, f"{name}.json")
    _atomic_json_write(path, {"layout": layout_list, "columns": columns}, indent=4)

def _atomic_json_write(path, data, **dump_kwargs): return utils._atomic_json_write(path, data, **dump_kwargs)

_save_settings_presets = utils._save_settings_presets

def save_config():
    """Function to save configuration"""
    files_folder = os.path.dirname(CONFIG_FILE)  # Get the folder path

    if not os.path.exists(files_folder):
        os.makedirs(files_folder)
    lightning_diff = compute_settings_diff(lightning_mode_settings_default, lightning_mode_settings) or {}

    _save_settings_presets(LIGHTNING_SETTINGS_FOLDER, saved_lightning_mode_settings,
                           lightning_mode_settings_default, update_fn=update_lightning_mode_settings)
    _save_settings_presets(INFINITE_SETTINGS_FOLDER, saved_infinite_settings,
                           INFINITE_SETTINGS_DEFAULT, convert_inf=True)
    _save_settings_presets(BONUS_SETTINGS_FOLDER, saved_bonus_settings, BONUS_SETTINGS_DEFAULT)

    config = {
        "host": host,
        **{s["config_key"]: globals()[s["key"]] for s in SETTINGS_SCHEMA},
        "color_options": OVERLAY_COLOR_OPTIONS,
        "directory": directory,
        "lightning_mode_settings": lightning_diff,
        "selected_light_mode_settings": selected_light_mode_settings,
        "selected_infinite_settings": selected_infinite_settings,
        "bonus_settings": compute_settings_diff(BONUS_SETTINGS_DEFAULT, bonus_settings) or {},
        "selected_bonus_settings": selected_bonus_settings,
        "popout_layout": popout_layout if popout_layout is not None else [],
        "metadata_last_updated": metadata_last_updated,
        "censors_last_updated": censors_last_updated,
        "popout_columns": popout_columns,
        "shortcuts": globals().get("shortcuts_config", {}),
        "playlist": playlist,
        "directory_files": directory_files,
        "tutorial_shown": globals().get("tutorial_shown", False),
        "set_toggles": {
            "censors_enabled": censors.censors_enabled,
            "censors_nsfw_enabled": censors.censors_nsfw_enabled,
            "auto_info_start": auto_info_start,
            "auto_info_end": auto_info_end,
            "auto_refresh_toggle": auto_refresh_toggle,
            "disable_shortcuts": disable_shortcuts,
            "progress_bar_enabled": progress_bar_enabled,
            "autoplay_fullscreen": autoplay_fullscreen,
            "mpv_always_on_top": mpv_always_on_top,
            "player_collapsed": player_collapsed,
        },
    }
    
    # Convert infinities and diff infinite_settings against defaults before saving
    if playlist.get("infinite_settings"):
        config["playlist"] = copy.deepcopy(playlist)
        inf_diff = compute_settings_diff(INFINITE_SETTINGS_DEFAULT, config["playlist"]["infinite_settings"]) or {}
        config["playlist"]["infinite_settings"] = convert_infinities_to_markers(inf_diff)
    
    update_current_index(save = False)
    _atomic_json_write(CONFIG_FILE, config, indent=4, allow_nan=False)

_migrate_theme_flags = utils._migrate_theme_flags

def load_config():
    """Function to load configuration"""
    # NOTE: `playlist` and `directory_files` are intentionally NOT declared
    # global here. They are mutated in place (clear + update) so the
    # module-level aliases and `state.metadata.*` keep the same identity.
    global directory, host, inverted_colors, scoreboard_rules
    global metadata_last_updated, censors_last_updated, OVERLAY_COLOR_OPTIONS
    global selected_light_mode_settings, saved_lightning_mode_settings
    global selected_infinite_settings, saved_infinite_settings
    global saved_bonus_settings, selected_bonus_settings
    global INVERSE_OVERLAY_BACKGROUND_COLOR, INVERSE_OVERLAY_TEXT_COLOR, MIDDLE_OVERLAY_BACKGROUND_COLOR
    global popout_layout, popout_columns, shortcuts_config
    # Schema settings loaded via config keys below
    global auto_info_start, auto_info_end, auto_refresh_toggle, disable_shortcuts, tutorial_shown, progress_bar_enabled, autoplay_fullscreen, mpv_always_on_top
    # Read-only schema settings — declared global so static analyzers (Pylance)
    # can see they're module-level (assigned indirectly via `globals()[k] = v` below).
    global OPENAI_API_KEY, selected_rules_file, OVERLAY_BACKGROUND_COLOR, OVERLAY_TEXT_COLOR, volume_level, keep_set_toggles
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r") as f:
                config = json.load(f)
            # Convert infinity markers back to float('inf')
            config = convert_infinity_markers(config)
            # Load all schema settings
            _type_cast = {"int": int, "float": float, "bool": bool}
            for _s in SETTINGS_SCHEMA:
                _val = config.get(_s["config_key"], _s["default"])
                _cast = _type_cast.get(_s["type"])
                globals()[_s["key"]] = _cast(_val) if _cast else _val
            host = config.get("host", "")
            _loaded_playlist = config.get("playlist", copy.deepcopy(BLANK_PLAYLIST))
            playlist.clear()
            playlist.update(_loaded_playlist)
            if playlist.get("infinite_settings") is not None:
                def _deep_merge(base, override):
                    result = copy.deepcopy(base)
                    for k, v in override.items():
                        if isinstance(v, dict) and isinstance(result.get(k), dict):
                            result[k] = _deep_merge(result[k], v)
                        else:
                            result[k] = copy.deepcopy(v)
                    return result
                playlist["infinite_settings"] = _deep_merge(INFINITE_SETTINGS_DEFAULT, playlist["infinite_settings"])
            if "background_track_history" not in playlist:
                playlist["background_track_history"] = []
            _migrate_theme_flags(playlist.get("filter", {}))
            _loaded_directory_files = config.get("directory_files", {})
            directory_files.clear()
            directory_files.update(_loaded_directory_files)
            directory = config.get("directory", "themes")
            scoreboard_rules = load_rules(selected_rules_file)
            set_rules()
            lightning_mode_settings.clear()
            lightning_mode_settings.update(update_lightning_mode_settings(config.get("lightning_mode_settings", copy.deepcopy(lightning_mode_settings_default))))
            selected_light_mode_settings = config.get("selected_light_mode_settings", "")
            saved_lightning_mode_settings = convert_infinity_markers(_load_settings_presets(LIGHTNING_SETTINGS_FOLDER))

            selected_infinite_settings = config.get("selected_infinite_settings", "")
            saved_infinite_settings = convert_infinity_markers(_load_settings_presets(INFINITE_SETTINGS_FOLDER))

            saved_bonus_settings = _load_settings_presets(BONUS_SETTINGS_FOLDER)
            for _bn, _bd in saved_bonus_settings.items():
                saved_bonus_settings[_bn] = sync_with_default(copy.deepcopy(_bd), BONUS_SETTINGS_DEFAULT)
            bonus_settings.clear()
            bonus_settings.update(sync_with_default(
                copy.deepcopy(config.get("bonus_settings", {})), BONUS_SETTINGS_DEFAULT
            ))
            selected_bonus_settings = config.get("selected_bonus_settings", "")
            if selected_bonus_settings and selected_bonus_settings in saved_bonus_settings:
                bonus_settings.clear()
                bonus_settings.update(copy.deepcopy(saved_bonus_settings[selected_bonus_settings]))
            
            inverted_colors = config.get("inverted_colors", False)
            # mpv players do not need per-load recreation
            try:
                set_volume(volume_level)
            except Exception:
                pass
            if selected_light_mode_settings and selected_light_mode_settings in saved_lightning_mode_settings:
                # A named template is selected — load it (overrides the inline saved settings)
                lightning_mode_settings.clear()
                lightning_mode_settings.update(update_lightning_mode_settings(saved_lightning_mode_settings[selected_light_mode_settings]))
            
            if selected_infinite_settings and selected_infinite_settings in saved_infinite_settings:
                infinite_settings.clear()
                infinite_settings.update(sync_with_default(copy.deepcopy(saved_infinite_settings[selected_infinite_settings]), INFINITE_SETTINGS_DEFAULT))
            
            if OPENAI_API_KEY:
                set_openai_client_key()
            metadata_fetch.set_credentials(IGDB_CLIENT_ID, IGDB_CLIENT_SECRET)
            cache_download.update_settings(
                themes_cache_size=themes_cache_size,
                auto_download_themes=auto_download_themes,
                app_version=APP_VERSION,
            )
            streaming.update_settings(youtube_api_key=YOUTUBE_API_KEY)
            try:
                update_playlist_name()
                update_current_index()
            except Exception:
                pass
            OVERLAY_COLOR_OPTIONS = config.get("color_options", ["black", "white"])
            INVERSE_OVERLAY_BACKGROUND_COLOR = config.get("text_color", "white")
            INVERSE_OVERLAY_TEXT_COLOR = config.get("back_color", "black")
            MIDDLE_OVERLAY_BACKGROUND_COLOR = interpolate_color(OVERLAY_BACKGROUND_COLOR, INVERSE_OVERLAY_BACKGROUND_COLOR, 0.6)
            send_scoreboard_colors()
            metadata_last_updated = config.get("metadata_last_updated", 0)
            censors_last_updated = config.get("censors_last_updated", 0)
            # Popout layout — None means "use default"
            _saved_layout = config.get("popout_layout", None)
            popout_layout = _saved_layout if _saved_layout else None  # empty list → None (use default)
            popout_columns = int(config.get("popout_columns", 5))
            shortcuts_config = config.get("shortcuts", {})
            tutorial_shown = config.get("tutorial_shown", False)
            web_server.set_host_password(HOST_PASSWORD)
            if keep_set_toggles:
                _t = config.get("set_toggles", {})
                if "censors_enabled" in _t:
                    censors.censors_enabled = bool(_t["censors_enabled"])
                if "censors_nsfw_enabled" in _t:
                    censors.censors_nsfw_enabled = bool(_t["censors_nsfw_enabled"])
                if "auto_info_start" in _t:
                    auto_info_start = bool(_t["auto_info_start"])
                if "auto_info_end" in _t:
                    auto_info_end = bool(_t["auto_info_end"])
                if "auto_refresh_toggle" in _t:
                    auto_refresh_toggle = bool(_t["auto_refresh_toggle"])
                if "disable_shortcuts" in _t:
                    disable_shortcuts = bool(_t["disable_shortcuts"])
                if "progress_bar_enabled" in _t:
                    progress_bar_enabled = bool(_t["progress_bar_enabled"])
                if "autoplay_fullscreen" in _t:
                    autoplay_fullscreen = bool(_t["autoplay_fullscreen"])
                if "mpv_always_on_top" in _t:
                    mpv_always_on_top = bool(_t["mpv_always_on_top"])
                    try:
                        player._p.ontop = mpv_always_on_top
                    except Exception:
                        pass
                if _t.get("player_collapsed") and not player_collapsed:
                    globals()["_pending_restore_collapsed"] = True
    except Exception as e:
        os.remove(CONFIG_FILE)
        print(f"Error loading config: {e}")
        return False
    return False

interpolate_color = utils.interpolate_color

# Color interpolation functions

settings_window = None
tutorial_shown = False  # Written to config after first launch
class ToolTip:
    """Hover tooltip for any Tkinter widget."""
    def __init__(self, widget, text):
        self.widget = widget
        self.text = text
        self.tooltip_window = None
        self._after_id = None
        widget.bind("<Enter>", self.show_tooltip)
        widget.bind("<Leave>", self.hide_tooltip)

    def show_tooltip(self, event=None):
        self._after_id = self.widget.after(1000, self._display)

    def _display(self):
        if self.tooltip_window or not self.text:
            return
        x = self.widget.winfo_rootx() + 20
        y = self.widget.winfo_rooty() + self.widget.winfo_height() + 5
        self.tooltip_window = tw = tk.Toplevel(self.widget)
        tw.wm_overrideredirect(True)
        tw.wm_geometry(f"+{x}+{y}")
        tw.attributes("-topmost", True)
        tk.Label(tw, text=self.text, justify="left",
                 background="#ffffe0", relief="solid", borderwidth=1,
                 font=("Arial", 9), wraplength=400).pack()

    def hide_tooltip(self, event=None):
        if self._after_id:
            self.widget.after_cancel(self._after_id)
            self._after_id = None
        if self.tooltip_window:
            self.tooltip_window.destroy()
            self.tooltip_window = None

def show_settings_popup():
    """Opens a settings popup for editing configuration values."""
    global settings_window

    if settings_window and settings_window.winfo_exists():
        try:
            settings_window.destroy()
        except tk.TclError:
            pass
        settings_window = None

    def is_valid_color(color):
        if not color:
            return False
        if color.startswith('#'):
            hex_part = color[1:]
            if len(hex_part) in (3, 6):
                try:
                    int(hex_part, 16)
                    return True
                except ValueError:
                    return False
            return False
        try:
            test_frame = tk.Frame(settings_window, bg=color)
            test_frame.destroy()
            return True
        except tk.TclError:
            return False

    def add_color(color_var, dropdown):
        new_color = simpledialog.askstring("Add Color",
            "Enter color name or hex code:\n\n"
            "Examples:\n"
            "• Color names: darkblue, lightgreen, gold\n"
            "• Hex codes: #FF5733, #00FF00, #123ABC")
        if new_color:
            new_color = new_color.strip()
            if new_color in OVERLAY_COLOR_OPTIONS:
                messagebox.showinfo("Color Already Exists", f"'{new_color}' is already in the color list.")
                return
            if is_valid_color(new_color):
                OVERLAY_COLOR_OPTIONS.append(new_color)
                dropdown['values'] = OVERLAY_COLOR_OPTIONS
                color_var.set(new_color)
            else:
                messagebox.showerror("Invalid Color",
                    f"'{new_color}' is not a valid color.\n\n"
                    "Please use:\n"
                    "• Valid color names (red, blue, darkgreen, etc.)\n"
                    "• Valid hex codes (#FF5733, #00FF00, etc.)")

    def delete_color(color_var, back_dd, text_dd):
        current_color = color_var.get()
        if not current_color:
            messagebox.showwarning("No Color Selected", "Please select a color to delete.")
            return
        default_colors = ["black", "white", "red", "green", "blue", "yellow", "cyan", "magenta",
                          "gray", "orange", "purple", "pink", "brown", "lime", "navy", "maroon"]
        if current_color in default_colors:
            messagebox.showwarning("Cannot Delete", f"'{current_color}' is a default color and cannot be deleted.")
            return
        if not messagebox.askyesno("Delete Color", f"Delete '{current_color}' from the color list?"):
            return
        if current_color in OVERLAY_COLOR_OPTIONS:
            OVERLAY_COLOR_OPTIONS.remove(current_color)
            back_dd['values'] = OVERLAY_COLOR_OPTIONS
            text_dd['values'] = OVERLAY_COLOR_OPTIONS
            color_var.set("black")

    def save_settings():
        global serpapi_limited, serpapi_limited_count
        try:
            # Snapshot originals for after_save callbacks
            _orig = {s["key"]: globals()[s["key"]] for s in SETTINGS_SCHEMA if s.get("after_save")}

            # Apply all schema settings from their tk vars
            for s in SETTINGS_SCHEMA:
                if s["key"] not in _setting_vars:
                    continue
                var = _setting_vars[s["key"]]
                t = s["type"]
                if t == "int":
                    val = int(var.get())
                elif t == "float":
                    val = float(var.get())
                elif t == "bool":
                    val = var.get()
                else:  # str, password, color, rules_file
                    val = var.get().strip()
                if t in ("int", "float"):
                    if "min" in s:
                        val = max(s["min"], val)
                    if "max" in s:
                        val = min(s["max"], val)
                globals()[s["key"]] = val

            save_config()
            load_config()

            # After-save callbacks
            for s in SETTINGS_SCHEMA:
                after = s.get("after_save")
                if after == "restart_warning":
                    if _orig[s["key"]] != globals()[s["key"]]:
                        messagebox.showinfo("Restart Required",
                                            "The 'Scale Main UI' setting has been changed.\n\n"
                                            "Please restart the application for this change to take effect.")
                elif after == "reset_serpapi":
                    if _orig[s["key"]] != globals()[s["key"]]:
                        serpapi_limited = False
                        serpapi_limited_count = 0

            save_btn.config(text="SAVED!", bg="darkgreen")
            settings_window.after(300, lambda: save_btn.config(text="SAVE SETTINGS", bg="black"))

        except ValueError as e:
            messagebox.showerror("Invalid Value", f"Settings must be valid numbers.\nError: {e}")

    # Create popup window
    settings_window = tk.Toplevel(bg=BACKGROUND_COLOR)
    settings_window.title("Configuration Settings")
    settings_window.resizable(False, False)

    def on_settings_close():
        global settings_window
        if settings_window and settings_window.winfo_exists():
            settings_window.destroy()
        settings_window = None

    settings_window.protocol("WM_DELETE_WINDOW", on_settings_close)

    try:
        settings_window.transient(root)
        get_window_position_and_setup(settings_window)
    except tk.TclError:
        pass

    main_frame = tk.Frame(settings_window, bg=BACKGROUND_COLOR)
    main_frame.pack(padx=15, pady=15)

    # Two-column layout
    cols_frame = tk.Frame(main_frame, bg=BACKGROUND_COLOR)
    cols_frame.pack(fill="x")
    col_left  = tk.Frame(cols_frame, bg=BACKGROUND_COLOR)
    col_right = tk.Frame(cols_frame, bg=BACKGROUND_COLOR)
    col_left.pack(side="left", anchor="n", padx=(0, 20))
    col_right.pack(side="left", anchor="n")

    # tk vars keyed by schema key
    _setting_vars = {}
    # color dropdown widget refs (for shared delete_color)
    _color_dropdowns = {}

    def _render_simple_row(s, parent):
        """Auto-render a row for int / float / str / password / bool schema entries."""
        frame = tk.Frame(parent, bg=BACKGROUND_COLOR)
        frame.pack(fill="x", pady=5)
        lbl = tk.Label(frame, text=s["label"], bg=BACKGROUND_COLOR, fg="white", width=20, anchor="w")
        lbl.pack(side="left")
        if s.get("tooltip"):
            ToolTip(lbl, s["tooltip"])
        t = s["type"]
        if t == "bool":
            var = tk.BooleanVar(value=globals()[s["key"]])
            text_var = tk.StringVar(value="Enabled" if globals()[s["key"]] else "Disabled")
            btn = tk.Checkbutton(frame, variable=var, textvariable=text_var,
                                 bg=BACKGROUND_COLOR, fg="white", selectcolor="black",
                                 command=lambda v=var, tv=text_var: tv.set("Enabled" if v.get() else "Disabled"))
            btn.pack(side="left", padx=(5, 0))
        else:
            var = tk.StringVar(value=str(globals()[s["key"]]))
            kw = {"textvariable": var, "bg": "black", "fg": "white",
                  "insertbackground": "white",
                  "width": s.get("width", 10), "justify": "center"}
            if t == "password":
                kw["show"] = "*"
                kw["justify"] = "left"
            tk.Entry(frame, **kw).pack(side="left", padx=(5, 0))
        _setting_vars[s["key"]] = var

    def _render_skip_group(parent):
        """Render the four skip settings as a single consolidated row."""
        group = [s for s in SETTINGS_SCHEMA if s.get("group") == "skip_group"]
        frame = tk.Frame(parent, bg=BACKGROUND_COLOR)
        frame.pack(fill="x", pady=5)
        lbl = tk.Label(frame, text=group[0]["label"], bg=BACKGROUND_COLOR, fg="white", width=20, anchor="w")
        lbl.pack(side="left")
        ToolTip(lbl, "Auto-skip settings: play duration, jump distance, and fade timing.")
        inputs = tk.Frame(frame, bg=BACKGROUND_COLOR)
        inputs.pack(side="left", padx=(5, 0))
        for sg in group:
            var = tk.StringVar(value=str(globals()[sg["key"]]))
            entry = tk.Entry(inputs, textvariable=var, bg="black", fg="white",
                             insertbackground="white",
                             width=sg.get("width", 6), justify="center")
            entry.pack(side="left", padx=(0, 3))
            if sg.get("tooltip"):
                ToolTip(entry, sg["tooltip"])
            _setting_vars[sg["key"]] = var

    def _render_color_row(s, parent):
        """Render a color dropdown row with add/delete buttons."""
        frame = tk.Frame(parent, bg=BACKGROUND_COLOR)
        frame.pack(fill="x", pady=5)
        lbl = tk.Label(frame, text=s["label"], bg=BACKGROUND_COLOR, fg="white", width=20, anchor="w")
        lbl.pack(side="left")
        ToolTip(lbl, s["tooltip"])
        var = tk.StringVar(value=globals()[s["key"]])
        dropdown = ttk.Combobox(frame, textvariable=var, values=OVERLAY_COLOR_OPTIONS, width=15)
        dropdown.pack(side="left", padx=(5, 2))
        _setting_vars[s["key"]] = var
        _color_dropdowns[s["key"]] = dropdown
        tk.Button(frame, text="➕", bg="black", fg="white", width=3,
                  command=lambda v=var, d=dropdown: add_color(v, d)).pack(side="left", padx=(0, 2))
        def _make_delete(cv):
            def _do():
                delete_color(cv,
                             _color_dropdowns.get("OVERLAY_BACKGROUND_COLOR"),
                             _color_dropdowns.get("OVERLAY_TEXT_COLOR"))
            return _do
        tk.Button(frame, text="❌", bg="black", fg="white", width=3,
                  command=_make_delete(var)).pack(side="left")

    def _render_rules_file_row(s, parent):
        """Render the rules-file folder-scanned dropdown."""
        frame = tk.Frame(parent, bg=BACKGROUND_COLOR)
        frame.pack(fill="x", pady=5)
        lbl = tk.Label(frame, text=s["label"], bg=BACKGROUND_COLOR, fg="white", width=20, anchor="w")
        lbl.pack(side="left")
        ToolTip(lbl, s["tooltip"])
        var = tk.StringVar(value=globals()[s["key"]])
        ttk.Combobox(frame, textvariable=var, values=get_available_rules_files(),
                     width=25, state="readonly").pack(side="left", padx=(5, 0))
        _setting_vars[s["key"]] = var

    # Collect visible rows first so we can split evenly
    _visible_rows = []
    _skip_group_seen = False
    for s in SETTINGS_SCHEMA:
        if s.get("requires_ngrok") and not NGROK_AVAILABLE:
            continue
        if s.get("requires_cloudflared") and not CLOUDFLARED_AVAILABLE:
            continue
        if s.get("requires_tunnel") and not (NGROK_AVAILABLE or CLOUDFLARED_AVAILABLE):
            continue
        if s.get("requires_scoreboard") and not scoreboard_control.AVAILABLE:
            continue
        if s.get("group") == "skip_group":
            if not _skip_group_seen:
                _visible_rows.append(("skip_group", None))
                _skip_group_seen = True
            continue
        _visible_rows.append((s["type"], s))

    # Split into two roughly equal columns
    half = (len(_visible_rows) + 1) // 2
    for i, (t, s) in enumerate(_visible_rows):
        parent = col_left if i < half else col_right
        if t == "skip_group":
            _render_skip_group(parent)
        elif t == "color":
            _render_color_row(s, parent)
        elif t == "rules_file":
            _render_rules_file_row(s, parent)
        else:
            _render_simple_row(s, parent)

    # Buttons
    button_frame = tk.Frame(main_frame, bg=BACKGROUND_COLOR)
    button_frame.pack(fill="x", pady=(20, 0))

    save_btn = tk.Button(button_frame, text="SAVE SETTINGS", command=save_settings,
                         bg="black", fg="white", font=("Arial", 12, "bold"), width=15)
    save_btn.pack(side="left", padx=(3, 10))

    tk.Button(button_frame, text="CANCEL", command=on_settings_close,
              bg="black", fg="white", font=("Arial", 12, "bold"), width=15).pack(side="left")

