def append_lightning_history():
    data = currently_playing.get("data", {})
    mode_limits = lightning_mode_settings.get(light_mode, {}).get("variety", {}).get("cooldown")
    if mode_limits and mode_limits.get("no_repeat_limit", 0) > 0:
        if "c." in light_mode:
            append = character_round_answer[0]
        elif light_mode == "title":
            append = get_base_title()
        else:
            append = data.get("mal")
        if append:
            history_by_mode = playlist.get("lightning_history")
            if not isinstance(history_by_mode, dict):
                history_by_mode = {}
                playlist["lightning_history"] = history_by_mode
            history_by_mode.setdefault(light_mode, []).append(append)
            while len(history_by_mode[light_mode]) > mode_limits.get("no_repeat_limit"):
                history_by_mode[light_mode].pop(0)

def check_recent_history(mode, data=None):
    if not data:
        data = currently_playing.get("data", {})
    mode_limits = lightning_mode_settings.get(mode, {}).get("variety", {}).get("cooldown")
    if mode_limits and mode_limits.get("no_repeat_limit"):
        if "c." in mode:
            data = currently_playing.get("data", {})
            history = playlist.get("lightning_history", {}).get(mode, [])
            valid_types = get_char_types_by_popularity(data, mode)
            for char in data.get("characters", []):
                role = char[0]
                name = char[1]
                if role in valid_types and name not in history:
                    return False  # Found a character not in history
            return True  # All valid characters are in history
        elif mode == "title":
            append_check = get_base_title(data)
        else:
            append_check = data.get("mal")

        if append_check:
            return append_check in playlist.get("lightning_history", {}).get(mode, [])
    return False

_series_popularity_cache = None
def get_series_popularity(data):
    global _series_popularity_cache

    if _series_popularity_cache is None:
        _series_popularity_cache = {}
        for anime in anime_metadata.values():
            pop = anime.get("popularity") or 10000
            for s in series_list(anime, fallback_title=False):
                if s not in _series_popularity_cache or pop < _series_popularity_cache[s]:
                    _series_popularity_cache[s] = pop

    pops = [_series_popularity_cache[s] for s in series_list(data, fallback_title=False) if s in _series_popularity_cache]
    return min(pops) if pops else (data.get("popularity") or 10000)

is_slug_op = utils.is_slug_op

lightning_queue = None
lightning_queue_data = {}
def queue_next_lightning_mode():
    def queue_next_lightning_mode_worker():
        global lightning_queue
        lightning_queue = None
        fixed_data = None
        next_fixed_round = None
        if fixed_lightning_queue or fixed_lightning_round_playlist_data:
            fixed_data = fixed_lightning_round_playlist_data or fixed_lightning_queue

            if fixed_data.get("current_index", 0)+1 >= len(fixed_data.get("rounds", [])):
                return
            next_fixed_round = fixed_data.get("rounds", [])[fixed_data.get("current_index", -1)+1]
            next_filename = next_fixed_round.get("theme")
        else:
            next_index = playlist["current_index"] + 1
            if next_index < len(playlist["playlist"]) and (get_file_path(playlist["playlist"][next_index]) or is_animethemes_stream_file(playlist["playlist"][next_index])):
                next_filename = get_clean_filename(playlist["playlist"][next_index])
            else:
                return
        
        data = get_metadata(next_filename)
        if next_filename not in lightning_queue_data:
            lightning_queue_data[next_filename] = {}

        excluded_modes = []
        next_mode = None
        while not next_mode:
            if next_fixed_round:
                next_mode = next_fixed_round.get("type")
            elif variety_light_mode_enabled:
                next_mode = set_variety_light_mode(next_filename, excluded_modes=excluded_modes)
            else:
                next_mode = light_mode
            if next_mode in ["clip", 'ost']:
                clip_variants = lightning_mode_settings.get("clip", {}).get("variants", {})
                clip_enabled, trailer_enabled = clip_variants.get("random_clip"), clip_variants.get("trailer")
                url, name, channel, length = None, None, None, None
                yt_source_url = None  # Original YouTube URL (url may be resolved CDN URL for fixed rounds)
                if next_fixed_round:
                    clip_url = next_fixed_round.get("clip_url")
                    yt_source_url = clip_url
                    url, length, name, channel = get_youtube_stream_url(clip_url, include_other_info=True)
                    name = next_fixed_round.get("clip_title") or name
                    channel = next_fixed_round.get("clip_author") or channel
                else:
                    if not streaming.youtube_api_limited and YOUTUBE_API_KEY and clip_enabled:
                        url, name, channel = play_random_clip(data, True, ost=(next_mode=='ost'))
                    if url:
                        yt_source_url = url
                        length = get_youtube_stream_url(url)
                    elif next_mode != 'ost' and data.get("trailer") and trailer_enabled:
                        url = f"https://www.youtube.com/watch?v={data.get("trailer")}"
                        yt_source_url = url
                        name = "trailer"
                        channel = None
                        length = get_youtube_stream_url(url)
                    elif variety_light_mode_enabled:
                        excluded_modes.append(next_mode)
                        next_mode = None
                if next_mode == "ost":
                    lightning_queue_data[next_filename]["ost_url"] = [url, name, channel, length]
                else:
                    lightning_queue_data[next_filename]["clip_url"] = [url, name, channel, length]
                # Pre-download to local cache if the setting is enabled and ffmpeg is available
                if yt_source_url and ffmpeg_available:
                    cache_mb = int(lightning_mode_settings.get("_misc_settings", {}).get("download_cache_mb", 0))
                    always_dl = lightning_mode_settings.get("_misc_settings", {}).get("always_download_clip", False)
                    # When always_download_clip is on and no cache size is configured, use 500 MB as headroom
                    effective_cache_mb = cache_mb if cache_mb > 0 else (500 if always_dl else 0)
                    if effective_cache_mb > 0:
                        cache_path = _get_yt_cache_path(yt_source_url)
                        if cache_path and not os.path.exists(cache_path) and not os.path.exists(cache_path + '.part'):
                            threading.Thread(
                                target=_yt_cache_download_bg,
                                args=(yt_source_url, cache_path, effective_cache_mb),
                                daemon=True
                            ).start()
            elif "c. " in next_mode:
                min_desc = 0
                if next_mode == 'c. profile':
                    min_desc = 120
                lightning_queue_data[next_filename]["character_answer"] = get_character_round_image(types=get_char_types_by_popularity(data, next_mode), min_desc_length=min_desc, data=data, queue=True, mode=next_mode)
            elif next_mode == "character":
                lightning_queue_data[next_filename]["characters"] = get_character_round_characters(data=data, queue=True)
            elif next_mode == "trivia":
                if not fixed_data:
                    trivia_question = set_light_trivia(data=data, queue=True)
                    if trivia_question[1] == "None" and variety_light_mode_enabled:
                        excluded_modes.append('trivia')
                        next_mode = None
                    else:
                        lightning_queue_data[next_filename]["trivia"] = trivia_question
            elif next_mode == "emoji":
                if not data.get("emojis"):
                    get_emoji_clues_for_title(data)
            elif next_mode == "image":
                if next_fixed_round and next_fixed_round.get("image_url"):
                    image_url = next_fixed_round.get("image_url")
                else:
                    image_url = get_google_image_url(data)
                if image_url:
                    lightning_queue_data[next_filename]["image_url"] = image_url
                elif variety_light_mode_enabled:
                    excluded_modes.append("image")
                    next_mode = None
        up_next_text()
    
    if light_mode or fixed_lightning_queue or fixed_lightning_round_playlist_data:
        threading.Thread(target=queue_next_lightning_mode_worker, daemon=True).start()

def set_variety_light_mode(queue=None, excluded_modes=[]):
    global last_round, variety_light_mode_enabled, lightning_queue, last_variety_forced

    forced = False
    if not queue and lightning_queue and lightning_queue[0] == currently_playing.get("filename"):
        next_round = lightning_queue[1]
    else:
        if queue:
            data = get_metadata(queue)
        else:
            data = currently_playing.get('data', {})
        popularity = ((data.get('popularity') or 3000) + get_series_popularity(data)) / 2
        
        is_op = is_slug_op(data.get('slug', ""))
        
        variety_settings = lightning_mode_settings.get("variety", {})
        popularity_limit = variety_settings.get("popularity_limit", True)
        series_mode_limit = variety_settings.get("series_mode_limit", True)
        mode_weight = variety_settings.get("mode_weight", True)
        mode_cooldowns = variety_settings.get("mode_cooldowns", True)

        round_options = []
        for rnd_name, rnd_data in lightning_mode_settings.items():
            v_data = rnd_data.get("variety", {})
            if v_data and v_data["enabled"] and rnd_name not in excluded_modes:
                pop_limit = v_data.get("popularity", {})
                range = pop_limit.get("range", (0,0))
                if not popularity_limit:
                    range = (0,0)
                weight = pop_limit.get("weight", 10)
                if not mode_weight:
                    weight = 1
                elif isinstance(weight, dict):
                    if is_op:
                        weight = weight.get("op")
                    else:
                        weight = weight.get("ed")
                if has_lightning_mode_info(data, rnd_name) and popularity > range[0] and (not range[1] or popularity <= range[1]):
                    round_options += [rnd_name]*weight

        # Remove last round from options to avoid repeats
        round_options = [r for r in round_options if r != last_round]

        # Apply cooldown filtering
        forced_options = []
        forced_max_pop_limit = 3000
        for rnd_name, rnd_data in lightning_mode_settings.items():
            v_data = rnd_data.get("variety", {})
            cd = v_data.get("cooldown", {})
            min_cooldown = cd.get("min_gap", 0)
            max_cooldown = cd.get("max_gap", 10000)
            if not mode_cooldowns:
                min_cooldown = 0
                max_cooldown = 10000
            max_popularity_limit = cd.get("popularity_force_threshold") or INT_INF
            if isinstance(max_popularity_limit, dict):
                if is_op:
                    max_popularity_limit = max_popularity_limit.get("op") or INT_INF
                else:
                    max_popularity_limit = max_popularity_limit.get("ed") or INT_INF
            if rnd_name in round_options:
                count = variety_mode_cooldown_counts.get(rnd_name, 0)
                if (series_mode_limit and check_recent_history(rnd_name, data)) or count < min_cooldown:
                    round_options = [r for r in round_options if r != rnd_name]
                elif (max_cooldown and count >= max_cooldown) and popularity <= max_popularity_limit:
                    if forced_options:
                        if forced_max_pop_limit == max_popularity_limit:
                            forced_options.append(rnd_name)
                        elif forced_max_pop_limit < max_popularity_limit:
                            continue
                    forced_options = [rnd_name]
                    forced_max_pop_limit = max_popularity_limit

        if forced_options:
            next_round = random.choice(forced_options)
            last_variety_forced = True
            forced = True
        elif not round_options:
            next_round = "regular"
        else:
            random.shuffle(round_options)
            next_round = round_options[0]

        if queue:
            lightning_queue = [queue, next_round]
            return next_round
    
    # Update cooldown counters
    for rnd_name in lightning_mode_settings:
        if rnd_name == next_round:
            variety_mode_cooldown_counts[rnd_name] = 0
        else:
            variety_mode_cooldown_counts[rnd_name] += 1

    last_round = next_round

    if not testing_variety:
        unselect_light_modes()
        toggle_light_mode(next_round, False, False)
        variety_light_mode_enabled = True
    return next_round, forced

def has_lightning_mode_info(data, round_type):
    """Returns True if the given round_type has enough info for the file's data."""
    if round_type == "clues":
        return len(get_tags(data)) >= 3
    elif round_type == "song":
        return get_song_string(data, "artist_string") != "N/A"
    elif round_type == "synopsis":
        return len((data.get("synopsis") or "").split()) > 40
    elif round_type == "title":
        return len(get_base_title(data).replace(" ", "")) >= 7
    elif round_type == "character":
        return len(data.get("characters", [])) >= 4
    elif round_type == "cover":
        return bool(data.get("cover"))
    elif round_type == "image":
        return fixed_lightning_queue or fixed_lightning_round_playlist_data or (SERPAPI_KEY and not serpapi_limited)
    elif round_type == "tags":
        return len(data.get("tags", [])) >= 10
    elif round_type == "episodes":
        return len(data.get("episode_info", [])) >= 6 and check_valid_episodes(data)
    elif round_type == "clip":
        return not is_game(data) and not ((streaming.youtube_api_limited or not YOUTUBE_API_KEY) and not data.get("trailer"))
    elif round_type == "ost":
        return not (streaming.youtube_api_limited or not YOUTUBE_API_KEY)
    elif round_type == "trivia":
        return data.get("trivia") or (OPENAI_API_KEY and (int(data.get("season", "9999")[-4:]) <= gpt_cutoff_year or len((data.get("synopsis") or "").split()) > 40))
    elif round_type == "emoji":
        return bool(data.get("emojis")) or OPENAI_API_KEY
    elif round_type == "names":
        return len(data.get("characters", [])) >= 6
    elif round_type in ["c. reveal", "c. profile", "c. name"]:
        if not data.get("characters"):
            return False
        if round_type == "c. profile":
            return has_char_descriptions(
                data.get("characters"), 
                120, 
                types=get_char_types_by_popularity(data, mode="c. profile"),
                anilist_id=data.get("anilist")
            )
        return True
    else:
        return True

testing_variety = False

# =========================================
#          *FRAME LIGHTNING ROUND
# =========================================

frame_light_round_started = False
frame_light_round_frames = None
frame_light_round_frame_index = None
frame_light_round_frame_time = None
frame_light_round_pause = False

def get_frame_light_round_frames():
    frames = []
    if fixed_lightning_round_playlist_data and fixed_current_round:
        for f in range(4):
            frames.append(fixed_current_round.get('frame'+str(f+1)))
        return frames
    buffer = 5
    video_length_ms = player.get_length()
    total_length = video_length_ms - ((buffer + light_round_answer_length + 1) * 1000)
    start_time_ms = buffer * 1000
    end_time_ms = start_time_ms + total_length
    
    # Get file censors and build list of valid time ranges (excluding skip censors)
    file_censors = get_file_censors(currently_playing.get('filename'))
    
    # Build list of valid time ranges by excluding skip censors
    valid_ranges = []
    current_start = start_time_ms / 1000
    
    # Sort censors by start time
    skip_censors = [c for c in file_censors if c.get('skip')]
    skip_censors.sort(key=lambda c: c['start'])
    
    for censor in skip_censors:
        censor_start = censor['start']
        censor_end = censor['end'] if censor['end'] else video_length_ms / 1000
        
        # Add the valid range before this skip censor
        if current_start < censor_start and current_start < end_time_ms / 1000:
            range_end = min(censor_start, end_time_ms / 1000)
            if range_end > current_start:
                valid_ranges.append((current_start, range_end))
        
        # Move past this skip censor
        current_start = max(current_start, censor_end)
    
    # Add final range after all skip censors
    if current_start < end_time_ms / 1000:
        valid_ranges.append((current_start, end_time_ms / 1000))
    
    # If no valid ranges, fall back to original behavior
    if not valid_ranges:
        valid_ranges = [(start_time_ms / 1000, end_time_ms / 1000)]
    
    # Calculate total valid time
    total_valid_time = sum(end - start for start, end in valid_ranges)
    quadrant_time = total_valid_time / 4
    
    # Select one frame from each quadrant of valid time
    for quadrant in range(4):
        target_time_start = quadrant * quadrant_time
        target_time_end = (quadrant + 1) * quadrant_time
        
        # Find which valid range(s) this quadrant falls into
        frame = None
        try_count = 0
        
        while frame is None and try_count < 20:
            accumulated_time = 0
            # Find the valid range that contains our target time
            random_time_in_quadrant = random.uniform(target_time_start, target_time_end)
            
            for range_start, range_end in valid_ranges:
                range_duration = range_end - range_start
                if accumulated_time <= random_time_in_quadrant < accumulated_time + range_duration:
                    # This range contains our random point
                    offset = random_time_in_quadrant - accumulated_time
                    frame = range_start + offset
                    
                    is_censored = False
                    for censor in file_censors:
                        if not censor.get('skip') and not censor.get('mute'):
                            if frame > censor['start'] and frame < censor['end']:
                                is_censored = True
                                break
                    
                    if is_censored:
                        frame = None
                        try_count += 1
                        break
                    
                    if total_length > 60000 and len(frames) > 0 and (frame - frames[-1]) <= 5:
                        frame = None
                        try_count += 1
                        break
                    
                    break
                
                accumulated_time += range_duration
        
        # If we couldn't find a valid frame after 20 tries, pick any time in the quadrant
        if frame is None:
            accumulated_time = 0
            random_time_in_quadrant = random.uniform(target_time_start, target_time_end)
            for range_start, range_end in valid_ranges:
                range_duration = range_end - range_start
                if accumulated_time <= random_time_in_quadrant < accumulated_time + range_duration:
                    offset = random_time_in_quadrant - accumulated_time
                    frame = range_start + offset
                    break
                accumulated_time += range_duration
        
        if frame is not None:
            frames.append(frame)
    
    random.shuffle(frames)
    return frames

def setup_frame_light_round():
    global frame_light_round_started, frame_light_round_frames, frame_light_round_frame_index, frame_light_round_frame_time, frame_light_round_pause
    toggle_coming_up_popup(False, "Lightning Round")
    frame_light_round_started = True
    player.pause()
    frame_light_round_frames = get_frame_light_round_frames()
    frame_light_round_frame_index = -1
    frame_light_round_frame_time = 5000
    frame_light_round_pause = False
    play_background_music(True)
    update_light_round_number()
    if lightning_mode_settings.get("_misc_settings", {}).get("framed_video"):
        root.after(300, set_video_frame, True)
    # Increased delay to give video more time to load before attempting first frame
    root.after(1000, update_frame_light_round, currently_playing.get('filename'))
    root.after(1300, set_black_screen, False)

def update_frame_light_round(currently_playing_filename):
    global frame_light_round_frame_index, frame_light_round_frame_time
    
    if not frame_light_round_started or currently_playing.get('filename') != currently_playing_filename:
        return

    show_frame_length = (light_round_length/4)*1000
    if not frame_light_round_pause:
        if not player.is_playing():
            if frame_light_round_frames and 0 <= frame_light_round_frame_index < len(frame_light_round_frames):
                time = int(frame_light_round_frames[frame_light_round_frame_index]*1000)
                length = player.get_length()
                apply_censors(time/1000,length/1000)
        frame_light_round_frame_time = frame_light_round_frame_time + SEEK_POLLING
        if frame_light_round_frame_index < 4:
            play_background_music(True)
            if player.is_playing():
                player.pause()
        else:
            player.play()
    else:
        play_background_music(False)
        if player.is_playing():
            player.pause()
    if frame_light_round_frame_index == 4:
        start_str = "next"
        if not light_mode or (fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("current_index") == fixed_lightning_round_playlist_data.get("round_count") - 1):
            start_str = "end"
        set_countdown(start_str + " in..." + str(round(((light_round_answer_length*1000)-frame_light_round_frame_time)/1000)))
        if frame_light_round_frame_time >= light_round_answer_length*1000:
            light_round_transition()
            return
    else:
        if frame_light_round_frame_index > -1:
            set_countdown(int(((light_round_length*1000)-((show_frame_length*frame_light_round_frame_index)+frame_light_round_frame_time))/1000))
        if frame_light_round_frame_time >= show_frame_length:
            # Check if video is loaded before attempting to show next frame
            length = player.get_length()
            if length <= 0:
                # Video not loaded yet, wait for next cycle without incrementing frame
                root.after(SEEK_POLLING, update_frame_light_round, currently_playing_filename)
                return
            
            frame_light_round_frame_index = frame_light_round_frame_index + 1
            if frame_light_round_frame_index < len(frame_light_round_frames):
                frame_light_round_frame_time = 0
                if frame_light_round_frame_index == 0:
                    frame_light_round_frame_time = -1000
                time = int(frame_light_round_frames[frame_light_round_frame_index]*1000)
                apply_censors(time/1000, length/1000)
                
                # Attempt to set time with retry limit to avoid infinite loop
                max_attempts = 20
                for attempt in range(max_attempts):
                    player.set_time(time)
                    root.update()  # Process pending events
                    if abs(player.get_time() - time) < 100:  # Within 100ms is close enough
                        break
                
                # Ensure player stays paused after seeking
                if player.is_playing():
                    player.pause()
                
                update_progress_bar(time, length, currently_playing.get("filename"))
                bottom_info(str(frame_light_round_frame_index+1) + "/" + str(len(frame_light_round_frames)))
            elif not is_title_window_up():
                frame_light_round_frame_time = 0
                player.play()
                toggle_title_popup(True)
                bottom_info()
                play_background_music(False)
    
    root.after(SEEK_POLLING, update_frame_light_round, currently_playing_filename)

# =========================================
#          *CLUES LIGHTNING ROUND
# =========================================

_clues_img_overlay = None
_clues_cell_values = {}   # key → text string currently displayed


def _draw_clues_canvas():
    """Render the current _clues_cell_values as an mpv PIL image overlay."""
    global _clues_img_overlay
    try:
        osd_w = int(player._p.osd_width  or 0)
        osd_h = int(player._p.osd_height or 0)
    except Exception:
        return
    if not osd_w or not osd_h:
        return

    modifier = min(osd_w / 2560, osd_h / 1440)
    def fs(pt): return max(6, round(pt * modifier * 1.15))

    try:
        r16, g16, b16 = root.winfo_rgb(OVERLAY_BACKGROUND_COLOR)
        bg_r, bg_g, bg_b = r16 >> 8, g16 >> 8, b16 >> 8
        r16, g16, b16 = root.winfo_rgb(OVERLAY_TEXT_COLOR)
        fg_r, fg_g, fg_b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        bg_r, bg_g, bg_b = 0,   0,   0
        fg_r, fg_g, fg_b = 255, 255, 255

    box_w   = round(osd_w * 0.70)
    box_h   = round(osd_h * 0.80)
    box_x   = (osd_w - box_w) // 2
    box_y   = (osd_h - box_h) // 2
    gap     = max(2, round(8  * modifier))
    pad     = max(4, round(16 * modifier))
    border  = max(1, round(4  * modifier))
    title_fs = fs(58)
    title_fnt = _get_ass_font(title_fs, bold=True)

    n_cols   = 3
    col_w    = (box_w - gap * (n_cols - 1)) // n_cols
    song_h   = round(box_h * 0.22)
    top_h    = box_h - song_h - gap
    # Row 0 is single-line values only — give it just enough height for title + one value line
    val_fs_approx = fs(70)
    row0_h   = title_fs + max(1, round(2 * modifier)) + max(1, round(2 * modifier)) + max(2, round(4 * modifier)) + val_fs_approx + 2 * pad
    row0_h   = min(row0_h, round(top_h * 0.34))   # cap at 34% so it can't dominate
    rows12_h = (top_h - row0_h - gap * 2) // 2    # rows 1 and 2 share the rest equally

    def cell_rect(row, col, colspan=1, rowspan=1):
        x = box_x + col * (col_w + gap)
        w = col_w * colspan + gap * (colspan - 1)
        if row == 0:
            y = box_y
            h = row0_h
        elif row == 1:
            y = box_y + row0_h + gap
            h = rows12_h * rowspan + gap * (rowspan - 1)
        elif row == 2:
            y = box_y + row0_h + gap + rows12_h + gap
            h = rows12_h
        else:                         # song row
            y = box_y + top_h + gap
            h = song_h
        return x, y, w, h

    # (key, row, col, colspan, rowspan, title_label)
    CELLS = [
        ("Type",     0, 0, 1, 1, "TYPE"),
        ("Source",   0, 1, 1, 1, "SOURCE"),
        ("Episodes", 0, 2, 1, 1, "EPISODES"),
        ("Season",   1, 0, 1, 1, "SEASON"),
        ("Studio",   1, 1, 1, 1, "STUDIO"),
        ("Tags",     1, 2, 1, 2, "TAGS"),
        ("Score",    2, 0, 1, 1, "SCORE"),
        ("Members",  2, 1, 1, 1, "MEMBERS"),
        ("Song",     3, 0, 3, 1, None),
    ]

    canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    draw   = ImageDraw.Draw(canvas)
    line_gap = max(1, round(2 * modifier))

    for key, row, col, colspan, rowspan, title_label in CELLS:
        cx, cy, cw, ch = cell_rect(row, col, colspan, rowspan)
        value = _clues_cell_values.get(key, "")

        draw.rectangle([cx, cy, cx + cw - 1, cy + ch - 1],
                       fill=(bg_r, bg_g, bg_b, 204),
                       outline=(fg_r, fg_g, fg_b, 200), width=border)

        iy = cy + pad
        inner_w = cw - 2 * pad

        # Title (bold, centred, underlined)
        if title_label and title_fnt:
            try:
                tw = round(title_fnt.getlength(title_label))
            except AttributeError:
                tw = len(title_label) * title_fs // 2
            tx = cx + (cw - tw) // 2
            draw.text((tx, iy), title_label,
                      font=title_fnt, fill=(fg_r, fg_g, fg_b, 255))
            ul_y = iy + title_fs + max(1, round(2 * modifier))
            ul_h = max(1, round(2 * modifier))
            draw.rectangle([tx, ul_y, tx + tw - 1, ul_y + ul_h - 1],
                           fill=(fg_r, fg_g, fg_b, 220))
            iy = ul_y + ul_h + max(2, round(4 * modifier))

        # Value (regular, auto-sized, height-clamped)
        if value:
            lines  = value.split('\n')
            val_pt = 70 - max(0, (len(lines) - 5) * 5)
            val_fs = fs(val_pt)
            remaining_h = cy + ch - pad - iy
            # Shrink until all lines fit vertically
            while val_fs > 6:
                total_text_h = len(lines) * val_fs + max(0, len(lines) - 1) * line_gap
                if total_text_h <= remaining_h:
                    break
                val_fs = max(6, val_fs - 1)
            val_fnt = _get_ass_font(val_fs, bold=False)
            if val_fnt:
                total_text_h  = len(lines) * val_fs + max(0, len(lines) - 1) * line_gap
                text_y        = iy + max(0, (remaining_h - total_text_h) // 2)
                for line in lines:
                    try:
                        lw = round(val_fnt.getlength(line))
                    except AttributeError:
                        lw = len(line) * val_fs // 2
                    fnt_use, lw_use = val_fnt, lw
                    if lw > inner_w and line:
                        scaled_fs = max(6, round(val_fs * inner_w / lw))
                        fnt_use = _get_ass_font(scaled_fs, bold=False)
                        try:
                            lw_use = round(fnt_use.getlength(line))
                        except AttributeError:
                            lw_use = len(line) * scaled_fs // 2
                    draw.text((cx + (cw - lw_use) // 2, text_y), line,
                              font=fnt_use, fill=(fg_r, fg_g, fg_b, 255))
                    text_y += val_fs + line_gap

    if _clues_img_overlay is None:
        _clues_img_overlay = player._p.create_image_overlay()
    _clues_img_overlay.update(canvas)


def toggle_clues_overlay(destroy=False, **_ignored):
    """Show or hide the clues lightning-round OSD (mpv PIL image overlay)."""
    global _clues_img_overlay, _clues_cell_values

    if destroy:
        _clues_cell_values = {}
        if _clues_img_overlay is not None:
            try:
                _clues_img_overlay.remove()
            except Exception:
                pass
            _clues_img_overlay = None
        return

    if _clues_cell_values:
        return  # already visible

    data = currently_playing.get("data")
    if not data:
        return

    _clues_cell_values = {
        "Type":     get_format(data),
        "Source":   data.get("source", ""),
        "Season":   data.get("season", "").replace(" ", "\n"),
        "Studio":   "\n".join(data.get("studios", [])),
        "Episodes": "",
        "Tags":     "",
        "Score":    "",
        "Members":  "",
        "Song":     "",
    }
    _draw_clues_canvas()

# =========================================
#          *SONG LIGHTNING ROUND
# =========================================

song_overlay_boxes = {}   # kept truthy {"active":True} while active — game-loop guard relies on it
_song_img_overlay = None
_song_anim_after = None
_song_base_cache = [None, None, 0, 0]   # [state_key, PIL Image, note_x, note_y]
_song_note_color = [None]
_song_note_px_cache = {}          # px → PIL font
_song_last_flags = {"show_title": True, "show_artist": True, "show_theme": True, "show_music": True}


def _draw_song_base(show_title, show_artist, show_theme, osd_w, osd_h):
    """Render the static song boxes (theme / title / artist) to a full OSD RGBA canvas."""
    from PIL import Image, ImageDraw
    modifier = min(osd_w / 2560, osd_h / 1440)
    def fs(pt): return max(6, round(pt * modifier))

    try:
        r16, g16, b16 = root.winfo_rgb(OVERLAY_BACKGROUND_COLOR)
        bg_r, bg_g, bg_b = r16 >> 8, g16 >> 8, b16 >> 8
        r16, g16, b16 = root.winfo_rgb(OVERLAY_TEXT_COLOR)
        fg_r, fg_g, fg_b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        bg_r, bg_g, bg_b = 0, 0, 0
        fg_r, fg_g, fg_b = 255, 255, 255

    bg   = (bg_r, bg_g, bg_b, 217)   # ~0.85 alpha
    fg   = (fg_r, fg_g, fg_b, 255)
    bdr_color = fg

    pad    = max(9, round(31 * modifier))
    border = max(1, round(4  * modifier))
    max_inner_w = round(osd_w * 0.72)
    cx = osd_w // 2

    data         = currently_playing.get("data", {})
    slug         = format_slug(data.get("slug"))
    song_title   = get_song_string(data, "title")
    artist_str   = get_song_string(data, "artist_string")
    theme_label  = format_slug(slug).upper()

    canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    draw   = ImageDraw.Draw(canvas)

    def truncate_fit(text, font, max_w):
        """Shorten text with ellipsis until it fits within max_w pixels."""
        bb = draw.textbbox((0, 0), text, font=font)
        if bb[2] - bb[0] <= max_w:
            return text, bb
        t = text
        while len(t) > 1:
            t = t[:-1]
            candidate = t.rstrip() + "\u2026"
            bb = draw.textbbox((0, 0), candidate, font=font)
            if bb[2] - bb[0] <= max_w:
                return candidate, bb
        return "\u2026", draw.textbbox((0, 0), "\u2026", font=font)

    def draw_box(header, body, y_top, hdr_fs_pt, body_fs_pt, body_fs_min_pt, measure_only=False):
        hdr_font = _get_ass_font(fs(hdr_fs_pt), bold=True)
        if not hdr_font:
            return
        # Header measurement
        hb = draw.textbbox((0, 0), header, font=hdr_font)
        hw = hb[2] - hb[0]
        hh = hb[3] - hb[1]
        # Body: reduce font until width fits, then truncate as last resort
        body_font = None
        bb = (0, 0, 0, 0)
        bw = bh = 0
        if body:
            bfs     = fs(body_fs_pt)
            bfs_min = fs(body_fs_min_pt)
            while bfs >= bfs_min:
                bf = _get_ass_font(bfs, bold=True)
                if bf:
                    b = draw.textbbox((0, 0), body, font=bf)
                    if b[2] - b[0] <= max_inner_w:
                        body_font = bf
                        bb = b
                        bw, bh = bb[2] - bb[0], bb[3] - bb[1]
                        break
                bfs = max(bfs_min, bfs - 2)
            if body_font is None:
                body_font = _get_ass_font(bfs_min, bold=True)
                if body_font:
                    body, bb = truncate_fit(body, body_font, max_inner_w)
                    bw, bh = bb[2] - bb[0], bb[3] - bb[1]
            else:
                # Even when it fitted, save adjusted bb for accurate positioning
                body, bb = truncate_fit(body, body_font, max_inner_w)
                bw, bh = bb[2] - bb[0], bb[3] - bb[1]
        # Underline bar
        ul_gap = max(2, round(3  * modifier))
        ul_h   = max(2, round(5  * modifier))
        # Box geometry
        content_h = hh + ul_gap + ul_h + (pad + bh if body_font and body else 0)
        box_h     = content_h + pad * 2
        box_w     = min(max(hw, bw) + pad * 2 + border * 2, round(osd_w * 0.80))
        bx        = cx - box_w // 2
        by        = round(y_top)
        if measure_only:
            return bx, by, box_w, box_h
        # Background + border
        draw.rectangle([bx, by, bx + box_w, by + box_h], fill=bg)
        draw.rectangle([bx, by, bx + box_w, by + box_h], outline=bdr_color, width=border)
        # Header — compensate bbox offsets so visual top lands at by+pad
        hx = cx - hw // 2 - hb[0]
        hy = by + pad - hb[1]
        draw.text((hx, hy), header, font=hdr_font, fill=fg)
        # Underline: only under the text, not the full box width
        ul_y  = hy + hb[3] + ul_gap
        ul_x0 = hx + hb[0]
        ul_x1 = hx + hb[2]
        draw.rectangle([ul_x0, ul_y, ul_x1, ul_y + ul_h], fill=fg)
        # Body — compensate bbox[0]/[1] so text is visually centred inside the box
        if body_font and body:
            bx2 = cx - bw // 2 - bb[0]
            by2 = by + pad + hh + ul_gap + ul_h + pad - bb[1]
            draw.text((bx2, by2), body, font=body_font, fill=fg)
        return bx, by, box_w, box_h

    note_gap    = max(8, round(20 * modifier))
    box_gap     = max(6, round(18 * modifier))   # gap between stacked boxes
    theme_right = round(osd_w * 0.72)   # fallback if theme box not shown
    theme_cy    = round(osd_h * 0.32)   # fallback

    # Measure each visible box so we can calculate positions before drawing
    title_m  = draw_box("SONG TITLE",  song_title, 0, 72, 200, 24, measure_only=True) if show_title  else None
    theme_m  = draw_box(theme_label,   None,        0, 72, 72,  20, measure_only=True) if show_theme  else None
    artist_m = draw_box("SONG ARTIST", artist_str,  0, 72, 130, 24, measure_only=True) if show_artist else None

    # Center song title vertically; stack theme above and artist below it
    title_h  = title_m[3]  if title_m  else 0
    theme_h  = theme_m[3]  if theme_m  else 0

    title_y  = (osd_h - title_h) // 2
    theme_y  = title_y - box_gap - theme_h
    artist_y = title_y + title_h + box_gap

    if show_theme:
        rect = draw_box(theme_label, None, theme_y, 72, 72, 20)
        if rect:
            theme_right = rect[0] + rect[2] + note_gap
            theme_cy    = rect[1] + rect[3] // 2
    if show_title:
        draw_box("SONG TITLE", song_title, title_y, 72, 200, 24)
    if show_artist:
        draw_box("SONG ARTIST", artist_str, artist_y, 72, 130, 24)

    return canvas, theme_right, theme_cy


def toggle_song_overlay(show_title=True, show_artist=True, show_theme=True, show_music=True, destroy=False, quick_destroy=False):
    """Toggles the Song Lightning Round overlay (mpv PIL image overlay)."""
    global song_overlay_boxes, _song_img_overlay, _song_anim_after

    if destroy or quick_destroy:
        if _song_anim_after is not None:
            try:
                root.after_cancel(_song_anim_after)
            except Exception:
                pass
            _song_anim_after = None
        if _song_img_overlay is not None:
            try:
                _song_img_overlay.remove()
            except Exception:
                pass
            _song_img_overlay = None
        song_overlay_boxes = {}
        _song_base_cache[0] = None
        _song_base_cache[1] = None
        _song_note_px_cache.clear()
        if destroy:
            return
        # quick_destroy: rebuild immediately with saved flags
        toggle_song_overlay(**_song_last_flags)
        return

    # Update flags — the running animation loop reads these each tick
    _song_last_flags.update(show_title=show_title, show_artist=show_artist,
                             show_theme=show_theme, show_music=show_music)

    # If the loop is already running, just let it pick up the new flags
    if _song_img_overlay is not None:
        return

    # First call: create overlay and start animation
    _song_img_overlay = player._p.create_image_overlay()
    song_overlay_boxes = {"active": True}
    _song_note_color[0] = (random.randint(100, 255),
                           random.randint(100, 255),
                           random.randint(100, 255), 255)
    _song_anim_start = [_wall_time()]

    def _song_step():
        global _song_img_overlay, _song_anim_after
        if _song_img_overlay is None:
            return
        flags = _song_last_flags
        st  = flags["show_title"]
        sa  = flags["show_artist"]
        sth = flags["show_theme"]
        sm  = flags["show_music"]
        try:
            osd_w = player._p.osd_width  or 1920
            osd_h = player._p.osd_height or 1080
        except Exception:
            osd_w, osd_h = 1920, 1080

        state_key = (st, sa, sth, osd_w, osd_h)
        if _song_base_cache[0] != state_key:
            _song_base_cache[0] = state_key
            _canvas, _nx, _ny = _draw_song_base(st, sa, sth, osd_w, osd_h)
            _song_base_cache[1] = _canvas
            _song_base_cache[2] = _nx
            _song_base_cache[3] = _ny

        from PIL import Image, ImageDraw
        base = _song_base_cache[1]
        canvas = base.copy() if (base is not None and sm) else (
            base if base is not None else Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
        )

        if sm and base is not None:
            modifier   = min(osd_w / 2560, osd_h / 1440)
            base_note  = max(20, round(160 * modifier))
            max_note   = max(24, round(200 * modifier))
            elapsed    = _wall_time() - _song_anim_start[0]
            if not player.is_playing():
                _song_anim_start[0] += 0.05  # freeze elapsed while paused
            # ~1.5 second period for a full pulse cycle
            angle      = elapsed * (2 * math.pi / 1.5)
            px = int(base_note + math.sin(angle) * (max_note - base_note) / 2)
            if px not in _song_note_px_cache:
                from PIL import ImageFont
                font = None
                for path in ["C:/Windows/Fonts/seguiemj.ttf", "C:/Windows/Fonts/seguisym.ttf"]:
                    try:
                        font = ImageFont.truetype(path, px)
                        break
                    except Exception:
                        pass
                _song_note_px_cache[px] = font or _get_ass_font(px, bold=False)
            note_font = _song_note_px_cache[px]
            if note_font:
                draw       = ImageDraw.Draw(canvas)
                NOTE_TEXT  = "\U0001F3B5"
                bbox       = draw.textbbox((0, 0), NOTE_TEXT, font=note_font)
                nh         = bbox[3] - bbox[1]
                note_gap   = max(8, round(30 * modifier))
                nx         = _song_base_cache[2] + note_gap - bbox[0]
                ny         = _song_base_cache[3] - nh // 2 - bbox[1] - nh // 3
                bdr        = max(2, px // 22)
                nc         = _song_note_color[0]
                for dx, dy in ((-bdr, 0), (bdr, 0), (0, -bdr), (0, bdr),
                               (-bdr, -bdr), (bdr, -bdr), (-bdr, bdr), (bdr, bdr)):
                    draw.text((nx + dx, ny + dy), NOTE_TEXT, font=note_font, fill=(0, 0, 0, 200))
                draw.text((nx, ny), NOTE_TEXT, font=note_font, fill=nc)

        try:
            _song_img_overlay.update(canvas)
        except Exception:
            _song_img_overlay = None
            return
        _song_anim_after = root.after(50, _song_step)

    _song_step()

# =========================================
#       *TRIVIA LIGHTNING ROUND
# =========================================

client = None
gpt_cutoff_year = 2023
def set_openai_client_key():
    global client
    client = openai.OpenAI(api_key=OPENAI_API_KEY)

def extract_response_text(response):
    texts = []
    for item in response.output:
        if hasattr(item, "content") and item.content:
            for c in item.content:
                if hasattr(c, "text") and c.text:
                    texts.append(c.text)
    return "\n".join(texts) if texts else None

def generate_anime_trivia(data, display=False):
    if fixed_current_round:
        trivia = fixed_current_round.get("trivia_question", "No trivia found.")
        trivia_answer = fixed_current_round.get("trivia_answer", "None")
        return trivia, trivia_answer

    def no_trivia_available():
        return "No trivia available.", "None"
    
    mal_id = data.get("mal")
    stored_trivia = ai_metadata.get(mal_id, {}).get("trivia") if mal_id else []
    if not isinstance(stored_trivia, list):
        stored_trivia = [stored_trivia] if stored_trivia else []

    if not client:
        if stored_trivia:
            question, answer = random.choice(stored_trivia)
            return question, answer
        return "No 'openai_api_key' set in config file.", "None"
    
    title = get_display_title(data)
    year = int(data.get("season", "9999")[-4:])

    media_type = "anime"
    if is_game(data):
        media_type = "game"

    prompt = f"""
        Generate a trivia question and answer about the {media_type} "{title}" ({year}).
        - The question must be under 40 words.
        - Start the question with: "In {title} ({year}),"
        - Avoid questions with ambiguous answers.
        - Avoid spoilers and generic questions like "Who is the main character?"
        - Do NOT make the answer a character name.
        - Do NOT use character names or any words from the anime's title in the answer.
        - Avoid questions where the answer is "Who is ___" or "What is the name of ___".
        - Do NOT make the answer a person's name.
        - Do NOT make the answer a song name or artist.
        - Do NOT ask about the number of episodes.
        - The answer should be concise and direct (not a full sentence).

        Format:
        Question: <your question>
        Answer: <your answer>
        """

    if year > gpt_cutoff_year:
        if len((data.get("synopsis") or "").split()) <= 40:
            return no_trivia_available()
        short_synopsis = data["synopsis"][:300].rsplit('.', 1)[0] + '.'
        prompt += f"""
        The anime may be too recent, so here's a synopsis you can use for context:
        [{short_synopsis}]
        """
    try:
        response = client.responses.create(
            model="gpt-4-turbo",
            input=prompt
        )

        content = extract_response_text(response)
        if display:
            print(content)
        if content and "Question:" in content and "Answer:" in content:
            question, answer = parse_trivia_response(content)
            if mal_id and answer and all(answer != a for _, a in stored_trivia):
                ai_metadata.setdefault(mal_id, {}).setdefault("trivia", []).append([question, answer])
                save_metadata()
            return question, answer
        else:
            return no_trivia_available()
    except Exception as e:
        if display:
            print(e)
        return no_trivia_available()

def parse_trivia_response(response_text):
    lines = response_text.split("\n")
    q = next((line[9:] for line in lines if line.startswith("Question:")), None).strip()
    a = next((line[7:] for line in lines if line.startswith("Answer:")), None).strip()
    return q, a

light_trivia_answer = None
def set_light_trivia(data=None, queue=False, trivia_data=None):
    global light_trivia_answer, synopsis_start_index, synopsis_split
    if trivia_data:
        question, answer = trivia_data[0], trivia_data[1]
    else:
        if not data:
            data = currently_playing.get("data")
        question, answer = generate_anime_trivia(data)
    if queue:
        return [question, answer]
    else:
        synopsis_start_index = 0
        synopsis_split = question.split(" ")
        light_trivia_answer = answer

# =========================================
#          *EMOJI LIGHTNING ROUND
# =========================================

def get_emoji_clues_for_title(data):
    """Uses OpenAI to generate emoji clues for the anime's title/concept."""
    mal_id = data.get("mal")
    if mal_id and mal_id in ai_metadata and "emojis" in ai_metadata[mal_id]:
        return ai_metadata[mal_id]["emojis"]
    if not client or not OPENAI_API_KEY:
        return ["❓"]
    title = get_display_title(data)
    year = int(data.get("season", "9999")[-4:])
    prompt = (
        f"Give me exactly 6 emojis that represent the anime '{title}' ({year}). "
        "Order them in a way to make the easier emojis later. "
        "Do NOT use any words or character names. "
        "Only output emojis, separated by spaces."
    )
    try:
        response = client.responses.create(
            model="gpt-4-turbo",
            input=prompt
        )
        # Extract emojis from response
        content = extract_response_text(response)
        # Split by whitespace - compound emojis stay intact since ZWJ isn't whitespace
        emojis = content.split()
        
        # Limit to 6 emojis
        emojis = emojis[:6]
        
        if mal_id:
            ai_metadata.setdefault(mal_id, {})["emojis"] = emojis
            save_metadata()

        return emojis if emojis else ["❓"]
    except Exception as e:
        print("Emoji GPT error:", e)
        return ["❓"]

    
emoji_overlay_window = None   # kept as sentinel — True when overlay active, None when not
_emoji_img_overlay = None

def toggle_emoji_overlay(emojis=None, destroy=False, max_emojis=None, title="EMOJIS"):
    global emoji_overlay_window, _emoji_img_overlay

    NUM_EMOJI_SLOTS = 6

    if destroy:
        if _emoji_img_overlay is not None:
            try:
                _emoji_img_overlay.remove()
            except Exception:
                pass
            _emoji_img_overlay = None
        emoji_overlay_window = None
        return

    if not emojis:
        data = currently_playing.get("data", {})
        emojis = get_emoji_clues_for_title(data)

    if max_emojis is not None:
        emojis = emojis[:max_emojis]

    padded_emojis = (emojis + [""] * NUM_EMOJI_SLOTS)[:NUM_EMOJI_SLOTS]

    try:
        osd_w = player._p.osd_width  or 1920
        osd_h = player._p.osd_height or 1080
    except Exception:
        osd_w, osd_h = 1920, 1080

    modifier = min(osd_w / 2560, osd_h / 1440)
    def ws(n): return max(1, int(n * modifier))

    # Header font size — mirrors synopsis exactly: physical window mod × screen DPI → OSD pixels
    _mx, _my, _mw_phys, _mh_phys = _get_mpv_window_rect()
    if not _mw_phys:
        _mw_phys, _mh_phys = osd_w, osd_h
    _phys_mod = min(_mw_phys / 2560, _mh_phys / 1440)
    _screen_dpi = root.winfo_fpixels('1i')
    header_font_px = max(1, round(max(1, int(70 * _phys_mod)) * _screen_dpi / 72))

    # Colours
    try:
        r16, g16, b16 = root.winfo_rgb(OVERLAY_BACKGROUND_COLOR)
        bg_r, bg_g, bg_b = r16 >> 8, g16 >> 8, b16 >> 8
        r16, g16, b16 = root.winfo_rgb(OVERLAY_TEXT_COLOR)
        fg_r, fg_g, fg_b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        bg_r, bg_g, bg_b = 0, 0, 0
        fg_r, fg_g, fg_b = 255, 255, 255
    bg = (bg_r, bg_g, bg_b, 230)   # 0.9 alpha — matches Toplevel alpha=0.9
    fg = (fg_r, fg_g, fg_b, 255)

    # Box geometry (matches 70% wide × 35% tall, centered)
    box_w  = int(osd_w * 0.70)
    box_h  = int(osd_h * 0.35)
    box_x  = (osd_w - box_w) // 2
    box_y  = (osd_h - box_h) // 2
    border = ws(4)
    pad    = ws(20)

    canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    draw   = ImageDraw.Draw(canvas)

    # Background + border
    draw.rectangle([box_x, box_y, box_x + box_w, box_y + box_h], fill=bg)
    draw.rectangle([box_x, box_y, box_x + box_w, box_y + box_h],
                   outline=fg, width=border)

    # Title — style matches synopsis header (bold, underline under text only)
    title_font = _get_ass_font(header_font_px, bold=True)
    title_bottom = box_y + pad + header_font_px + ws(20)   # fallback
    if title_font:
        tb = draw.textbbox((0, 0), title, font=title_font)
        tx = box_x + pad - tb[0]
        ty = box_y + pad - tb[1]
        draw.text((tx, ty), title, font=title_font, fill=fg)
        # Underline spans only the text width — same as synopsis \u1 ASS tag
        ul_y  = ty + tb[3] + max(1, round(header_font_px * 0.05))
        ul_x1 = tx + tb[0]   # visual left edge of text
        ul_x2 = tx + tb[2]   # visual right edge of text
        ul_h  = max(2, round(header_font_px * 0.07))
        draw.rectangle([ul_x1, ul_y, ul_x2, ul_y + ul_h], fill=fg)
        title_bottom = ul_y + ul_h + ws(20)

    # Emoji slots — extra side padding so emojis don't crowd the box edges
    slot_size      = ws(200)
    emoji_side_pad = pad * 2          # larger inset on left/right vs. the text pad
    emoji_area_w   = box_w - emoji_side_pad * 2
    total_slots    = NUM_EMOJI_SLOTS
    slot_gap       = max(ws(10), (emoji_area_w - slot_size * total_slots) // max(1, total_slots - 1))
    emoji_area_h   = box_h - (title_bottom - box_y) - pad
    slot_y         = title_bottom + (emoji_area_h - slot_size) // 2

    # Emoji font (loaded once per size)
    _efont = None
    for _fp in [r"C:\Windows\Fonts\seguiemj.ttf",
                r"C:\Windows\Fonts\NotoColorEmoji.ttf",
                r"C:\Windows\Fonts\seguisym.ttf"]:
        if os.path.exists(_fp):
            try:
                from PIL import ImageFont as _IFnt
                _efont = _IFnt.truetype(_fp, size=int(slot_size * 1.2))
                break
            except Exception:
                pass

    for i, emoji_char in enumerate(padded_emojis):
        if not emoji_char or not _efont:
            continue
        slot_x = box_x + emoji_side_pad + i * (slot_size + slot_gap)
        try:
            ec = unicodedata.normalize('NFC', emoji_char)
            cs = slot_size * 8
            em_im  = Image.new("RGBA", (cs, cs), (0, 0, 0, 0))
            em_drw = ImageDraw.Draw(em_im)
            em_drw.text((cs // 2, cs // 2), ec, font=_efont,
                        anchor="mm", embedded_color=True)
            bbox = em_im.getbbox()
            if not bbox:
                continue
            cropped = em_im.crop(bbox)
            cw, ch  = cropped.size
            scale   = min(slot_size / cw, slot_size / ch)
            if scale < 1:
                cw, ch  = int(cw * scale), int(ch * scale)
                cropped = cropped.resize((cw, ch), Image.LANCZOS)
            ox = slot_x + (slot_size - cw) // 2
            oy = slot_y  + (slot_size - ch) // 2
            canvas.paste(cropped, (ox, oy), cropped)
        except Exception:
            pass

    if _emoji_img_overlay is None:
        _emoji_img_overlay = player._p.create_image_overlay()
    _emoji_img_overlay.update(canvas)
    emoji_overlay_window = True   # sentinel so game-loop guard stays truthy


