def get_mismatched_theme():
    global mismatch_visuals
    match_data = currently_playing.get("data")
    if not match_data:
        return None

    is_op = is_slug_op(match_data.get("slug"))
    match_series = series_primary(match_data)
    match_season = match_data.get("season")  # e.g., "Fall 2020"

    # Convert season to year
    def extract_year(season_str):
        if season_str and isinstance(season_str, str) and season_str[-4:].isdigit():
            return int(season_str[-4:])
        return None

    match_year = extract_year(match_season)

    # Return {tag_name: rank} from anilist_metadata for a given anime data dict.
    # Uses file_metadata to resolve MAL → AniList ID, then looks up tags.
    def get_anilist_tags(data):
        mal_id = data.get("mal")
        if not mal_id:
            return {}
        fm = file_metadata.get(str(mal_id)) or file_metadata.get(mal_id)
        if not fm:
            return {}
        al_id = fm.get("anilist")
        if not al_id:
            return {}
        al = anilist_metadata.get(str(al_id))
        if not al:
            return {}
        return {t["name"]: t.get("rank", 0) for t in al.get("tags", []) if t.get("name")}

    match_anilist_tags = get_anilist_tags(match_data)
    match_basic_tags   = set(get_tags(match_data))  # fallback when no AniList data

    theme_pool = cached_sfw_themes["ops"] if is_op else cached_sfw_themes["eds"]
    if len(theme_pool) <= 1:
        theme_pool = cached_sfw_themes["ops"] + cached_sfw_themes["eds"]

    candidates = []

    for filename in theme_pool:
        file_data = get_metadata(filename)
        if not file_data:
            continue

        file_series = series_primary(file_data)
        if file_series == match_series:
            continue  # skip same series

        file_year = extract_year(file_data.get("season"))

        # Tag similarity: prefer AniList weighted overlap (min(rank1,rank2)/100 per shared tag),
        # same formula as bonus get_random_titles. Fall back to basic set-overlap count.
        file_anilist_tags = get_anilist_tags(file_data)
        if match_anilist_tags and file_anilist_tags:
            tag_score = sum(
                min(match_anilist_tags[name], file_anilist_tags[name]) / 100
                for name in match_anilist_tags if name in file_anilist_tags
            )
        else:
            tag_score = len(match_basic_tags & set(get_tags(file_data)))

        year_score = 0
        if match_year and file_year:
            year_diff = abs(match_year - file_year)
            year_score = max(0, 5 - year_diff)  # Closer years get more points

        # Add a little randomness
        random_bonus = random.uniform(0, 1.5)

        total_score = tag_score * 1.5 + year_score + random_bonus

        candidates.append((total_score, filename, file_data))

    if not candidates:
        tries = 0
        while tries <= 10:
            filename = random.choice(theme_pool)
            file_data = get_metadata(filename)
            file_series = series_primary(file_data)
            if file_series != match_series:
                mismatch_visuals = get_display_title(file_data) + " " + format_slug(file_data.get("slug"))
                return filename
            tries += 1
        return None

    # Sort by score and randomly choose from top 5
    candidates.sort(key=lambda x: x[0], reverse=True)
    top_candidates = candidates[:5]
    score, chosen_filename, chosen_data = random.choice(top_candidates)

    mismatch_visuals = get_display_title(chosen_data) + " " + format_slug(chosen_data.get("slug"))
    return chosen_filename

def check_nsfw(filename):
    for censor in get_file_censors(filename):
        if censor.get("nsfw"):
            return True
    data = get_metadata(filename)
    if data:
        theme = get_song_by_slug(data, data.get("slug", ""))
        if theme.get("nsfw"):
            return True
    return False

_note_img_overlay = None
_note_anim_after = None

def spawn_pulsating_music_note(x=0, y=0, font_size=scl(100), destroy=False):
    global _note_img_overlay, _note_anim_after

    # Cancel any running animation
    if _note_anim_after is not None:
        try:
            root.after_cancel(_note_anim_after)
        except Exception:
            pass
        _note_anim_after = None

    # Remove existing overlay
    if _note_img_overlay is not None:
        try:
            _note_img_overlay.remove()
        except Exception:
            pass
        _note_img_overlay = None

    if destroy:
        return

    # Pick a random bright color once per spawn
    note_color = (random.randint(100, 255), random.randint(100, 255), random.randint(100, 255), 255)

    # Try Segoe UI Emoji so we can render 🎵 properly; fall back to Arial ♪
    _emoji_font_cache = {}
    def _get_note_font(px):
        if px not in _emoji_font_cache:
            from PIL import ImageFont
            for path in ["C:/Windows/Fonts/seguiemj.ttf", "C:/Windows/Fonts/seguisym.ttf"]:
                try:
                    _emoji_font_cache[px] = ImageFont.truetype(path, px)
                    break
                except Exception:
                    pass
            else:
                _emoji_font_cache[px] = _get_ass_font(px, bold=False)
        return _emoji_font_cache[px]

    NOTE_TEXT = "\U0001F3B5"  # 🎵

    _note_img_overlay = player._p.create_image_overlay()
    _step = [0.0]
    _last_osd = [0, 0]  # track last known OSD size for dynamic rebase
    _frame_cache = [None, None, None]  # [last_px, last_canvas_w, last_canvas]

    def _note_step():
        global _note_img_overlay, _note_anim_after
        if _note_img_overlay is None:
            return
        try:
            cur_osd_w = player._p.osd_width or 1920
            cur_osd_h = player._p.osd_height or 1080
        except Exception:
            cur_osd_w, cur_osd_h = 1920, 1080

        # Dynamically rebase whenever OSD size changes
        if cur_osd_w != _last_osd[0] or cur_osd_h != _last_osd[1]:
            _last_osd[0] = cur_osd_w
            _last_osd[1] = cur_osd_h
            _step[1] = max(60, int(cur_osd_h * 0.30))   # base_px
            _step[2] = int(_step[1] * 1.15)              # max_px
            _frame_cache[0] = None  # force redraw on resize

        base_px = _step[1]
        max_px  = _step[2]

        if not player.is_playing():
            _note_anim_after = root.after(50, _note_step)
            return

        _step[0] += 0.9  # pulse speed
        px = int(base_px + math.sin(_step[0]) * (max_px - base_px) / 2)

        # Only re-render when the pixel size actually changed
        if px == _frame_cache[0] and cur_osd_w == _frame_cache[1]:
            _note_anim_after = root.after(50, _note_step)
            return

        from PIL import Image, ImageDraw
        canvas = Image.new("RGBA", (cur_osd_w, cur_osd_h), (0, 0, 0, 0))
        draw = ImageDraw.Draw(canvas)
        font = _get_note_font(px)
        if font:
            bbox = draw.textbbox((0, 0), NOTE_TEXT, font=font)
            tw = bbox[2] - bbox[0]
            th = bbox[3] - bbox[1]
            tx = (cur_osd_w - tw) // 2 - bbox[0]
            ty = (cur_osd_h - th) // 2 - bbox[1]
            # 8-point outline — vastly cheaper than a full grid loop
            border = max(3, px // 22)
            for dx, dy in ((-border, 0), (border, 0), (0, -border), (0, border),
                           (-border, -border), (border, -border), (-border, border), (border, border)):
                draw.text((tx + dx, ty + dy), NOTE_TEXT, font=font, fill=(0, 0, 0, 200))
            draw.text((tx, ty), NOTE_TEXT, font=font, fill=note_color)

        _frame_cache[0] = px
        _frame_cache[1] = cur_osd_w
        _frame_cache[2] = canvas
        try:
            _note_img_overlay.update(canvas)
        except Exception:
            _note_img_overlay = None
            return
        _note_anim_after = root.after(50, _note_step)

    # Initialise the per-step size slots before the first call
    try:
        _init_h = player._p.osd_height or 1080
    except Exception:
        _init_h = 1080
    _step.append(max(60, int(_init_h * 0.30)))   # index 1: base_px
    _step.append(int(_step[1] * 1.15))            # index 2: max_px
    _step.append(0)                               # index 3: unused sentinel
    _note_step()

