zoom_reveal_image_window = None   # mpv image overlay
zoom_reveal_crop = None

def pick_interesting_zoom_crop(pil_img, crop_size=(0.35, 0.35), attempts=50, initial_zoom=16):
    """
    Picks a visually interesting crop for zoom reveal.
    Returns (crop_x, crop_y, crop_w, crop_h) in pixel coordinates.
    For fixed rounds with selected area: the area itself is returned
    For automatic selection: finds an area that looks interesting when zoomed in
    """
    # Check if we're in a fixed round with a pre-selected area
    if fixed_current_round and fixed_current_round.get("image_selected_area"):
        selected_area = fixed_current_round["image_selected_area"]
        # selected_area format: {"x_pct": x, "y_pct": y, "w_pct": w, "h_pct": h} as percentages
        # Convert percentages to pixel coordinates for the current image size
        img_w, img_h = pil_img.size
        x = int(selected_area["x_pct"] * img_w)
        y = int(selected_area["y_pct"] * img_h)
        w = int(selected_area["w_pct"] * img_w)
        h = int(selected_area["h_pct"] * img_h)
        return (x, y, w, h)
    
    img_w, img_h = pil_img.size
    crop_w = int(img_w * crop_size[0])
    crop_h = int(img_h * crop_size[1])
    best_crop = None
    best_score = -1

    # Calculate the view size at initial zoom (for non-fixed rounds)
    view_w = int(img_w / initial_zoom)
    view_h = int(img_h / initial_zoom)

    # Try different crop positions and score them by visual interest at zoom level
    for _ in range(attempts):
        # Pick a random crop position (this defines the center point)
        x = random.randint(0, img_w - crop_w)
        y = random.randint(0, img_h - crop_h)
        
        # Center of crop
        center_x = x + crop_w // 2
        center_y = y + crop_h // 2
        
        # Simulate initial zoomed view (what will be shown at max zoom)
        left = max(0, center_x - view_w // 2)
        top = max(0, center_y - view_h // 2)
        right = min(img_w, left + view_w)
        bottom = min(img_h, top + view_h)
        zoomed_crop = pil_img.crop((left, top, right, bottom))
        
        # Score the zoomed area by visual variance
        arr = np.array(zoomed_crop.convert("L"))
        score = arr.var()
        if score > best_score:
            best_score = score
            best_crop = (x, y, crop_w, crop_h)
        if score > 500:  # tweak threshold as needed
            break
    return best_crop if best_crop else (0, 0, crop_w, crop_h)

def toggle_character_zoom_reveal_overlay(percent=1.0, destroy=False):
    """
    Displays the character image zoomed in at an interesting spot, then zooms out as percent decreases.
    percent: 1.0 = fully zoomed in, 0.0 = fully zoomed out.
    """
    global zoom_reveal_image_window, zoom_reveal_crop

    if destroy:
        if zoom_reveal_image_window is not None:
            try:
                zoom_reveal_image_window.remove()
            except Exception:
                pass
            zoom_reveal_image_window = None
        zoom_reveal_crop = None
        return

    if light_cover_image:
        pil_img = ImageTk.getimage(light_cover_image).copy()
    else:
        if not character_round_answer:
            return
        pil_img = ImageTk.getimage(character_round_answer[1]).copy()

    try:
        osd_w = int(player._p.osd_width  or 0) or 1920
        osd_h = int(player._p.osd_height or 0) or 1080
    except Exception:
        osd_w, osd_h = 1920, 1080

    width_percent = lightning_mode_settings.get("_misc_settings", {}).get("image_width_percent", 70) / 100
    target_width  = int(osd_w * width_percent)
    target_height = int(osd_h * 0.7)
    scale = min(target_width / pil_img.width, target_height / pil_img.height)
    new_size = (int(pil_img.width * scale), int(pil_img.height * scale))
    pil_img = pil_img.resize(new_size, Image.LANCZOS)

    # Pick an interesting crop position once
    initial_zoom = 16  # Zoom factor for non-fixed rounds
    if 'zoom_reveal_crop' not in globals() or zoom_reveal_crop is None:
        zoom_reveal_crop = pick_interesting_zoom_crop(pil_img, initial_zoom=initial_zoom)

    crop_x, crop_y, crop_w, crop_h = zoom_reveal_crop

    # Check if this is a fixed round with a selected area
    has_fixed_area = fixed_current_round and fixed_current_round.get("image_selected_area")
    has_ending_area = fixed_current_round and fixed_current_round.get("image_ending_area")
    
    if has_fixed_area:
        # For fixed rounds with selected area
        if has_ending_area:
            # Interpolate from starting area to ending area
            # At percent=1.0: show exactly the starting selected area
            # At percent=0.0: show exactly the ending area
            ending_area = fixed_current_round["image_ending_area"]
            end_x = int(ending_area["x_pct"] * new_size[0])
            end_y = int(ending_area["y_pct"] * new_size[1])
            end_w = int(ending_area["w_pct"] * new_size[0])
            end_h = int(ending_area["h_pct"] * new_size[1])
            
            # Interpolate dimensions
            view_w = int(crop_w + (end_w - crop_w) * (1 - percent))
            view_h = int(crop_h + (end_h - crop_h) * (1 - percent))
            
            # Interpolate center position
            start_center_x = crop_x + crop_w // 2
            start_center_y = crop_y + crop_h // 2
            end_center_x = end_x + end_w // 2
            end_center_y = end_y + end_h // 2
            
            center_x = int(start_center_x + (end_center_x - start_center_x) * (1 - percent))
            center_y = int(start_center_y + (end_center_y - start_center_y) * (1 - percent))
        else:
            # Interpolate from starting area to full image
            # At percent=1.0: show exactly the selected area (crop_w x crop_h)
            # At percent=0.0: show the full image (new_size[0] x new_size[1])
            view_w = int(crop_w + (new_size[0] - crop_w) * (1 - percent))
            view_h = int(crop_h + (new_size[1] - crop_h) * (1 - percent))
            center_x = crop_x + crop_w // 2
            center_y = crop_y + crop_h // 2
    else:
        # For non-fixed rounds: use zoom factor for more dramatic zoom
        initial_zoom = 16
        zoom = 1.0 + percent * (initial_zoom - 1)  # 1.0 = full image, up to initial_zoom x
        view_w = int(new_size[0] / zoom)
        view_h = int(new_size[1] / zoom)
        center_x = crop_x + crop_w // 2
        center_y = crop_y + crop_h // 2
    
    left = max(0, center_x - view_w // 2)
    top = max(0, center_y - view_h // 2)
    right = min(new_size[0], left + view_w)
    bottom = min(new_size[1], top + view_h)
    
    # Adjust if we hit edges - expand in the opposite direction to maintain view size
    if right - left < view_w:
        # Hit right edge, expand left
        left = max(0, right - view_w)
    if bottom - top < view_h:
        # Hit bottom edge, expand top
        top = max(0, bottom - view_h)
    if left == 0 and right - left < view_w:
        # Hit left edge, expand right
        right = min(new_size[0], left + view_w)
    if top == 0 and bottom - top < view_h:
        # Hit top edge, expand bottom
        bottom = min(new_size[1], top + view_h)
    
    cropped = pil_img.crop((left, top, right, bottom))
    
    # Check if we're showing nearly the full image (within 5%)
    crop_w_actual = right - left
    crop_h_actual = bottom - top
    
    # Scale cropped region to fit display while maintaining aspect ratio
    scale_w = new_size[0] / crop_w_actual
    scale_h = new_size[1] / crop_h_actual
    scale_fit = min(scale_w, scale_h)
    
    scaled_w = int(crop_w_actual * scale_fit)
    scaled_h = int(crop_h_actual * scale_fit)
    cropped = cropped.resize((scaled_w, scaled_h), Image.LANCZOS)
    
    # Center the scaled crop on a black background
    composite = Image.new("RGBA", new_size, (0, 0, 0, 255))
    offset_x = (new_size[0] - scaled_w) // 2
    offset_y = (new_size[1] - scaled_h) // 2
    composite.paste(cropped.convert("RGBA"), (offset_x, offset_y))

    # Place composite centered on full OSD canvas
    canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    ix = (osd_w - new_size[0]) // 2
    iy = (osd_h - new_size[1]) // 2
    from PIL import ImageDraw as _ImageDraw
    border = scl(4)
    _ImageDraw.Draw(canvas).rectangle(
        [ix - border, iy - border, ix + new_size[0] + border, iy + new_size[1] + border],
        fill=(0, 0, 0, 242)
    )
    canvas.paste(composite, (ix, iy))

    if zoom_reveal_image_window is None:
        zoom_reveal_image_window = player._p.create_image_overlay()
    try:
        zoom_reveal_image_window.update(canvas)
    except Exception:
        pass

# =========================================
#          *SLICE LIGHTNING ROUND
# =========================================

def generate_image_slices(tk_img, num_slices=10, vertical=True):
    """
    Slices the image into num_slices vertical (or horizontal) parts.
    Returns a list of PIL images (not Tkinter PhotoImages).
    """
    pil_img = ImageTk.getimage(tk_img).convert("RGBA")
    w, h = pil_img.size
    slices = []
    for i in range(num_slices):
        if vertical:
            left = int(i * w / num_slices)
            right = int((i + 1) * w / num_slices)
            box = (left, 0, right, h)
        else:
            top = int(i * h / num_slices)
            bottom = int((i + 1) * h / num_slices)
            box = (0, top, w, bottom)
        part = pil_img.crop(box)
        slices.append((part, box))
    return slices

slice_overlay_window = None   # mpv image overlay
slice_overlay_parts = []
slice_overlay_order = []

def toggle_slice_overlay(num_revealed=10, num_slices=10, vertical=True, swap=False, destroy=False):
    """
    Shows the image sliced into num_slices parts.
    If swap=True, all slices are visible but their positions are shuffled.
    If swap=False, only num_revealed slices are shown in a random order.
    """
    global slice_overlay_window, slice_overlay_parts, slice_overlay_order

    if destroy:
        if slice_overlay_window is not None:
            try:
                slice_overlay_window.remove()
            except Exception:
                pass
            slice_overlay_window = None
        slice_overlay_parts = []
        slice_overlay_order = []
        return

    # Use character_round_answer or light_cover_image
    if character_round_answer:
        tk_img = character_round_answer[1]
    elif light_cover_image:
        tk_img = light_cover_image
    else:
        return

    # Generate slices only once
    if not slice_overlay_parts or len(slice_overlay_parts) != num_slices:
        slice_overlay_parts = generate_image_slices(tk_img, num_slices, vertical)
        slice_overlay_order = list(range(num_slices))
        random.shuffle(slice_overlay_order)

    pil_img = ImageTk.getimage(tk_img).convert("RGBA")
    w, h = pil_img.size

    # Compose slices onto a transparent background
    composite = Image.new("RGBA", (w, h), (0, 0, 0, 0))
    if swap:
        swap_order = slice_overlay_order[:]
        random.shuffle(swap_order)
        for i, idx in enumerate(swap_order):
            part, box = slice_overlay_parts[idx]
            if vertical:
                left = int(i * w / num_slices)
                right = int((i + 1) * w / num_slices)
                new_box = (left, 0, right, h)
                # Resize part to fit new_box
                part_resized = part.resize((right - left, h), Image.LANCZOS)
            else:
                top = int(i * h / num_slices)
                bottom = int((i + 1) * h / num_slices)
                new_box = (0, top, w, bottom)
                part_resized = part.resize((w, bottom - top), Image.LANCZOS)
            composite.paste(part_resized, new_box)
    else:
        # Reveal slices in random order
        for i in range(num_revealed):
            idx = slice_overlay_order[i]
            part, box = slice_overlay_parts[idx]
            composite.paste(part, box)

    try:
        osd_w = int(player._p.osd_width  or 0) or 1920
        osd_h = int(player._p.osd_height or 0) or 1080
    except Exception:
        osd_w, osd_h = 1920, 1080
    width_percent = lightning_mode_settings.get("_misc_settings", {}).get("image_width_percent", 70) / 100
    target_w = int(osd_w * width_percent)
    target_h = int(osd_h * 0.7)
    scale = min(target_w / w, target_h / h)
    img_w = int(w * scale)
    img_h = int(h * scale)
    composite = composite.resize((img_w, img_h), Image.LANCZOS)

    osd_canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    ix = (osd_w - img_w) // 2
    iy = (osd_h - img_h) // 2
    from PIL import ImageDraw
    border = scl(4)
    ImageDraw.Draw(osd_canvas).rectangle([ix - border, iy - border, ix + img_w + border, iy + img_h + border], fill=(0, 0, 0, 242))
    osd_canvas.paste(composite, (ix, iy), composite)

    if slice_overlay_window is None:
        slice_overlay_window = player._p.create_image_overlay()
    try:
        slice_overlay_window.update(osd_canvas)
    except Exception:
        pass
                
# =========================================
#        *TILE LIGHTNING ROUND
# =========================================

def is_solid_color(image_crop, tolerance=30):
    arr = np.array(image_crop.convert("RGB"))
    # If the standard deviation is low, it's a solid color
    return arr.std() < tolerance

def generate_image_grid_slices(tk_img, grid_size=4, ignore_solid=True):
    pil_img = ImageTk.getimage(tk_img).convert("RGBA")
    w, h = pil_img.size
    tile_w = w // grid_size
    tile_h = h // grid_size
    slices = []
    for row in range(grid_size):
        for col in range(grid_size):
            left = col * tile_w
            top = row * tile_h
            right = left + tile_w if col < grid_size - 1 else w
            bottom = top + tile_h if row < grid_size - 1 else h
            box = (left, top, right, bottom)
            part = pil_img.crop(box)
            if not is_solid_color(part, tolerance=30) or not ignore_solid:  # Only add if not solid
                slices.append((part, box, (row, col)))
    return slices

tile_overlay_window = None   # mpv image overlay
tile_overlay_parts = []
tile_overlay_order = []
tile_overlay_swap = False
tile_overlay_grid_size = 4

def toggle_tile_overlay(num_revealed=1, grid_size=4, swap=False, destroy=False):
    """
    If swap=False: reveals num_revealed tiles in a random order, rest hidden.
    If swap=True: all tiles shown, but only num_revealed unique swaps are restored to correct positions.
    Tiles in the wrong position are dimmed.
    """
    global tile_overlay_window, tile_overlay_parts, tile_overlay_order, tile_overlay_swap, tile_overlay_grid_size

    if destroy:
        if tile_overlay_window is not None:
            try:
                tile_overlay_window.remove()
            except Exception:
                pass
            tile_overlay_window = None
        tile_overlay_parts = []
        tile_overlay_order = []
        tile_overlay_swap = False
        return

    if character_round_answer:
        tk_img = character_round_answer[1]
    elif light_cover_image:
        tk_img = light_cover_image
    else:
        return

    # Only generate once per round
    if not tile_overlay_parts:
        tile_overlay_grid_size = grid_size
        tile_overlay_parts = generate_image_grid_slices(tk_img, grid_size, ignore_solid=not swap)
        tile_overlay_order = list(range(len(tile_overlay_parts)))
        
        if swap:
            # For swap mode, start with correct order and create meaningful scramble
            toggle_tile_overlay.swap_order = tile_overlay_order[:]  # Start correct: [0,1,2,3,4,...]
            
            # Create swap pairs that will scramble the puzzle meaningfully
            swap_pairs = []
            used = set()
            order_copy = toggle_tile_overlay.swap_order[:]
            available_positions = list(range(len(order_copy)))
            random.shuffle(available_positions)
            
            # Create random pairs and apply swaps to scramble the order
            i = 0
            while i < len(available_positions) - 1:
                pos_a = available_positions[i]
                pos_b = available_positions[i + 1]
                
                if pos_a not in used and pos_b not in used:
                    # Swap these two random positions to create the scrambled puzzle
                    order_copy[pos_a], order_copy[pos_b] = order_copy[pos_b], order_copy[pos_a]
                    swap_pairs.append((pos_a, pos_b))
                    used.update([pos_a, pos_b])
                    i += 2
                else:
                    i += 1
            
            # The scrambled order becomes our starting state
            toggle_tile_overlay.swap_order = order_copy
            random.shuffle(swap_pairs)  # Randomize which swaps happen when
            toggle_tile_overlay.swap_pairs = swap_pairs
        else:
            # For regular mode, shuffle normally
            random.shuffle(tile_overlay_order)

    pil_img = ImageTk.getimage(tk_img).convert("RGBA")
    w, h = pil_img.size
    composite = Image.new("RGBA", (w, h), (0, 0, 0, 0))

    if swap:
        tile_overlay_swap = True
        swap_order = toggle_tile_overlay.swap_order[:]
        # Perform up to num_revealed unique swaps from precomputed swap_pairs
        if hasattr(toggle_tile_overlay, "swap_pairs"):
            swaps_to_do = toggle_tile_overlay.swap_pairs[:num_revealed]
            for a, b in swaps_to_do:
                # Actually swap the tiles at positions a and b
                swap_order[a], swap_order[b] = swap_order[b], swap_order[a]
        grid_cols = tile_overlay_grid_size
        for i, idx in enumerate(swap_order):
            part, box, (row, col) = tile_overlay_parts[idx]
            grid_row = i // grid_cols
            grid_col = i % grid_cols
            left = grid_col * (w // grid_cols)
            top = grid_row * (h // grid_cols)
            right = left + (w // grid_cols) if grid_col < grid_cols - 1 else w
            bottom = top + (h // grid_cols) if grid_row < grid_cols - 1 else h
            new_box = (left, top, right, bottom)
            part_resized = part.resize((right - left, bottom - top), Image.LANCZOS)
            if idx != i:
                overlay = Image.new("RGBA", part_resized.size, (0, 0, 0, 100))
                part_resized = Image.alpha_composite(part_resized, overlay)
            if (right - left) > 0 and (bottom - top) > 0:
                composite.paste(part_resized, new_box)
    else:
        # Reveal tiles in the same shuffled order each time
        for i in range(num_revealed):
            idx = tile_overlay_order[i]
            part, box, _ = tile_overlay_parts[idx]
            composite.paste(part, box)

    try:
        osd_w = int(player._p.osd_width  or 0) or 1920
        osd_h = int(player._p.osd_height or 0) or 1080
    except Exception:
        osd_w, osd_h = 1920, 1080
    width_percent = lightning_mode_settings.get("_misc_settings", {}).get("image_width_percent", 70) / 100
    target_w = int(osd_w * width_percent)
    target_h = int(osd_h * 0.7)
    scale = min(target_w / w, target_h / h)
    img_w = int(w * scale)
    img_h = int(h * scale)
    composite = composite.resize((img_w, img_h), Image.LANCZOS)

    osd_canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    ix = (osd_w - img_w) // 2
    iy = (osd_h - img_h) // 2
    from PIL import ImageDraw
    border = scl(4)
    ImageDraw.Draw(osd_canvas).rectangle([ix - border, iy - border, ix + img_w + border, iy + img_h + border], fill=(0, 0, 0, 242))
    osd_canvas.paste(composite, (ix, iy), composite)

    if tile_overlay_window is None:
        tile_overlay_window = player._p.create_image_overlay()
    try:
        tile_overlay_window.update(osd_canvas)
    except Exception:
        pass

# =========================================
#        *PROFILE LIGHTNING ROUND
# =========================================

profile_overlay_window = None   # sentinel — True when active, None when not
_profile_img_overlay = None

_profile_last_word_count = 0
_profile_last_image_countdown = 15

def toggle_character_profile_overlay(word_count=0, image_countdown=15, destroy=False, quick_destroy=False):
    """Displays a character profile with gender, a word-by-word BIO, and delayed image reveal."""
    global profile_overlay_window, _profile_img_overlay
    global _profile_last_word_count, _profile_last_image_countdown

    if destroy or quick_destroy:
        if _profile_img_overlay is not None:
            try:
                _profile_img_overlay.remove()
            except Exception:
                pass
            _profile_img_overlay = None
        profile_overlay_window = None
        if quick_destroy:
            toggle_character_profile_overlay(
                word_count=_profile_last_word_count,
                image_countdown=_profile_last_image_countdown,
            )
        return

    if not character_round_answer:
        return

    _profile_last_word_count = word_count
    _profile_last_image_countdown = image_countdown

    name, img, gender, desc = character_round_answer

    try:
        osd_w = player._p.osd_width  or 1920
        osd_h = player._p.osd_height or 1080
    except Exception:
        osd_w, osd_h = 1920, 1080

    osd_mod = min(osd_w / 2560, osd_h / 1440)
    def ws(n): return max(1, int(n * osd_mod))

    # Font sizes: Tkinter used point sizes, PIL uses pixels.
    # Apply the same DPI conversion as synopsis/emoji headers so they match.
    _screen_dpi   = root.winfo_fpixels('1i')
    title_font_px = max(1, round(ws(60) * _screen_dpi / 72))
    body_font_px  = max(1, round(ws(50) * _screen_dpi / 72))

    # Colours — profile uses INVERSE palette
    try:
        r16, g16, b16 = root.winfo_rgb(INVERSE_OVERLAY_BACKGROUND_COLOR)
        bg_r, bg_g, bg_b = r16 >> 8, g16 >> 8, b16 >> 8
        r16, g16, b16 = root.winfo_rgb(INVERSE_OVERLAY_TEXT_COLOR)
        fg_r, fg_g, fg_b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        bg_r, bg_g, bg_b = 255, 255, 255
        fg_r, fg_g, fg_b = 0, 0, 0
    bg = (bg_r, bg_g, bg_b, round(0.95 * 255))   # alpha=0.95 matches Toplevel
    fg = (fg_r, fg_g, fg_b, 255)

    # Layout — exact ratios from Tkinter version
    width_percent = lightning_mode_settings.get("_misc_settings", {}).get("image_width_percent", 70) / 100
    target_w    = int(osd_w * width_percent)
    target_h    = int(osd_h * 0.7)
    border      = max(1, round(4 * osd_mod))   # highlightthickness=4
    outer_pad_x = ws(5)    # padx=5 on frames
    outer_pad_y = ws(10)   # pady=10 on frames
    inner_pad   = ws(10)   # padx=ws(10) on labels
    desc_w      = (target_w // 3) * 2   # left panel: 2/3 of total width
    img_panel_w = target_w - desc_w     # right panel: 1/3

    box_x = (osd_w - target_w) // 2
    box_y = (osd_h - target_h) // 2

    canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    draw   = ImageDraw.Draw(canvas)

    # Background + border
    draw.rectangle([box_x, box_y, box_x + target_w, box_y + target_h], fill=bg)
    draw.rectangle([box_x, box_y, box_x + target_w, box_y + target_h],
                   outline=fg, width=border)

    title_font = _get_ass_font(title_font_px, bold=True)
    body_font  = _get_ass_font(body_font_px,  bold=False)

    # Left panel text origin (inside border + outer padding + label padding)
    text_x = box_x + outer_pad_x + inner_pad
    text_y = box_y + outer_pad_y + inner_pad

    # Wrap width: from text_x to the right edge of the desc panel minus a right margin
    wrap_w = (box_x + desc_w) - text_x - inner_pad

    # Title: "CHARACTER DESCRIPTION:" bold + underline
    title_bottom = text_y + title_font_px + inner_pad   # fallback if font missing
    if title_font:
        TITLE = "CHARACTER DESCRIPTION:"
        tb = draw.textbbox((0, 0), TITLE, font=title_font)
        draw.text((text_x - tb[0], text_y - tb[1]), TITLE, font=title_font, fill=fg)
        ul_gap = max(1, round(title_font_px * 0.05))
        ul_h   = max(2, round(title_font_px * 0.07))
        ul_y   = text_y - tb[1] + tb[3] + ul_gap
        draw.rectangle([text_x, ul_y, text_x + (tb[2] - tb[0]), ul_y + ul_h], fill=fg)
        title_bottom = ul_y + ul_h + inner_pad

    # Body: "Gender: X. [description]" — word-wrapped, up to word_count+2 words, max 11 lines
    full_text   = f"Gender: {gender.capitalize()}. {desc}"
    all_words   = full_text.split()
    limited     = all_words[:word_count + 2]
    max_lines   = 11

    if body_font and limited:
        # Measure space width by comparing "a b" vs "ab" to avoid zero-width issues
        _sp_bb  = draw.textbbox((0, 0), "a b", font=body_font)
        _ab_bb  = draw.textbbox((0, 0), "ab",  font=body_font)
        space_w = max(1, (_sp_bb[2] - _sp_bb[0]) - (_ab_bb[2] - _ab_bb[0]))

        lines     = []
        cur_words = []
        cur_w     = 0

        for word in limited:
            wbb    = draw.textbbox((0, 0), word, font=body_font)
            word_w = wbb[2] - wbb[0]
            test_w = cur_w + (space_w if cur_words else 0) + word_w
            if cur_words and test_w > wrap_w:
                lines.append(' '.join(cur_words))
                if len(lines) >= max_lines:
                    cur_words = []
                    break
                cur_words = [word]
                cur_w     = word_w
            else:
                cur_words.append(word)
                cur_w = test_w

        if cur_words and len(lines) < max_lines:
            lines.append(' '.join(cur_words))

        # If not all limited words were shown, add ellipsis to the last line
        shown_words = sum(len(l.split()) for l in lines)
        if shown_words < len(limited) and lines:
            last_words = lines[-1].split()
            for trim in range(len(last_words), 0, -1):
                candidate = ' '.join(last_words[:trim]) + '...'
                cbb = draw.textbbox((0, 0), candidate, font=body_font)
                if (cbb[2] - cbb[0]) <= wrap_w:
                    lines[-1] = candidate
                    break

        # Line height: cap height + ~15% leading to match Tk label spacing
        lhbb   = draw.textbbox((0, 0), "Ag", font=body_font)
        line_h = (lhbb[3] - lhbb[1]) + max(1, round(body_font_px * 0.15))

        cy = title_bottom
        for line in lines:
            lbb = draw.textbbox((0, 0), line, font=body_font)
            draw.text((text_x - lbb[0], cy - lbb[1]), line, font=body_font, fill=fg)
            cy += line_h

    # Right panel: character image — blurred when countdown > 0, sharp when 0
    pil_img = ImageTk.getimage(img).copy().convert("RGBA")
    max_img_w = img_panel_w - outer_pad_x * 2   # stay within right panel + padding
    max_img_h = target_h    - outer_pad_y * 2
    scale_w = max_img_w / pil_img.width
    scale_h = max_img_h / pil_img.height
    scale   = min(scale_w, scale_h)
    sc_w    = int(pil_img.width  * scale)
    sc_h    = int(pil_img.height * scale)
    sc_img  = pil_img.resize((sc_w, sc_h), Image.LANCZOS)

    if image_countdown > 0:
        display_img = sc_img.filter(ImageFilter.GaussianBlur(radius=100))
    else:
        display_img = sc_img

    # Centre image in right panel
    right_x = box_x + desc_w
    paste_x = right_x + (img_panel_w - sc_w) // 2
    paste_y = box_y   + (target_h   - sc_h) // 2
    canvas.paste(display_img, (paste_x, paste_y), display_img)

    if _profile_img_overlay is None:
        _profile_img_overlay = player._p.create_image_overlay()
    _profile_img_overlay.update(canvas)
    profile_overlay_window = True   # sentinel for game-loop guards

# =========================================
#          *TAGS LIGHTNING ROUND
# =========================================

tag_cloud_tags = []

def set_cloud_tags():
    global tag_cloud_tags
    data = currently_playing.get("data")
    if data:
        tags = []
        use_anilist = lightning_mode_settings.get("tags", {}).get("use_anilist_tags", True)
        
        anilist_tags_found = False
        if use_anilist:
            anilist_id = data.get("anilist")
            if anilist_id and str(anilist_id) in anilist_metadata:
                anilist_data = anilist_metadata[str(anilist_id)]
                anilist_tags_list = anilist_data.get("tags", [])
                if anilist_tags_list:
                    # Use AniList tags with their rank as weight (rank is 0-100)
                    for tag in anilist_tags_list:
                        if not tag.get("spoiler", False):  # Skip spoiler tags
                            rank = tag.get("rank", 50)
                            # Use cubic scaling to create dramatic visual difference
                            weight = int(((rank / 100) ** 3) * 1000)
                            tags.append({
                                "name": tag.get("name", ""),
                                "weight": weight
                            })
                    anilist_tags_found = True
        
        if not anilist_tags_found and data.get("tags"):
            for tag in data.get("tags"):
                tags.append({"name": tag[0].replace(" - to be split and deleted", "").replace(" -- to be split and deleted", ""), "weight": tag[1]})
        
        if not tags:
            for tag in get_tags(data):
                tags.append({"name": tag, "weight": 600})
            tags.append({"name": "only MAL tags", "weight": 600})
    else:
        tags = [
            {"name": "no tags found", "weight": 600}
        ]
    tag_cloud_tags = sorted(tags, key=lambda t: t["weight"], reverse=True)

    random.shuffle(tag_cloud_tags)
    if currently_playing.get("data", {}).get("season"):
        tag_cloud_tags.insert(0, {"name": currently_playing.get("data", {}).get("season")[-4:], "weight": 600})

# Globals
tag_cloud_positions = []
_tag_cloud_last_osd_h = 0
_tag_cloud_font_sizes = []  # parallel to tag_cloud_tags; recomputed when osd_h changes

def _compute_tag_font_sizes(osd_h):
    """Compute and cache font sizes for all tags based on current osd_h."""
    global _tag_cloud_font_sizes, _tag_cloud_last_osd_h
    _tag_cloud_last_osd_h = osd_h
    weights = [t["weight"] for t in tag_cloud_tags]
    if not weights:
        _tag_cloud_font_sizes = []
        return
    min_w, max_w = min(weights), max(weights)
    _fs_modifier = osd_h / 1440
    n = len(tag_cloud_tags)
    min_fs_ref = max(22, 60 - n)
    max_fs_ref = max(min_fs_ref + 40, 100 - n // 4)
    min_fs = max(10, round(min_fs_ref * _fs_modifier * 1.6))
    max_fs = max(min_fs + round(20 * _fs_modifier * 1.6), round(max_fs_ref * _fs_modifier * 1.6))
    fs_range = max_fs - min_fs
    sizes = []
    for t in tag_cloud_tags:
        normalized = (t["weight"] - min_w) / (max_w - min_w + 1e-5)
        amplified = normalized ** 2
        sizes.append(max(10, int(min_fs + fs_range * amplified)))
    _tag_cloud_font_sizes = sizes

def _plan_tag_cloud_layout(osd_w, osd_h):
    """Pre-compute positions for ALL tags at once, strictly within screen bounds.
    Falls back to smaller font sizes when a tag can't fit at its assigned size.
    Populates tag_cloud_positions and updates _tag_cloud_font_sizes in-place."""
    global tag_cloud_positions, _tag_cloud_font_sizes

    cx, cy = osd_w // 2, osd_h // 2
    top_margin    = round(osd_h * 0.12)
    bottom_margin = round(osd_h * 0.12)
    left_margin   = round(osd_w * 0.03)
    right_margin  = round(osd_w * 0.03)
    x_min, x_max = left_margin, osd_w - right_margin
    y_min, y_max = top_margin, osd_h - bottom_margin

    def est_dims(fs, text):
        w = round(len(text) * fs * 0.55)
        h = round(fs * 1.3)
        return w, h

    def overlaps_any(pos, placed):
        ax, ay, aw, ah = pos
        for bx, by, bw, bh in placed:
            if not (ax + aw < bx or ax > bx + bw or ay + ah < by or ay > by + bh):
                return True
        return False

    font_sizes = list(_tag_cloud_font_sizes)
    placed = []

    for i, tag in enumerate(tag_cloud_tags):
        text = tag["name"]
        placed_this = False
        # Try progressively smaller font sizes until the tag fits on-screen
        for fs_try in range(font_sizes[i], 9, -3):
            w, h = est_dims(fs_try, text)
            if w > (x_max - x_min) or h > (y_max - y_min):
                continue
            # Spiral outward from center; cap radius so tags stay on-screen
            angle, radius = 0.0, 0.0
            max_radius = max(osd_w, osd_h) * 0.7
            best_x = best_y = None
            while radius <= max_radius:
                x = max(x_min, min(int(cx + radius * math.cos(angle)) - w // 2, x_max - w))
                y = max(y_min, min(int(cy + radius * math.sin(angle)) - h // 2, y_max - h))
                if not overlaps_any((x, y, w, h), placed):
                    best_x, best_y = x, y
                    break
                angle += 0.5
                radius += 4
            if best_x is not None:
                font_sizes[i] = fs_try
                placed.append((best_x, best_y, w, h))
                placed_this = True
                break
        if not placed_this:
            # Absolute fallback: minimum size, clamped, ignoring overlaps
            w, h = est_dims(10, text)
            w = min(w, x_max - x_min)
            h = min(h, y_max - y_min)
            px = max(x_min, min(cx - w // 2, x_max - w))
            py = max(y_min, min(cy - h // 2, y_max - h))
            font_sizes[i] = 10
            placed.append((px, py, w, h))

    tag_cloud_positions = placed
    _tag_cloud_font_sizes = font_sizes

def toggle_tag_cloud_overlay(num_tags=1, destroy=False):
    global _tag_cloud_last_osd_h, _tag_cloud_font_sizes

    if destroy:
        tag_cloud_positions.clear()
        _tag_cloud_font_sizes = []
        _tag_cloud_last_osd_h = 0
        try:
            _osd_command('osd-overlay', _TAG_CLOUD_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
        except Exception:
            pass
        return

    try:
        osd_w = int(player._p.osd_width or 0)
        osd_h = int(player._p.osd_height or 0)
    except Exception:
        return
    if not osd_w or not osd_h:
        return

    num_tags = min(num_tags, len(tag_cloud_tags))
    if not num_tags:
        return

    # Recompute font sizes (and clear cached positions) if osd_h changed
    if osd_h != _tag_cloud_last_osd_h or len(_tag_cloud_font_sizes) != len(tag_cloud_tags):
        _compute_tag_font_sizes(osd_h)
        tag_cloud_positions.clear()

    # Plan ALL positions up front on first call, guaranteeing on-screen placement
    if not tag_cloud_positions:
        _plan_tag_cloud_layout(osd_w, osd_h)

    # Build ASS payload for all visible tags
    text_bgr = _color_str_to_ass_bgr(OVERLAY_TEXT_COLOR)
    bg_bgr   = _color_str_to_ass_bgr(OVERLAY_BACKGROUND_COLOR)
    lines = []
    for i in range(num_tags):
        tag = tag_cloud_tags[i]
        px, py, tw, th = tag_cloud_positions[i]
        fs  = _tag_cloud_font_sizes[i]
        tx  = px + tw // 2
        ty  = py + th // 2
        bord = max(2, round(fs * 0.12))
        # Bold text; border acts as per-glyph background (perfectly consistent padding)
        lines.append(
            f"{{\\an5\\pos({tx},{ty})\\1c&H{text_bgr}&\\1a&H00&"
            f"\\3c&H{bg_bgr}&\\3a&H40&\\bord{bord}\\shad0\\fs{fs}\\b1}}{tag['name']}"
        )
    ass_payload = "\n".join(lines)
    try:
        _osd_command('osd-overlay', _TAG_CLOUD_ASS_OSD_ID, 'ass-events',
                          ass_payload, osd_w, osd_h, 3, 'no')
    except Exception as e:
        print(f"Tag cloud OSD error: {e}")

