def thread_prefetch_metadata():
    if auto_fetch_missing:
        threading.Thread(target=pre_fetch_metadata, daemon=True).start()

def play_video_retry(retries, filename=None):
    global video_stopped
    retry_delay = 2000
    if animethemes_stream:
        retry_delay = 5000 + 1000*(5-retries)  # Increase delay with each retry for streaming
    if (not player.is_playing() or player.get_length() == 0) and filename and currently_playing.get("filename") == filename:
        if retries > 0:
            if retries < 5:
                print(f"Retrying playback for: {currently_playing.get('filename')}")
                player_play()
            root.after(retry_delay, play_video_retry, retries - 1, filename)  # Retry playback
            return
        else:
            play_video(playlist["current_index"] + skip_direction)
    set_skip_direction(1)
    video_stopped = False

previous_media = None

def _handle_video_end():
    """Called on the main thread when a video reaches its natural end.
    Contains the advance-or-loop logic previously polled by check_video_end."""
    global video_stopped
    if video_stopped or autoplay_toggle == 2:
        return
    # During the lightning question phase the player has paused at EOF (keep-open=yes).
    # Calling play_next() here risks falling through to the next-track path if any
    # state variable is momentarily inconsistent.  Instead, seek past the round
    # boundary directly and call player.play() so that update_light_round (which only
    # runs when the player IS playing) detects elapsed >= light_round_length and
    # triggers the answer phase normally.
    if light_round_started and light_round_start_time is not None and _light_answer_wall_start is None:
        try:
            if streaming.currently_streaming:
                seek_target_ms = round((stream_start_time + light_round_length + 0.1) * 1000)
                player.set_time(seek_target_ms)
            else:
                answer_ms = int((light_round_start_time + light_round_length + 0.05) * 1000)
                seek_to(answer_ms)
            was_playing = player.is_playing()
            if not was_playing:
                player.play()
        except Exception as e:
            print(f"[DBG _handle_video_end] exception in lightning branch: {e}")
        video_stopped = True  # guard against re-entry if eof-reached fires again
        return
    if autoplay_toggle == 0:
        play_next()
        video_stopped = True
    else:
        player.pause()
        player.set_media(previous_media)
        player.play()


def update_current_index(value = None, save = True):
    """Function to update the playlist button counter label"""
    try:
        if value != None:
            playlist["current_index"] = value
        if globals().get("playlist_menu_button"):
            if playlist.get("infinite", False):
                out_of = playlist_ops.total_infinite_files - len(playlist_ops.cached_skipped_themes)
                counter = f"\u221e/{out_of}"
            else:
                out_of = len(playlist["playlist"])
                counter = f"{playlist['current_index']+1}/{out_of}"
            playlist_menu_button.config(text=f"PLAYLIST {counter}\u25be")
        
        if list_loaded == "playlist" and value is not None:
            global current_list_offset, current_list_selected
            # Update the selected index to match the current playing item
            current_list_selected = value
            entries_count = get_list_entries_count()
            current_start = current_list_offset
            current_end = current_list_offset + entries_count
            
            look_ahead = min(3, len(playlist["playlist"]) - value - 1)  # Don't look beyond playlist end
            needs_scroll = (value < current_start or value >= current_end or 
                          (value + look_ahead) >= current_end)
            
            if needs_scroll:
                ideal_offset = max(0, value - 1)  # Show current with 1 item before if possible
                max_offset = max(0, len(playlist["playlist"]) - entries_count)
                current_list_offset = min(ideal_offset, max_offset)
            refresh_current_list()
            
        if save:
            save_config()
        if web_server.is_running():
            if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
                fixed_rounds = fixed_lightning_round_playlist_data.get("rounds", [])
                fixed_index = fixed_lightning_round_playlist_data.get("current_index", 0)
                web_server.push_playlist_info(len(fixed_rounds), fixed_index, counter=(f'{fixed_index+1}/{len(fixed_rounds)}' if fixed_rounds else '0/0'), label=fixed_lightning_round_playlist_data.get('name') or 'Fixed Playlist')
            elif playlist.get('infinite', False):
                out_of = playlist_ops.total_infinite_files - len(playlist_ops.cached_skipped_themes)
                web_server.push_playlist_info(-1, -1, counter=f'\u221e/{out_of}', label=playlist.get('name') or 'Playlist')
            else:
                out_of = len(playlist['playlist'])
                cur = playlist['current_index']
                web_server.push_playlist_info(out_of, cur, counter=f'{cur+1}/{out_of}', label=playlist.get('name') or 'Playlist')
    except NameError:
        pass  # root isn't defined yet — possibly too early in startup

_cached_images = {}
state.playback.cached_images = _cached_images
def load_image_from_url(url, size=(400, 400)):
    """Loads an image from a URL, resizes it to fit one side of the box fully (maximizing size while preserving aspect ratio), centers it in a transparent box, and returns a Tkinter-compatible PhotoImage."""
    if _cached_images.get(url):
        image = _cached_images[url]
    else:
        try:
            headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"}
            response = requests.get(url, headers=headers, timeout=10)
            response.raise_for_status()
            image = Image.open(BytesIO(response.content)).convert("RGBA")
            _cached_images[url] = image
        except Exception as e:
            print(f"load_image_from_url: failed to load {url!r}: {e}")
            return None
    if not size:
        return ImageTk.PhotoImage(image)

    # Target box size
    box_width, box_height = size
    img_width, img_height = image.size

    # Calculate scale factors
    scale_w = box_width / img_width
    scale_h = box_height / img_height

    # Use the smaller scale so the image fits completely inside the box
    scale = min(scale_w, scale_h)

    # Compute new size
    new_size = (int(img_width * scale), int(img_height * scale))
    image = image.resize(new_size, Image.LANCZOS)

    # Create a transparent box and paste the resized image centered
    background = Image.new("RGBA", (box_width, box_height), (0, 0, 0, 0))
    offset_x = (box_width - new_size[0]) // 2
    offset_y = (box_height - new_size[1]) // 2
    background.paste(image, (offset_x, offset_y), image)

    return ImageTk.PhotoImage(background)

def load_pil_image_from_url(url, size=(400, 225)):
    """Like load_image_from_url but returns a PIL RGBA Image for use with OSD overlays."""
    if _cached_images.get(url):
        image = _cached_images[url]
    else:
        try:
            headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"}
            response = requests.get(url, headers=headers, timeout=10)
            response.raise_for_status()
            image = Image.open(BytesIO(response.content)).convert("RGBA")
            _cached_images[url] = image
        except Exception as e:
            print(f"load_pil_image_from_url: failed to load {url!r}: {e}")
            return None
    if not size:
        return image.copy()
    box_width, box_height = size
    img_width, img_height = image.size
    scale = min(box_width / img_width, box_height / img_height)
    new_size = (int(img_width * scale), int(img_height * scale))
    resized = image.resize(new_size, Image.LANCZOS)
    background = Image.new("RGBA", (box_width, box_height), (0, 0, 0, 0))
    offset_x = (box_width - new_size[0]) // 2
    offset_y = (box_height - new_size[1]) // 2
    background.paste(resized, (offset_x, offset_y), resized)
    return background

def go_to_index():
    """Function to jump to a specific index"""
    total = len(playlist["playlist"])
    index = simpledialog.askinteger("Go to Index", f"Enter track number (1\u2013{total}):", minvalue=1, maxvalue=total)
    if index is not None:
        play_video(index - 1)

def _clear_playpause_icon():
    """Cancel any in-progress play/pause icon animation and remove the overlay."""
    global _playpause_icon_after_ids, _playpause_img_overlay
    for aid in _playpause_icon_after_ids:
        try:
            root.after_cancel(aid)
        except Exception:
            pass
    _playpause_icon_after_ids = []
    if _playpause_img_overlay is not None:
        try:
            _playpause_img_overlay.remove()
        except Exception:
            pass
        _playpause_img_overlay = None


def _show_playpause_icon(paused):
    """Flash a fading play or pause icon centred on the mpv OSD.

    Uses create_image_overlay() (overlay_add plane) so it renders above all
    ASS osd-overlay layers (blind z=1, progress z=2, etc.).
    paused=True  → two vertical bars (pause symbol)
    paused=False → right-pointing triangle (play symbol)

    Border effect: draw expanded shapes in border color → GaussianBlur → draw
    fill on top.  This replicates the visual look of ASS \\bord + \\blur.
    Pre-rendered once at 2× (LANCZOS downscale for anti-aliasing).
    Per-frame: numpy alpha-scale — uniform, reliable fade for fill AND border.
    """
    global _playpause_icon_after_ids, _playpause_img_overlay
    _clear_playpause_icon()

    try:
        osd_w = int(player._p.osd_width or 0)
        osd_h = int(player._p.osd_height or 0)
    except Exception:
        return
    if not osd_w or not osd_h:
        return

    # Resolve theme colors (RGB for PIL)
    try:
        r16, g16, b16 = root.winfo_rgb(OVERLAY_BACKGROUND_COLOR)
        fill_rgb = (r16 >> 8, g16 >> 8, b16 >> 8)
        r16, g16, b16 = root.winfo_rgb(OVERLAY_TEXT_COLOR)
        bord_rgb = (r16 >> 8, g16 >> 8, b16 >> 8)
    except Exception:
        fill_rgb = (255, 255, 255)
        bord_rgb = (0,   0,   0)

    cx, cy = osd_w // 2, osd_h // 2
    h    = max(60, int(osd_h * 0.24))   # icon height in OSD pixels
    bord = max(2, h // 18)              # border thickness
    hh   = h // 2

    # Pre-render at 1× — hard border, no blur needed
    img = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    d   = ImageDraw.Draw(img)
    if paused:
        bw  = max(2, int(h * 0.22))
        gap = max(4, int(h * 0.20))
        x1, x2 = cx - bw - gap // 2, cx - gap // 2
        x3, x4 = cx + gap // 2,       cx + bw + gap // 2
        y1, y2 = cy - hh, cy + hh
        # outward border: draw expanded rect behind, fill rect on top
        d.rectangle([x1 - bord, y1 - bord, x2 + bord, y2 + bord], fill=bord_rgb + (255,))
        d.rectangle([x3 - bord, y1 - bord, x4 + bord, y2 + bord], fill=bord_rgb + (255,))
        d.rectangle([x1, y1, x2, y2], fill=fill_rgb + (255,))
        d.rectangle([x3, y1, x4, y2], fill=fill_rgb + (255,))
    else:
        tx = cx - int(h * 0.30)
        rx = cx + int(h * 0.35)
        # Compute properly expanded triangle via per-edge outward normals + miter joins.
        # Winding: A(top-left) → B(right tip) → C(bottom-left) = clockwise.
        # Outward unit normal for clockwise edge dir (dx,dy) = (dy/l, -dx/l).
        import math as _math
        d_px = rx - tx
        l    = _math.hypot(d_px, hh)
        n_ab = ( hh / l, -d_px / l)   # top-right edge
        n_bc = ( hh / l,  d_px / l)   # bottom-right edge
        n_ca = (-1.0,     0.0      )   # left edge
        def _miter(n1, n2, e):
            dot   = n1[0]*n2[0] + n1[1]*n2[1]
            denom = 1.0 + dot
            if abs(denom) < 1e-6:
                return (e * n1[0], e * n1[1])
            return (e * (n1[0] + n2[0]) / denom, e * (n1[1] + n2[1]) / denom)
        oA = _miter(n_ca, n_ab, bord)
        oB = _miter(n_ab, n_bc, bord)
        oC = _miter(n_bc, n_ca, bord)
        exp_pts = [(int(tx + oA[0]), int(cy - hh + oA[1])),
                   (int(rx + oB[0]), int(cy      + oB[1])),
                   (int(tx + oC[0]), int(cy + hh + oC[1]))]
        fill_pts = [(tx, cy - hh), (rx, cy), (tx, cy + hh)]
        d.polygon(exp_pts,  fill=bord_rgb + (255,))
        d.polygon(fill_pts, fill=fill_rgb  + (255,))

    base_np  = np.array(img, dtype=np.uint16)   # (h, w, 4) uint16 for safe multiply
    base_a   = base_np[:, :,  3]                 # uint16 alpha, scaled per frame

    def _render_frame(anim_a):
        """Return a full-OSD RGBA premultiplied image scaled by anim_a (0–255).

        mpv overlay_add expects premultiplied BGRA: RGB must be scaled together
        with alpha, otherwise bright pixels appear stuck at full brightness.
        """
        out          = np.empty((osd_h, osd_w, 4), dtype=np.uint8)
        out[:, :, :3] = ((base_np[:, :, :3] * anim_a) // 255).astype(np.uint8)
        out[:, :,  3] = ((base_a            * anim_a) // 255).astype(np.uint8)
        return Image.fromarray(out)

    # Create overlay after the progress bar overlay → higher ID → renders on top
    _playpause_img_overlay = player._p.create_image_overlay()

    def _apply(alpha_val):
        if _playpause_img_overlay is None:
            return
        try:
            _playpause_img_overlay.update(_render_frame(alpha_val))
        except Exception:
            pass

    def _finish():
        global _playpause_img_overlay
        if _playpause_img_overlay is not None:
            try:
                _playpause_img_overlay.remove()
            except Exception:
                pass
            _playpause_img_overlay = None

    # Show first frame immediately (synchronously) — no perceived delay
    _apply(255)

    # Schedule hold then fade-out only
    HOLD, FADE_OUT = 250, 120
    N_OUT = 4
    schedule = []
    for i in range(1, N_OUT + 1):
        schedule.append((HOLD + int(FADE_OUT * i / N_OUT),
                         int(255 * (1.0 - i / N_OUT))))                        # 255→0

    _playpause_icon_after_ids = [
        root.after(delay, lambda a=alpha: _apply(a))
        for delay, alpha in schedule
    ]
    _playpause_icon_after_ids.append(
        root.after(HOLD + FADE_OUT + 50, _finish)
    )


def play_pause():
    """Function to play/pause the video"""
    global video_stopped, frame_light_round_pause
    video_stopped = True
    if frame_light_round_started:
        frame_light_round_pause = not frame_light_round_pause
        _show_playpause_icon(frame_light_round_pause)
        return
    elif light_mode and lightning_mode_settings.get(light_mode, {}).get("muted") and light_mode not in ['clip', 'ost']:
        if player.is_playing():
            pygame.mixer.music.pause()
        elif light_round_start_time and ((player.get_time()/1000) < (light_round_start_time+light_round_length)):
            pygame.mixer.music.unpause()
    if player.is_playing():
        video_stopped = True
        player.pause()
        _show_playpause_icon(True)
    elif player.get_media():
        player.play()
        video_stopped = False
        _show_playpause_icon(False)
    else:
        play_video(playlist["current_index"])

# Function to play next video
skip_direction = 1
def set_skip_direction(dir):
    global skip_direction
    skip_direction = dir

def skip_to_lightning_answer():
    global light_blind_one_second_count
    global frame_light_round_frame_index, frame_light_round_frame_time
    if frame_light_round_started:
        try:
            if frame_light_round_frame_index is None or frame_light_round_frame_index < 4:
                frame_light_round_frame_index = 4
                frame_light_round_frame_time = 0
                bottom_info()
                play_background_music(False)
                set_black_screen(False)
                toggle_title_popup(True)
                return True
        except Exception:
            pass
    if light_round_started and light_round_start_time is not None:
        try:
            if light_blind_one_second_count:
                player.play()
                light_blind_one_second_count = None
                player.play()

            # Already in answer phase — let play_next fall through to light_round_transition
            if _light_answer_wall_start is not None:
                return False

            if streaming.currently_streaming:
                # Seek the stream player to stream_start_time + light_round_length so
                # update_light_round's elapsed calculation crosses the round-end threshold.
                seek_target_ms = round((stream_start_time + light_round_length + 0.1) * 1000)
                player.set_time(seek_target_ms)
                return True

            answer_time = light_round_start_time + light_round_length
            target_ms = int((answer_time + 0.05) * 1000)
            seek_to(target_ms)
            return True
        except Exception as e:
            print(f"[DBG skip_to_lightning_answer] exception: {e}")
    return False

def play_next():
    if skip_to_lightning_answer():
        return
    elif (light_round_started or ((light_mode or fixed_lightning_queue) and light_round_number == 0)) and not black_overlay:
        light_round_transition()
        return
    if special_repeat_track_mode:
        toggle_special_repeat()
    set_skip_direction(1)
    if playlist_loaded or playlist_ops.playlist_changed:
        play_video(playlist["current_index"])
    elif fixed_lightning_round_playlist_data or fixed_lightning_queue:
        play_video(playlist["current_index"])
    else:
        if playlist["current_index"] + 1 >= len(playlist["playlist"]):
            _promote_or_generate_next()
        if playlist["current_index"] + 1 < len(playlist["playlist"]):
            play_video(playlist["current_index"] + 1)

def play_previous():
    """Function to play previous video"""
    if playlist["current_index"] - 1 >= 0:
        set_skip_direction(-1)
        play_video(playlist["current_index"] - 1)

def stop():
    """Function to stop the video"""
    global video_stopped, light_round_started
    global fixed_lightning_queue, fixed_lightning_round_playlist_data, fixed_current_round
    currently_playing.clear()  # Clear first to prevent idle-active re-entry
    video_stopped = True
    toggle_light_mode()
    light_round_started = False
    set_countdown()
    set_light_round_number()
    set_black_screen(False)
    toggle_title_popup(False)
    if end_message_window:
        toggle_end_message()
    fixed_lightning_queue = None
    fixed_lightning_round_playlist_data = None
    fixed_current_round = None
    search_ops.search_queue = None
    unload_youtube_video()
    guess_extra()
    player.stop()
    player.set_media(None)  # Reset the media
    update_progress_bar(0,1)
    remove_all_censor_boxes()
    toggle_coming_up_popup(False, title=(coming_up_queue or {}).get("title", ""))
    seek_bar.set(0)
    clean_up_light_round(new_round=True)
    root.after(500, lambda: clean_up_light_round(new_round=True))

last_seek_time = None
def seek(value):
    """Function to seek the video"""
    global can_seek
    if can_seek:
        global last_seek_time
        last_seek_time = value
    else:
        can_seek = True

def seek_to(time_ms):
    """Function to seek the video to a specific time in milliseconds"""
    global projected_player_time
    time_ms = int(time_ms)
    apply_censors(time_ms/1000, player.get_length()/1000)
    projected_player_time = time_ms
    player.set_time(time_ms)

# Skip fade window (milliseconds)
SKIP_FADE_WINDOW_MS = 350
SKIP_FADE_IN_WINDOW_MS = 300
skip_fade_in_elapsed_ms = None

last_player_time = 0
projected_player_time = 0
last_skip_anchor_ms = None
SEEK_POLLING = 50
last_error = None
last_error_count = 0
playing_next_error = False
_web_playback_counter = 0   # throttle web playback state pushes to ~1/sec
def update_seek_bar():
    """Function to update the seek bar"""
    global last_player_time, projected_player_time, last_error, last_error_count, coming_up_queue, playing_next_error, can_seek, last_skip_anchor_ms, skip_fade_in_elapsed_ms
    try:
        if not player.is_playing():
            player_time = player.get_time()
            if player_time != last_player_time or last_player_time != projected_player_time:
                last_player_time = player_time
                projected_player_time = player_time
                if not last_seek_time:
                    can_seek = False
                    seek_bar.set(player_time/1000)
        else:
            player_time = player.get_time()
            if player_time != last_player_time:
                last_player_time = player_time
                projected_player_time = player_time
            else:
                projected_player_time = projected_player_time + SEEK_POLLING * light_speed_modifier
            skip_play_ms = int(max(0, float(skip_play_seconds)) * 1000)
            skip_jump_ms = int(max(0, float(skip_jump_seconds)) * 1000)
            skip_triggered = False
            if not light_round_started and bonus.guessing_extra and web_server.is_running():
                if (bonus.guessing_extra == "yt_bonus" and bonus._yt_bonus_current_question
                        and bonus._yt_bonus_current_question.get("end_time", 0) > 0):
                    _time_left = max(0.0, bonus._yt_bonus_current_question["end_time"] - projected_player_time / 1000)
                else:
                    _eff_rem = _effective_remaining_ms(
                        projected_player_time, player.get_length(),
                        currently_playing.get("filename")
                    )
                    _time_left = _eff_rem / 1000.0 - (8 if auto_info_end else 0)
                web_server.push_timer(_time_left, paused=True)
            if currently_playing.get("type") != "youtube" and not light_round_started and skip_play_ms > 0 and skip_jump_ms > 0:
                if last_skip_anchor_ms is None or last_seek_time or projected_player_time < last_skip_anchor_ms:
                    last_skip_anchor_ms = projected_player_time
                time_since_anchor = projected_player_time - last_skip_anchor_ms
                time_to_skip = skip_play_ms - time_since_anchor
                fade_window_ms = min(skip_play_ms, SKIP_FADE_WINDOW_MS)
                if skip_fade_in_elapsed_ms is None and not disable_video_audio and fade_window_ms > 0:
                    if time_to_skip <= fade_window_ms:
                        fade_factor = max(0.0, min(1.0, time_to_skip / fade_window_ms))
                        player.audio_set_volume(int(volume_level * fade_factor))
                    else:
                        player.audio_set_volume(volume_level)
                if time_since_anchor >= (skip_play_ms - SEEK_POLLING):
                    # Nudge past the boundary so it doesn't immediately re-trigger
                    skip_offset = max(SEEK_POLLING, 1)
                    total_length_ms = player.get_length()
                    if total_length_ms > 0 and (projected_player_time + skip_jump_ms + skip_offset) >= total_length_ms:
                        play_next()
                    else:
                        seek_to(projected_player_time + skip_jump_ms + skip_offset)
                    last_skip_anchor_ms = projected_player_time + skip_jump_ms
                    skip_fade_in_elapsed_ms = 0
                    skip_triggered = True
            else:
                last_skip_anchor_ms = None
                skip_fade_in_elapsed_ms = None

            if not skip_triggered:
                if not disable_video_audio and skip_fade_in_elapsed_ms is not None:
                    skip_fade_in_elapsed_ms += (SEEK_POLLING * light_speed_modifier)
                    fade_factor = max(0.0, min(1.0, skip_fade_in_elapsed_ms / max(1, SKIP_FADE_IN_WINDOW_MS)))
                    player.audio_set_volume(int(volume_level * fade_factor))
                    if fade_factor >= 1.0:
                        skip_fade_in_elapsed_ms = None
                length = player.get_length()/1000
                time = projected_player_time/1000
                if manual_blind and not light_round_started:
                    _eff_time, _eff_len = _apply_skip_censor_to_progress(
                        time * 1000, length * 1000, currently_playing.get("filename")
                    )
                    set_progress_overlay(_eff_time / 1000, _eff_len / 1000)
                if peek_overlay1 and not light_round_started:
                    gap = get_peek_gap(currently_playing.get("data"))
                    progress = ((time+peek_modifier)%24/12)*100
                    if progress >= 100:
                        direction = "right"
                        progress -= 100
                    else:
                        direction = "down"
                    toggle_peek_overlay(direction=direction, progress=progress, gap=gap)
                if length > 0:
                    # Auto-revoke skip grant when already within the last 3 seconds
                    if web_server.is_running() and web_server.get_skip_grant_player():
                        if time >= length - 3:
                            web_server.push_skip_grant('')
                    if not last_seek_time:
                        can_seek = False
                        seek_bar.config(to=length)
                        seek_bar.set(time)
                    if currently_playing.get("type") == "youtube":
                        start = currently_playing.get("data").get("start")
                        end = currently_playing.get("data").get("end")
                        yt_end_time = end if end != 0 else length
                        if time < start:
                            player.set_time(round(start*1000)+100)
                        elif end != 0 and time >= end:
                            player.pause()
                            play_next()
                        elif (yt_end_time - time) <= 8:
                            if (not is_title_window_up() or title_info_only) and auto_info_end and (not bonus.guessing_extra or bonus.guessing_extra == "buzzer"):
                                toggle_title_popup(True)
                        # Bonus template auto-trigger
                        for _bq_i, _bq in enumerate(bonus._yt_bonus_template_questions):
                            _bq_start = _bq.get("start_time", 0)
                            _bq_end = _bq.get("end_time", 0)
                            if _bq_i not in bonus._yt_bonus_template_triggered and time >= _bq_start:
                                if _bq_end > 0 and time >= _bq_end:
                                    # Already past this question's window — skip silently
                                    bonus._yt_bonus_template_triggered.add(_bq_i)
                                    bonus._yt_bonus_template_scored.add(_bq_i)
                                else:
                                    bonus._yt_bonus_template_triggered.add(_bq_i)
                                    bonus._yt_bonus_current_question = _bq
                                    bonus._yt_bonus_pts = float(_bq.get("points", 1))
                                    guess_extra("yt_bonus")
                                break
                            elif (_bq_i in bonus._yt_bonus_template_triggered and
                                  _bq_i not in bonus._yt_bonus_template_scored and
                                  _bq_end > 0 and time >= _bq_end):
                                bonus._yt_bonus_template_scored.add(_bq_i)
                                if bonus.guessing_extra == "yt_bonus":
                                    guess_extra("yt_bonus")
                                break
                        apply_censors(time, length)
                    else:
                        if not light_round_started and not video_stopped and (
                                _effective_remaining_ms(time * 1000, length * 1000,
                                                        currently_playing.get("filename")) / 1000.0 <= 8):
                            if (not is_title_window_up() or title_info_only) and auto_info_end:
                                toggle_title_popup(True)
                            if coming_up_queue:
                                toggle_coming_up_popup(True, title=coming_up_queue["title"], details=coming_up_queue["details"], image=coming_up_queue["image"], up_next=coming_up_queue["up_next"])
                                coming_up_queue = None
                        update_light_round(time)
                        apply_censors(time, length)
                update_progress_bar(projected_player_time, player.get_length(), currently_playing.get("filename"))
    except Exception as e:
        error_str = str(e)
        if not playing_next_error:
            if error_str == last_error:
                last_error_count += 1
                print(f"\rError: {error_str} x {last_error_count}", end='', flush=True)
            else:
                last_error = error_str
                last_error_count = 1
                if last_error_count > 20:
                    playing_next_error = True
                    play_next()
                print(f"\nError: {error_str} x 1", flush=True)
    # Push playback state to web host clients ~every 1 second
    global _web_playback_counter
    _web_playback_counter += 1
    if _web_playback_counter >= 20 and web_server.is_running():
        _web_playback_counter = 0
        try:
            web_server.push_playback_state(
                projected_player_time,
                player.get_length(),
                player.is_playing(),
                volume_level,
                autoplay_toggle,
                bgm_volume,
                bzz_modifier=bonus_settings.get('buzzer', BONUS_SETTINGS_DEFAULT['buzzer']).get('sound_volume', 1.0),
                strm_boost=stream_volume_boost
            )
            _push_web_toggles()
        except Exception:
            pass
    root.after(SEEK_POLLING, update_seek_bar)

format_seconds = utils.format_seconds

# =========================================
#            *COMING UP UI
# =========================================

coming_up_queue       = None

_COMING_UP_ASS_OSD_ID        = 80
_SKIP_TO_END_ASS_OSD_ID      = 81  # brief "SKIPPED TO END" flash overlay
_coming_up_osd_visible        = False
_coming_up_osd_current_title  = ""     # uppercased title currently displayed
_coming_up_img_overlay        = None   # mpv ImageOverlay for thumbnail
_coming_up_anim_after         = None   # root.after ID for slide-in animation
_coming_up_osd_box_h          = 0      # rendered box height in OSD px (for hide/resize)
_coming_up_osd_box_w          = 0      # rendered box width in OSD px
_coming_up_current_frame      = None   # (title_text, details, pil_image) of what is currently shown


def _coming_up_get_osd_dims():
    try:
        return int(player._p.osd_width or 0), int(player._p.osd_height or 0)
    except Exception:
        return 0, 0


def _render_coming_up_frame(title_text, details, pil_image, y, osd_w, osd_h, alpha_frac=1.0):
    """Render one animation frame of the coming-up popup at OSD y position.

    alpha_frac: 0.0 = fully transparent, 1.0 = final opacity (background ≈80%, text 100%).
    Mirrors the original Tkinter layout: title (large, underlined) → optional thumbnail → details.
    *pil_image* must be a PIL RGBA Image or None.
    """
    global _coming_up_img_overlay, _coming_up_osd_box_h, _coming_up_osd_box_w, _coming_up_current_frame
    _coming_up_current_frame = (title_text, details, pil_image)

    modifier = min(osd_w / 2560, osd_h / 1440)

    fs_title   = max(14, round(40 * modifier * 1.6))   # ≈ scl(40)
    fs_details = max(10, round(20 * modifier * 1.6))   # ≈ scl(20)

    pad_x  = max(8, round(osd_w * 0.010))
    pad_y  = max(6, round(osd_h * 0.012))
    gap    = max(4, round(fs_details * 0.3))
    margin = max(4, round(10 * modifier))

    def _measure_w(text_block, fs):
        fnt = _get_ass_font(fs)
        max_w = 0
        for line in text_block.split('\n'):
            if not line:
                continue
            try:
                w = round(fnt.getlength(line)) if fnt else round(len(line) * fs * 0.52)
            except AttributeError:
                w = fnt.getsize(line)[0] if fnt else round(len(line) * fs * 0.52)
            if w > max_w:
                max_w = w
        return max_w or fs

    def _line_h(fs, n):
        return round(n * fs * 1.0)

    # Cap box width at 65% of OSD width; pre-wrap title to fit so height is accurate
    max_box_w = min(round(osd_w * 0.65), osd_w - 2 * margin)
    title_wrap_max = max_box_w - 2 * pad_x

    title_wrapped = title_text
    if title_text:
        wrapped_title_lines = []
        for ln in title_text.split('\n'):
            if ln.strip():
                greedy = _ass_wrap_text(ln, fs_title, title_wrap_max)
                if len(greedy) > 1:
                    # Binary-search for the minimum wrap width that still fits in the same
                    # number of lines — this gives the most evenly balanced split.
                    n = len(greedy)
                    full_w = _measure_w(ln, fs_title)
                    lo = max(1, math.ceil(full_w / n))
                    hi = title_wrap_max
                    while lo < hi:
                        mid = (lo + hi) // 2
                        if len(_ass_wrap_text(ln, fs_title, mid)) <= n:
                            hi = mid
                        else:
                            lo = mid + 1
                    wrapped_title_lines.extend(_ass_wrap_text(ln, fs_title, lo))
                else:
                    wrapped_title_lines.extend(greedy)
            else:
                wrapped_title_lines.append('')
        title_wrapped = '\n'.join(wrapped_title_lines)

    # Wrap details preserving explicit newlines, word-wrapping each segment independently
    wrap_max = round(osd_w * 0.80)
    details_wrapped = details
    if details and details.strip():
        wrapped_lines = []
        for ln in details.split('\n'):
            if ln.strip():
                wrapped_lines.extend(_ass_wrap_text(ln, fs_details, wrap_max))
            else:
                wrapped_lines.append('')
        details_wrapped = '\n'.join(wrapped_lines)

    title_lines   = title_wrapped.count('\n') + 1    if title_wrapped                             else 0
    details_lines = details_wrapped.count('\n') + 1 if (details_wrapped and details_wrapped.strip()) else 0

    row_h_title   = _line_h(fs_title,   title_lines)   if title_lines   else 0
    row_h_details = _line_h(fs_details, details_lines) if details_lines else 0

    img_w_osd = round(400 * modifier) if pil_image else 0
    img_h_osd = round(225 * modifier) if pil_image else 0

    inner_h = (row_h_title
               + (gap if title_lines  and (pil_image or details_lines) else 0)
               + img_h_osd
               + (gap if pil_image    and details_lines                else 0)
               + row_h_details)
    box_h = inner_h + 2 * pad_y

    widths = []
    if title_wrapped:                                widths.append(_measure_w(title_wrapped,   fs_title))
    if details_wrapped and details_wrapped.strip():  widths.append(_measure_w(details_wrapped, fs_details))
    if pil_image:                                    widths.append(img_w_osd)
    box_w = (round(max(widths) * 0.91) if widths else fs_title) + 2 * pad_x
    box_w = min(box_w, max_box_w)

    _coming_up_osd_box_h = box_h
    _coming_up_osd_box_w = box_w

    bx = (osd_w - box_w) // 2
    by = y
    cx = osd_w // 2

    bg_bgr = _color_str_to_ass_bgr(OVERLAY_BACKGROUND_COLOR)
    fg_bgr = _color_str_to_ass_bgr(OVERLAY_TEXT_COLOR)

    # ASS alpha: 0x00=opaque, 0xFF=transparent.
    # Background target: 0x33 ≈ 80% opaque, matching the original -alpha 0.8.
    bg_ass_alpha = max(0, min(255, round(0x33 + (255 - 0x33) * (1.0 - alpha_frac))))
    fg_ass_alpha = max(0, min(255, round(255 * (1.0 - alpha_frac))))
    bg_alpha_hex = f"{bg_ass_alpha:02X}"
    fg_alpha_hex = f"{fg_ass_alpha:02X}"

    def _esc(text):
        return text.replace('{', '').replace('}', '').replace('\n', r'\N')

    events = []

    # Background rectangle
    events.append(
        f"{{\\an7\\pos({bx},{by})"
        f"\\1c&H{bg_bgr}&\\1a&H{bg_alpha_hex}&\\bord0\\shad0\\p1}}"
        f"m 0 0 l {box_w} 0 {box_w} {box_h} 0 {box_h}{{\\p0}}"
    )

    ty = by + pad_y
    _title_tags  = "\\bord0\\shad0\\b1\\q2\\u1"
    _detail_tags = "\\bord0\\shad0\\b1\\q2"

    if title_lines:
        events.append(
            f"{{\\an8\\pos({cx},{ty})"
            f"\\1c&H{fg_bgr}&\\1a&H{fg_alpha_hex}&{_title_tags}"
            f"\\fs{fs_title}}}{_esc(title_wrapped)}"
        )
        ty += row_h_title + gap

    img_top_y = ty   # OSD y where the thumbnail will be pasted (for PIL overlay)
    if pil_image:
        ty += img_h_osd + gap

    if details_lines:
        events.append(
            f"{{\\an8\\pos({cx},{ty})"
            f"\\1c&H{fg_bgr}&\\1a&H{fg_alpha_hex}&{_detail_tags}"
            f"\\fs{fs_details}}}{_esc(details_wrapped)}"
        )

    try:
        _osd_command('osd-overlay', _COMING_UP_ASS_OSD_ID, 'ass-events',
                     "\n".join(events), osd_w, osd_h, 3, 'no')
    except Exception as e:
        print(f"Coming-up OSD error: {e}")

    # PIL image overlay for thumbnail (layered on top of the ASS background)
    if pil_image is not None:
        try:
            canvas = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
            img_x  = bx + (box_w - img_w_osd) // 2
            img_y  = img_top_y
            scaled = (pil_image.resize((img_w_osd, img_h_osd), Image.LANCZOS)
                      if pil_image.size != (img_w_osd, img_h_osd) else pil_image.copy())
            if alpha_frac < 1.0:
                r, g, b, a = scaled.split()
                a = a.point(lambda px: int(px * alpha_frac))
                scaled = Image.merge("RGBA", (r, g, b, a))
            # Clip if the box is still sliding in from off the top
            src, paste_x, paste_y = scaled, img_x, img_y
            if paste_y < 0:
                crop_top = -paste_y
                if crop_top < img_h_osd:
                    src      = scaled.crop((0, crop_top, img_w_osd, img_h_osd))
                    paste_y  = 0
                else:
                    src = None
            if src is not None:
                canvas.paste(src, (paste_x, paste_y), src)
            if _coming_up_img_overlay is None:
                _coming_up_img_overlay = player._p.create_image_overlay()
            _coming_up_img_overlay.update(canvas)
        except Exception as e:
            print(f"Coming-up image OSD error: {e}")
    elif _coming_up_img_overlay is not None:
        try:
            _coming_up_img_overlay.remove()
        except Exception:
            pass
        _coming_up_img_overlay = None


_skip_to_end_after = None  # root.after handle for the skip-to-end flash animation

def show_skip_to_end_osd():
    """Show a brief centered 'SKIPPED TO END' ASS overlay that fades out."""
    global _skip_to_end_after
    if _skip_to_end_after is not None:
        try:
            root.after_cancel(_skip_to_end_after)
        except Exception:
            pass
        _skip_to_end_after = None

    HOLD_MS  = 1400   # time fully visible
    FADE_MS  = 500    # fade-out duration
    STEPS    = 20

    def _render(alpha_frac):
        try:
            osd_w = int(player._p.osd_width  or 0) or 1920
            osd_h = int(player._p.osd_height or 0) or 1080
            modifier = min(osd_w / 2560, osd_h / 1440)
            fs = max(18, round(52 * modifier * 1.6))
            cx, cy = osd_w // 2, osd_h // 2

            label = "\u23ed SKIPPED TO END"
            fnt = _get_ass_font(fs)
            try:
                text_w = round(fnt.getlength(label)) if fnt else round(len(label) * fs * 0.55)
            except AttributeError:
                text_w = fnt.getsize(label)[0] if fnt else round(len(label) * fs * 0.55)

            pad_x = max(10, round(fs * 0.55))
            pad_y = max(6,  round(fs * 0.30))
            line_h = round(fs * 1.15)
            box_w  = text_w + 2 * pad_x
            box_h  = line_h + 2 * pad_y
            bx = cx - box_w // 2
            by = cy - box_h // 2

            # Blue palette — dark navy fill, bright-blue border, white text
            # ASS colors are &HBBGGRR& (little-endian BGR)
            bg_bgr     = "3A1A0D"   # #0D1A3A dark navy
            border_bgr = "AA6633"   # #3366AA medium blue
            text_bgr   = "FFFFFF"   # white

            bg_a     = max(0, min(255, round(0x1A + (255 - 0x1A) * (1.0 - alpha_frac))))  # nearly opaque
            border_a = max(0, min(255, round(255 * (1.0 - alpha_frac))))
            text_a   = border_a
            bg_ah     = f"{bg_a:02X}"
            border_ah = f"{border_a:02X}"
            text_ah   = f"{text_a:02X}"

            bord_w = max(2, round(3 * modifier * 1.6))

            events = [
                # Background fill + blue border using drawing mode
                f"{{\\an7\\pos({bx},{by})"
                f"\\1c&H{bg_bgr}&\\1a&H{bg_ah}&"
                f"\\3c&H{border_bgr}&\\3a&H{border_ah}&"
                f"\\bord{bord_w}\\shad0\\p1}}"
                f"m 0 0 l {box_w} 0 {box_w} {box_h} 0 {box_h}{{\\p0}}",
                # Text — white, dark outline for readability
                f"{{\\an5\\pos({cx},{cy})"
                f"\\1c&H{text_bgr}&\\1a&H{text_ah}&"
                f"\\3c&H{border_bgr}&\\3a&H{border_ah}&"
                f"\\bord{bord_w}\\shad0\\b1\\fs{fs}}}{label}",
            ]
            _osd_command('osd-overlay', _SKIP_TO_END_ASS_OSD_ID, 'ass-events',
                         "\n".join(events), osd_w, osd_h, 3, 'no')
        except Exception as e:
            print(f"Skip-to-end OSD error: {e}")

    def _clear():
        global _skip_to_end_after
        _skip_to_end_after = None
        try:
            _osd_command('osd-overlay', _SKIP_TO_END_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
        except Exception:
            pass

    def _fade(step):
        global _skip_to_end_after
        if step > STEPS:
            _clear()
            return
        alpha = 1.0 - (step / STEPS)
        _render(alpha)
        _skip_to_end_after = root.after(FADE_MS // STEPS, lambda s=step+1: _fade(s))

    _render(1.0)
    _skip_to_end_after = root.after(HOLD_MS, lambda: _fade(0))


_ff_to_end_after = None   # root.after handle for fast-forward polling

def fast_forward_to_end(speed=4, ff_ms=500):
    """Play at `speed`x for `ff_ms` milliseconds for a visual FF effect,
    then seek directly to 3 seconds before the end and restore normal rate."""
    global _ff_to_end_after
    length_ms = player.get_length()
    if length_ms <= 3000:
        return
    # Cancel any existing FF session
    if _ff_to_end_after is not None:
        try:
            root.after_cancel(_ff_to_end_after)
        except Exception:
            pass
        _ff_to_end_after = None
    filename_at_start = currently_playing.get("filename")
    normal_rate = light_speed_modifier  # preserve lightning-round rate
    player.set_rate(speed)
    show_skip_to_end_osd()

    def _finish():
        global _ff_to_end_after
        _ff_to_end_after = None
        if currently_playing.get("filename") != filename_at_start:
            return
        player.set_rate(normal_rate)
        cur_length_ms = player.get_length()
        if cur_length_ms > 3000:
            seek_to(cur_length_ms - 3000)
        # root.after(0, show_skip_to_end_osd)

    _ff_to_end_after = root.after(ff_ms, _finish)


def _hide_coming_up_osd():
    """Immediately clear the coming-up ASS overlay and PIL image overlay."""
    global _coming_up_osd_visible, _coming_up_osd_current_title
    global _coming_up_img_overlay, _coming_up_anim_after
    if _coming_up_anim_after is not None:
        try:
            root.after_cancel(_coming_up_anim_after)
        except Exception:
            pass
        _coming_up_anim_after = None
    try:
        _osd_command('osd-overlay', _COMING_UP_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
    except Exception:
        pass
    if _coming_up_img_overlay is not None:
        try:
            _coming_up_img_overlay.remove()
        except Exception:
            pass
        _coming_up_img_overlay = None
    _coming_up_osd_visible       = False
    _coming_up_osd_current_title = ""


def toggle_coming_up_popup(show, title="", details="", image=None, up_next=True, queue=False):
    """Creates or destroys the lightning round announcement popup (OSD-based).

    *image* must be a PIL RGBA Image or None — callers pass the PIL image directly,
    not an ImageTk.PhotoImage.
    """
    global coming_up_queue
    global _coming_up_osd_current_title, _coming_up_anim_after

    if not show:
        if _coming_up_osd_visible:
            if title == "" or (title and title.lower() in _coming_up_osd_current_title.lower()):
                _hide_coming_up_osd()
        if coming_up_queue:
            if title in coming_up_queue["title"]:
                coming_up_queue = None
        return

    if queue and player.is_playing():
        coming_up_queue = {
            "title":   title,
            "details": details,
            "image":   image,
            "up_next": up_next,
        }
        return

    title_text = ("UP NEXT: " + title.upper() + "!") if up_next else title.upper()
    if title_text == _coming_up_osd_current_title:
        return

    # Cancel any in-progress slide-in; clear whatever is currently shown
    if _coming_up_anim_after is not None:
        try:
            root.after_cancel(_coming_up_anim_after)
        except Exception:
            pass
        _coming_up_anim_after = None
    if _coming_up_osd_visible:
        _hide_coming_up_osd()

    osd_w, osd_h = _coming_up_get_osd_dims()
    if not osd_w or not osd_h:
        return

    _coming_up_osd_current_title = title_text

    # Pre-render off-screen to populate _coming_up_osd_box_h before the animation starts
    _render_coming_up_frame(title_text, details, image, -9999, osd_w, osd_h, 0.0)
    box_h = _coming_up_osd_box_h
    if not box_h:
        return

    target_y = max(4, round(osd_h * 0.014))  # ≈20 px at 1440p, matches original y=20

    # Slide-in animation: time-based, ~100 ms duration
    duration = 0.10   # seconds
    poll     = 5      # ms between frames
    t0 = time.perf_counter()

    def _slide_step():
        global _coming_up_anim_after, _coming_up_osd_visible
        t = min((time.perf_counter() - t0) / duration, 1.0)
        bounce = math.sin(t * math.pi) * 5 if t > 0.7 else 0
        y = int(-box_h + (target_y + box_h) * t + bounce)
        _render_coming_up_frame(title_text, details, image, y, osd_w, osd_h, t)
        if t < 1.0:
            _coming_up_anim_after = root.after(poll, _slide_step)
        else:
            _coming_up_osd_visible = True
            _coming_up_anim_after  = None

    root.after(10, _slide_step)

format_slug = utils.format_slug

# =========================================
#            *PROGRESS BAR
# =========================================

progress_bar = None  # kept for compatibility checks elsewhere (always None now)
progress_bar_enabled = True
_PROGRESS_BAR_HEIGHT_PCT = 0.008  # fraction of OSD height (0.8%)
# ASS alpha: 0=opaque 255=transparent; 0xB2=178 ≈ 70% transparent (≈30% opaque, matching old -alpha 0.3)
_PROGRESS_BAR_ASS_ALPHA = 0xB2

def _draw_progress_osd(fraction, color_str="grey"):
    """Draw the progress bar OSD using ASS overlay — always composites above PIL image overlays."""
    try:
        osd_w = int(player._p.osd_width or 0)
        osd_h = int(player._p.osd_height or 0)
    except Exception:
        osd_w, osd_h = 0, 0
    if not osd_w or not osd_h:
        return

    fill_w = max(0, int(osd_w * fraction))
    if fill_w <= 0:
        _clear_progress_osd()
        return

    bar_h = max(4, int(osd_h * _PROGRESS_BAR_HEIGHT_PCT))
    y0 = osd_h - bar_h

    try:
        rgb = ImageColor.getrgb(color_str)
    except Exception:
        rgb = (128, 128, 128)
    r, g, b = rgb
    # ASS color format: &HBBGGRR& (blue-green-red order)
    color_hex = f"{b:02X}{g:02X}{r:02X}"
    alpha_hex = f"{_PROGRESS_BAR_ASS_ALPHA:02X}"

    path = f"m 0 {y0} l {fill_w} {y0} {fill_w} {osd_h} 0 {osd_h}"
    ass_payload = (
        f"{{\\an7\\pos(0,0)\\1c&H{color_hex}&\\1a&H{alpha_hex}&\\bord0\\shad0\\p1}}"
        + path
        + "{\\p0}"
    )
    try:
        _osd_command('osd-overlay', _PROGRESS_ASS_OSD_ID, 'ass-events',
                          ass_payload, osd_w, osd_h, 2, 'no')  # z=2, above blind at z=1
    except Exception as e:
        print(f"Progress OSD error: {e}")

def _clear_progress_osd():
    try:
        _osd_command('osd-overlay', _PROGRESS_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
    except Exception:
        pass

