#           *EDGE / GROW OSD
# =========================================

_peek_osd_a = None   # mpv ImageOverlay used by edge and grow variants (static overlays)

_PEEK_BLACK = (0, 0, 0, 255)  # premultiplied black

def _clear_peek_osd():
    global _peek_osd_a
    if _peek_osd_a is not None:
        try:
            _peek_osd_a.remove()
        except Exception:
            pass
        _peek_osd_a = None

def _push_peek_img(img):
    """Upload a PIL RGBA canvas to the edge/grow overlay, creating it if needed."""
    global _peek_osd_a
    try:
        if _peek_osd_a is None:
            _peek_osd_a = player._p.create_image_overlay()
        _peek_osd_a.update(img)
    except Exception as e:
        print(f"Peek OSD error: {e}")

def _draw_edge_osd(block_percent):
    """Draw a solid center box covering the video interior; edges remain visible."""
    osd_w, osd_h, vid_x, vid_y, vid_w, vid_h = _get_effective_video_rect()
    if not osd_w or not vid_w:
        return
    visible_pct = 100 - block_percent
    margin = int(min(vid_w, vid_h) * (visible_pct / 100.0 / 2.0))
    box_w = max(0, vid_w - margin * 2)
    box_h = max(0, vid_h - margin * 2)
    if not box_w or not box_h:
        _clear_peek_osd()
        return
    img = Image.new("RGBA", (osd_w, osd_h), (0, 0, 0, 0))
    bx = vid_x + margin
    by = vid_y + margin
    ImageDraw.Draw(img).rectangle([bx, by, bx + box_w - 1, by + box_h - 1], fill=_PEEK_BLACK)
    _push_peek_img(img)

_grow_osd_last_ms = 0.0   # wall time of last ASS push; throttle to ~60fps

def _draw_grow_osd(block_percent, cx_osd, cy_osd):
    """Draw four ASS panels surrounding a visible hole centered at (cx_osd, cy_osd).
    Uses mpv osd-overlay (ass-events) — no pixel data uploaded, GPU-rendered.
    The payload starts with '{' so mpv's text-echo produces nothing visible.
    """
    global _grow_osd_last_ms
    import time as _time_mod
    now = _time_mod.monotonic()
    if (now - _grow_osd_last_ms) < 0.016:  # ~60fps cap
        return
    try:
        osd_w, osd_h, fv_x, fv_y, fv_w, fv_h = _get_effective_video_rect()
        if not osd_w:
            return
        visible_w = int(fv_w * (1.0 - block_percent / 100.0))
        visible_h = int(fv_h * (1.0 - block_percent / 100.0))
        hole_l = max(fv_x, cx_osd - visible_w // 2)
        hole_t = max(fv_y, cy_osd - visible_h // 2)
        hole_r = min(fv_x + fv_w, cx_osd + visible_w // 2)
        hole_b = min(fv_y + fv_h, cy_osd + visible_h // 2)

        # Build the four surrounding panels as ASS vector paths.
        # All paths share one \p1 drawing block; multiple 'm' subpaths = multiple filled regions.
        # When framed video is active, panels are clipped to the framed rect (not the full OSD).
        out_l, out_t, out_r, out_b = fv_x, fv_y, fv_x + fv_w, fv_y + fv_h
        paths = []
        if hole_t > out_t:                    # top strip (inside framed rect)
            paths.append(f"m {out_l} {out_t} l {out_r} {out_t} {out_r} {hole_t} {out_l} {hole_t}")
        if hole_b < out_b:                    # bottom strip
            paths.append(f"m {out_l} {hole_b} l {out_r} {hole_b} {out_r} {out_b} {out_l} {out_b}")
        if hole_l > out_l:                    # left strip (between top/bottom strips)
            paths.append(f"m {out_l} {hole_t} l {hole_l} {hole_t} {hole_l} {hole_b} {out_l} {hole_b}")
        if hole_r < out_r:                    # right strip
            paths.append(f"m {hole_r} {hole_t} l {out_r} {hole_t} {out_r} {hole_b} {hole_r} {hole_b}")

        if not paths:
            # Fully uncovered — nothing to draw
            _osd_command('osd-overlay', _GROW_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
            return

        ass_payload = (
            "{\\an7\\pos(0,0)\\1c&H000000&\\bord0\\shad0\\p1}"
            + " ".join(paths)
            + "{\\p0}"
        )
        _osd_command('osd-overlay', _GROW_ASS_OSD_ID, 'ass-events',
                          ass_payload, osd_w, osd_h, 0, 'no')
        _grow_osd_last_ms = now
    except Exception as e:
        print(f"Grow OSD (ASS) error: {e}")


def _effective_remaining_ms(current_ms, total_ms, filename):
    """Remaining ms of audible content, subtracting upcoming skip-censor durations.
    Uses in-memory censor data so it is safe to call on every seek-bar tick."""
    raw = max(0.0, total_ms - current_ms)
    if not (censors.censors_enabled or censors.censors_nsfw_enabled) or not filename:
        return raw
    file_censors = censors.get_file_censors(filename) or []
    cur_s = current_ms / 1000.0
    skip_ahead_s = 0.0
    for c in file_censors:
        if not c.get("skip"):
            continue
        s = float(c.get("start", 0))
        e = float(c.get("end", 0))
        if e - s <= 0 or e <= cur_s:
            continue
        skip_ahead_s += e - max(s, cur_s)
    return max(0.0, raw - skip_ahead_s * 1000.0)


def _apply_skip_censor_to_progress(current_time_ms, total_time_ms, filename):
    """Adjust current/total time (in ms) to exclude skip-censor durations.
    Returns (effective_current_ms, effective_total_ms).
    Falls back to the original values on any error or when no filename is given.
    """
    if not filename:
        return current_time_ms, total_time_ms
    try:
        if not os.path.exists(CENSOR_JSON_FILE):
            return current_time_ms, total_time_ms
        with open(CENSOR_JSON_FILE, "r") as f:
            censor_data = json.load(f)
        file_censors = censor_data.get(filename, [])
        cur_s = current_time_ms / 1000.0
        tot_s = total_time_ms / 1000.0
        total_skip = 0.0
        skip_before = 0.0
        for censor in [c for c in file_censors if c.get("skip")]:
            s, e = censor["start"], censor["end"]
            dur = e - s
            if dur <= 0:
                continue
            total_skip += dur
            if e <= cur_s:
                skip_before += dur
            elif s < cur_s:
                skip_before += cur_s - s
        eff_cur = max(0.0, cur_s - skip_before) * 1000.0
        eff_tot = max(1.0, tot_s - total_skip) * 1000.0
        return eff_cur, eff_tot
    except Exception:
        return current_time_ms, total_time_ms


def update_progress_bar(current_time, total_time, filename=None):

    if not progress_bar_enabled:
        _clear_progress_osd()
        return

    # During lightning rounds, override current_time/total_time to show round
    # progress (question + answer phases) rather than raw video position.
    # For fixed playlists this extends across the entire playlist.
    if light_round_started and light_round_start_time is not None:
        if _light_answer_wall_start is not None:
            _current_round_elapsed = light_round_length + (_wall_time() - _light_answer_wall_start)
        else:
            _current_round_elapsed = max(0.0, projected_player_time / 1000.0 - light_round_start_time)
        if fixed_lightning_round_playlist_data:
            _pl = _get_fixed_playlist_progress(_current_round_elapsed)
            if _pl:
                current_time = _pl[0] * 10
                total_time = _pl[1] * 10
                filename = None
        else:
            _round_total = light_round_length + light_round_answer_length
            current_time = min(_current_round_elapsed, _round_total) * 1000
            total_time = _round_total * 1000
            filename = None

    if total_time <= 0:
        return

    # Calculate effective time excluding skip censors
    effective_current_time, effective_total_time = _apply_skip_censor_to_progress(
        current_time, total_time, filename
    )

    fraction = effective_current_time / effective_total_time
    _draw_progress_osd(fraction)

# =========================================
#            *BLIND SCREEN
# =========================================

black_overlay = None      # None = blind inactive; True = blind active (OSD-based)
_blind_osd_color_cache = "#000000"  # last color used; needed for hide path
blind_enabled = False
manual_blind = False

_video_frame_active = False
_FRAME_VIDEO_ZOOM         = -0.45   # 2^(-0.45) ≈ 73.3% — question phase
_FRAME_VIDEO_ZOOM_ANSWER  = -0.45   # 2^(-0.45) ≈ 73.3% — answer phase
_FRAME_PAN_Y              = -0.03   # shift video upward (fraction of display height)
_video_frame_zoom  = _FRAME_VIDEO_ZOOM   # currently applied zoom level
_video_frame_color = "#000000"          # sampled at activation; avoids re-reading during draw

def _draw_frame_border_osd():
    """Draw the framed-video effect: image-color fill in margins + white outline ring around the video."""
    try:
        osd_w = int(player._p.osd_width or 0)
        osd_h = int(player._p.osd_height or 0)
    except Exception:
        return
    if not (osd_w and osd_h):
        return
    scale = 2 ** _video_frame_zoom
    _, _, vid_x, vid_y, vid_w, vid_h = _get_osd_video_rect()
    if not vid_w:
        vid_x, vid_y, vid_w, vid_h = 0, 0, osd_w, osd_h
    # Video rect after zoom + vertical pan applied from OSD centre
    new_w = round(vid_w * scale)
    new_h = round(vid_h * scale)
    y_shift = round(new_h * abs(_FRAME_PAN_Y))  # upward shift in OSD pixels
    new_x = round((osd_w - new_w) / 2)
    new_y = round((osd_h - new_h) / 2) - y_shift
    # Outline ring thickness (scales with OSD size)
    ring_px = max(3, round(min(osd_w, osd_h) * 0.006))
    ox, oy = new_x - ring_px, new_y - ring_px
    ow, oh = new_w + ring_px * 2, new_h + ring_px * 2
    # Fill color sampled at activation time (stored in _video_frame_color)
    color_str = _video_frame_color
    try:
        r16, g16, b16 = root.winfo_rgb(color_str)
        r, g, b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        r, g, b = 0, 0, 0
    color_hex = f"{b:02X}{g:02X}{r:02X}"
    # ── OSD 60: image-color fill, clipped to leave the outline+video area transparent ──
    canvas_path = f"m 0 0 l {osd_w} 0 {osd_w} {osd_h} 0 {osd_h}"
    ass_bg = (
        f"{{\\an7\\pos(0,0)\\1c&H{color_hex}&\\1a&H00&\\bord0\\shad0"
        f"\\iclip({ox},{oy},{ox+ow},{oy+oh})\\p1}}"
        + canvas_path + "{\\p0}"
    )
    # ── OSD 61: white donut outline ring (clockwise outer, CCW inner → hollow) ──
    # Clockwise outer: TL→TR→BR→BL
    outer = f"m {ox} {oy} l {ox+ow} {oy} {ox+ow} {oy+oh} {ox} {oy+oh}"
    # Counter-clockwise inner: TL→BL→BR→TR
    inner = f"m {new_x} {new_y} l {new_x} {new_y+new_h} {new_x+new_w} {new_y+new_h} {new_x+new_w} {new_y}"
    ass_ring = (
        f"{{\\an7\\pos(0,0)\\1c&HFFFFFF&\\1a&H00&\\bord0\\shad0\\p1}}"
        + outer + " " + inner + "{\\p0}"
    )
    try:
        _osd_command('osd-overlay', _FRAME_BORDER_ASS_OSD_ID, 'ass-events',
                     ass_bg, osd_w, osd_h, 0, 'no')  # z=0: behind blind (z=1)
    except Exception as e:
        print(f"[frame_border] bg OSD error: {e}")
    try:
        _osd_command('osd-overlay', _FRAME_OUTLINE_ASS_OSD_ID, 'ass-events',
                     ass_ring, osd_w, osd_h, 0, 'no')  # z=0: behind blind (z=1)
    except Exception as e:
        print(f"[frame_border] ring OSD error: {e}")

def set_video_frame(enabled, answer_phase=False):
    """Enable, update, or disable the framed-video lightning round effect."""
    global _video_frame_active, _video_frame_zoom, _video_frame_color
    _video_frame_active = bool(enabled)
    if not enabled:
        _video_frame_zoom = _FRAME_VIDEO_ZOOM
        _video_frame_color = "#000000"
        try:
            player._p.video_zoom = 0
        except Exception:
            pass
        try:
            player._p.video_pan_y = 0
        except Exception:
            pass
        for _oid in (_FRAME_BORDER_ASS_OSD_ID, _FRAME_OUTLINE_ASS_OSD_ID):
            try:
                _osd_command('osd-overlay', _oid, 'none', '', 0, 0, 0, 'no')
            except Exception:
                pass
        _unregister_mpv_tracked_window("frame_border")
        return
    _video_frame_zoom = _FRAME_VIDEO_ZOOM_ANSWER if answer_phase else _FRAME_VIDEO_ZOOM
    # Use the same color the blind was rendered with; fall back to sampling if not set
    _video_frame_color = _blind_osd_color_cache if _blind_osd_color_cache and _blind_osd_color_cache != "#000000" else (get_image_color() or get_random_blind_color())
    try:
        player._p.video_zoom = _video_frame_zoom
    except Exception:
        pass
    try:
        player._p.video_pan_y = _FRAME_PAN_Y
    except Exception:
        pass
    def _on_mpv_rect(mx, my, mw, mh):
        if _video_frame_active:
            _draw_frame_border_osd()
    _register_mpv_tracked_window("frame_border", None, _on_mpv_rect)
    _draw_frame_border_osd()


def _set_blind_osd_alpha(color_str, alpha):
    """Show or hide the blind OSD using ASS osd-overlay (z=1, below progress bar at z=2)."""
    # ASS alpha: 0x00=opaque, 0xFF=transparent. Convert from PIL-style 0-255 opacity.
    if alpha <= 0:
        # Hide — clear the overlay
        try:
            _osd_command('osd-overlay', _BLIND_ASS_OSD_ID, 'none', '', 0, 0, 0, 'no')
        except Exception:
            pass
        return
    try:
        osd_w = int(player._p.osd_width or 0)
        osd_h = int(player._p.osd_height or 0)
        if not (osd_w and osd_h):
            return
    except Exception:
        return
    try:
        r16, g16, b16 = root.winfo_rgb(color_str)
        r, g, b = r16 >> 8, g16 >> 8, b16 >> 8
    except Exception:
        r, g, b = 0, 0, 0
    # ASS color: &HBBGGRR&; alpha tag: &HXX& where 0=opaque, 255=transparent
    color_hex = f"{b:02X}{g:02X}{r:02X}"
    ass_alpha = max(0, 255 - alpha)  # invert: PIL 255=opaque → ASS 0x00=opaque
    alpha_hex = f"{ass_alpha:02X}"
    path = f"m 0 0 l {osd_w} 0 {osd_w} {osd_h} 0 {osd_h}"
    ass_payload = (
        f"{{\\an7\\pos(0,0)\\1c&H{color_hex}&\\1a&H{alpha_hex}&\\bord0\\shad0\\p1}}"
        + path
        + "{\\p0}"
    )
    try:
        _osd_command('osd-overlay', _BLIND_ASS_OSD_ID, 'ass-events',
                          ass_payload, osd_w, osd_h, 1, 'no')  # z=1
    except Exception as e:
        print(f"Blind OSD error: {e}")


def blind(manual=False):
    """Toggle blind (black) overlay."""
    global manual_blind
    if black_overlay is None:
        manual_blind = manual
        set_black_screen(True)
    else:
        manual_blind = False
        if not streaming.currently_streaming:
            toggle_mute(False, True)
        set_black_screen(False)
        set_progress_overlay(destroy=True)

def set_black_screen(toggle, smooth=True, color=None):
    global black_overlay, _blind_osd_color_cache
    if toggle:
        _color = color if color else get_image_color()
        # If no explicit color was requested and the sampled color is near-black
        # (first frame not yet decoded or video fades in from black), use a
        # random color so the blind doesn't appear solid black.
        if not color and _color:
            try:
                _h = _color.lstrip('#')
                if len(_h) == 6 and (int(_h[0:2], 16) + int(_h[2:4], 16) + int(_h[4:6], 16)) < 60:
                    _color = get_random_blind_color()
            except Exception:
                pass
        _blind_osd_color_cache = _color
        black_overlay = True
        _set_blind_osd_alpha(_color, 255)
        set_blind_enabled(True)
        _register_mpv_tracked_window("blind_osd", None, _blind_osd_on_mpv_rect)
    else:
        if black_overlay:
            _set_blind_osd_alpha(_blind_osd_color_cache, 0)
        black_overlay = None
        _unregister_mpv_tracked_window("blind_osd")
        set_blind_enabled(False)
        _commit_censor_osd()  # restore censor overlay now that blind is gone
    root.after(100, configure_style)

def set_blind_enabled(toggle):
    global blind_enabled, manual_blind
    if toggle and not black_overlay:
        toggle = False
    blind_enabled = toggle
    if not toggle:
        manual_blind = False


blind_round_toggle = False
def toggle_blind_round():
    global blind_round_toggle
    blind_round_toggle = not blind_round_toggle
    if blind_round_toggle:
        if peek_round_toggle:
            toggle_peek_round()
        if mute_peek_round_toggle:
            toggle_mute_peek_round()
            
        if special_round_warning:
            toggle_coming_up_popup(True, "Blind Round", "Guess the anime from just the music.\nNormal rules apply.", queue=True)
    else:
        toggle_coming_up_popup(False, "Blind Round")

