def _theme_context_menu(filename, refresh_func, play_func=None, remove_func=None):
    """Show the standard theme right-click context menu for any theme list.

    play_func:   optional callable with no args used for "Play Now"; defaults to
                 play_video_from_filename(filename).
    remove_func: optional callable with no args; when provided, a "Remove from
                 Playlist" item is appended at the bottom.
    """
    filename = get_clean_filename(filename)
    m = tk.Menu(root, tearoff=0, bg="black", fg="white",
                activebackground=HIGHLIGHT_COLOR, activeforeground="white", font=MENU_FONT)

    # Play Now
    if play_func is None:
        play_func = lambda f=filename: play_video_from_filename(f)
    m.add_command(label="     Play Now", command=play_func)

    m.add_separator()

    # Queue Next / Un-Queue Next
    is_queued = search_ops.search_queue == filename
    queue_label = "✓  Queue Next" if is_queued else "     Queue Next"
    def _toggle_queue(f=filename):
        search_ops.search_queue = None if search_ops.search_queue == f else f
        if search_ops.search_queue and not player.is_playing():
            play_video()
            return
        refresh_func()
        up_next_text()
    m.add_command(label=queue_label, command=_toggle_queue)

    # Add Next
    def _add_next(f=filename):
        playlist["playlist"].insert(playlist["current_index"] + 1, f)
        up_next_text()
        save_config()
    m.add_command(label="     Add Next", command=_add_next)

    m.add_separator()

    # Mark submenu
    sub = tk.Menu(m, tearoff=0, bg="black", fg="white",
                  activebackground=HIGHLIGHT_COLOR, activeforeground="white", font=MENU_FONT)

    def _mark(playlist_name, exclusive=None, f=filename):
        # Remove mutually exclusive marks first
        if exclusive:
            for excl in exclusive:
                if check_theme(f, excl):
                    toggle_theme(excl, filename=f, quiet=True)
        toggle_theme(playlist_name, filename=f, quiet=True)
        refresh_func()

    marks = [
        ("Tagged",    "Tagged Themes",    None),
        ("Favorite",  "Favorite Themes",  None),
        ("Blind",     "Blind Themes",       ["Reveal Themes", "Mute Reveal Themes"]),
        ("Reveal",    "Reveal Themes",      ["Blind Themes", "Mute Reveal Themes"]),
        ("Mute Reveal", "Mute Reveal Themes", ["Blind Themes", "Reveal Themes"]),
    ]
    for label, pname, exclusive in marks:
        is_marked = check_theme(filename, pname, recache=True)
        entry_label = ("✓  " if is_marked else "     ") + label
        sub.add_command(label=entry_label, command=lambda p=pname, e=exclusive: _mark(p, e))

    m.add_cascade(label="     Mark ▸", menu=sub)

    m.add_separator()

    # Add to Playlist
    m.add_command(label="     Add to Playlist…", command=lambda f=filename: add_to_saved_playlist(f))

    if remove_func is not None:
        m.add_separator()
        m.add_command(label="     Remove from Playlist", command=remove_func)

    try:
        popup_menu(m, root.winfo_pointerx(), root.winfo_pointery())
    finally:
        pass

last_themes_listed = {}
def show_field_themes(update = False, group=[], title=None):
    global last_themes_listed
    if group == []:
        field_list = last_themes_listed
        if title is None:  # Preserve existing title when refreshing
            title = current_list_title
    else:
        field_list = group
    if last_themes_listed != group:
        update = True
    def _field_slug_sort_key(file):
        fname = get_clean_filename(file)
        meta = get_metadata(fname)
        slug = (meta.get("slug") or "").upper() if meta else ""
        title_key = (meta.get("eng_title") or meta.get("title") or fname).lower() if meta else fname.lower()
        if slug.startswith("OP"):
            slug_type = 0
            num_str = slug[2:]
        elif slug.startswith("ED"):
            slug_type = 1
            num_str = slug[2:]
        else:
            slug_type = 2
            num_str = slug
        slug_num = int(num_str) if num_str.isdigit() else 0
        return (title_key, slug_type, slug_num)
    field_list.sort(key=_field_slug_sort_key)
    last_themes_listed = field_list
    selected = -1
    if search_ops.search_queue:
        for index, filename in enumerate(field_list):
            if get_clean_filename(filename) == search_ops.search_queue or filename == search_ops.search_queue:
                selected = index
                break
    show_list("field_list", right_column, convert_playlist_to_dict(field_list), get_title, set_field_queue, selected, update, right_click_func=add_field_to_playlist, title=title)

def get_title(key, value):
    try:
        is_lightning = value.startswith("[L]")
        lightning_icon = "⚡" if is_lightning else ""
        
        filename = get_clean_filename(value)
        
        if is_youtube_file(filename):
            youtube_data = get_youtube_metadata_by_filename(filename)
            if youtube_data:
                title = get_youtube_display_title(youtube_data)
                display_name = f"{lightning_icon}[YT] {title}"
            else:
                display_name = lightning_icon + filename
        else:
            # Regular theme file handling
            data = get_metadata(filename)
            if data:
                title = get_display_title(data)
                display_name = title + " " + data.get("slug")
                version_num = data.get("version")
                if version_num and version_num not in ["null", "1"]:
                    display_name += f"v{version_num}"
                if os.path.isabs(value):
                    display_name = "📁 " + display_name
                display_name = lightning_icon + display_name
            else:
                display_name = filename
                if os.path.isabs(value):
                    display_name = "📁 " + display_name
                display_name = lightning_icon + display_name
        
        if filename not in directory_files and "SEARCHING" not in filename:
            if is_animethemes_stream_file(filename):
                display_name = stream_icon + display_name
            else:
                display_name = "❌" + display_name
        return display_name
        
    except:
        filename = get_clean_filename(value)
        is_lightning = value.startswith("[L]")
        lightning_icon = "⚡" if is_lightning else ""
        return lightning_icon + (("📁 " + filename) if os.path.isabs(value) else filename)


def set_field_queue(index):
    if last_themes_listed and index >= 0:
        filename = get_clean_filename(last_themes_listed[index])
        if search_ops.search_queue == filename:
            search_ops.search_queue = None
        else:
            search_ops.search_queue = filename
            if not player.is_playing():
                play_video()
                return
        show_field_themes(True)
        up_next_text()

def add_field_to_playlist(index):
    if last_themes_listed and index >= 0:
        filename = get_clean_filename(last_themes_listed[index])
        _theme_context_menu(filename, lambda: show_field_themes(True))

def show_playlist(update = False):
    # Check if fixed lightning round is active - display those rounds instead
    if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
        rounds = fixed_lightning_round_playlist_data.get("rounds", [])
        rounds_dict = convert_fixed_rounds_to_dict(rounds)
        current_index = fixed_lightning_round_playlist_data.get("current_index", 0)
        show_list("playlist", right_column, rounds_dict, get_fixed_round_title, play_fixed_round_by_index, current_index, update, right_click_func=None, title=fixed_lightning_round_playlist_data.get("name") or "FIXED LIGHTNING ROUNDS")
    else:
        def _playlist_right_click(index):
            if not (0 <= index < len(playlist["playlist"])):
                return
            filename = playlist["playlist"][index]
            clean = get_clean_filename(filename)
            _theme_context_menu(
                clean,
                refresh_func=lambda: show_playlist(True),
                play_func=lambda i=index: play_video(i),
                remove_func=lambda i=index: remove_theme(i),
            )

        show_list("playlist", right_column, convert_playlist_to_dict(playlist["playlist"]), get_title, play_video, playlist["current_index"], update, right_click_func=_playlist_right_click, title=playlist.get("name") or "PLAYLIST")

def convert_fixed_rounds_to_dict(rounds):
    """Convert fixed lightning rounds to dict for display"""
    return {f"round_{i}": round_data for i, round_data in enumerate(rounds)}

def get_fixed_round_title(key, round_data):
    """Get display title for a fixed lightning round"""
    theme = round_data.get("theme", "Unknown")
    round_type = round_data.get("type", "regular")
    
    # Get anime title from metadata if possible
    try:
        data = get_metadata(theme, fetch=False)
        title = get_display_title(data)
    except:
        title = theme
    
    # Get icon from light_modes dictionary
    icon = light_modes.get(round_type, {}).get("icon", "⚡")
    
    return f"{icon}{title}"

def play_fixed_round_by_index(index):
    """Play a fixed lightning round by index"""
    global skip_direction
    
    if not fixed_lightning_round_playlist_data:
        return
    
    rounds = fixed_lightning_round_playlist_data.get("rounds", [])
    if 0 <= index < len(rounds):
        # Calculate skip direction based on current vs target index
        current_index = fixed_lightning_round_playlist_data.get("current_index", 0)
        skip_direction = 1 if index > current_index else -1
        
        # Set to one before target so play_video advances to it
        fixed_lightning_round_playlist_data["current_index"] = index - skip_direction
        
        # Play the video which will advance to the target index
        play_video()

def remove(update = False):
    show_list("remove", right_column, convert_playlist_to_dict(playlist["playlist"]), get_title, remove_theme, playlist["current_index"], update, title="REMOVE THEME")

def convert_playlist_to_dict(playlis):
    return {f"{video}_{i}": video for i, video in enumerate(playlis)}

def update_playlist_display():
    """Helper function to update the playlist display when the playlist changes"""
    if list_loaded == "playlist":
        global current_list_content, current_list_selected, current_list_name_func
        
        # Check if fixed lightning round is active
        if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
            rounds = fixed_lightning_round_playlist_data.get("rounds", [])
            current_list_content = convert_fixed_rounds_to_dict(rounds)
            current_list_selected = fixed_lightning_round_playlist_data.get("current_index", 0)
            current_list_name_func = get_fixed_round_title
        else:
            current_list_content = convert_playlist_to_dict(playlist["playlist"])
            current_list_selected = playlist["current_index"]
            current_list_name_func = get_title
        
        refresh_current_list()

def remove_theme(index):
    global current_list_content, current_list_selected
    playlist_entry = playlist["playlist"][index]
    display_name = os.path.basename(playlist_entry) if os.path.isabs(playlist_entry) else playlist_entry
    confirm = messagebox.askyesno("Remove Theme", f"Are you sure you want to remove '{display_name}' from '{playlist["name"]}'?")
    if not confirm:
        return  # User canceled
    del playlist["playlist"][index]
    
    # Update current_list_content to reflect the removal
    if list_loaded == "playlist":
        current_list_content = convert_playlist_to_dict(playlist["playlist"])
        if current_list_selected > index:
            current_list_selected -= 1
        elif current_list_selected == index and current_list_selected >= len(playlist["playlist"]):
            current_list_selected = len(playlist["playlist"]) - 1 if playlist["playlist"] else -1
        refresh_current_list()
    elif list_loaded == "remove":
        current_list_content = convert_playlist_to_dict(playlist["playlist"])
        # If we're in the remove view, we need to refresh that too
        remove_theme(True)


def button_seleted(button, selected):
    if hasattr(button, 'configure') and button.winfo_exists():
        if selected:
            button.configure(bg=HIGHLIGHT_COLOR, fg="white")
        else:
            button.configure(bg="black", fg="white")

list_loaded = None
list_index = 0
list_func = None
playlist_page_offset = 0
def get_list_entries_count():
    """Get the number of entries to show in lists based on available height."""
    try:
        # Get the actual height of the right_column widget
        right_column.update_idletasks()  # Ensure geometry is updated
        available_height = right_column.winfo_height()
        
        # If height is not yet available (window not fully initialized), use default logic
        if available_height <= 1:
            content = right_top.get(1.0, tk.END)
            content_stripped = content.strip()
            base = 13 if (not content_stripped or content_stripped == "" or len(content_stripped) == 0) else 12
            return base
        
        # Estimate button height including padding/spacing
        # Each button is roughly 25-30 pixels with spacing, using 28 as safe estimate
        button_height_estimate = scl(26, "UI")  # Adjusted for UI scaling
        
        # Calculate how many buttons can fit, with minimum of 8 and maximum of 20
        calculated_count = available_height // button_height_estimate
        
        return calculated_count
        
    except Exception:
        return 12  # Default fallback

persistent_buttons = []  # Store the reusable buttons for any list type
button_to_index_map = {}  # Map button widgets to their current indices
current_list_offset = 0  # Offset for any list type
current_list_content = {}  # Store current list content
current_list_name_func = None  # Store current name function
current_list_selected = -1  # Store the currently selected/playing item index
current_list_show_numbers = True  # Whether to show "N: " index prefix on list buttons
current_list_title = ""  # Title shown at top of list, if any
_list_action_from_keyboard = False  # True when list_select() was triggered by a key press
right_column_header = None  # Persistent header Frame packed above right_column
right_column_header_label = None  # Label widget inside right_column_header
right_column_back_button = None  # ← back button; shown when _list_nav_stack is non-empty
list_title_label = None  # Points to right_column_header_label when active
right_column_scrollbar = None  # Custom scrollbar for the list display
list_header_font = None  # Font used by the list title header (set at GUI time)
_list_nav_stack = []  # Stack of 0-arg callables; each restores the previous list

def push_list_nav(restore_fn):
    """Push restore_fn onto the back-navigation stack and show the ← button.
    Captures current_list_offset so scrolling position is restored on back."""
    saved_offset = current_list_offset
    def _restore():
        restore_fn()
        global current_list_offset
        current_list_offset = saved_offset
        refresh_current_list()
        update_list_scrollbar()
    _list_nav_stack.append(_restore)
    _update_back_button()

def clear_list_nav():
    """Clear the back-navigation stack and hide the ← button."""
    _list_nav_stack.clear()
    _update_back_button()

def _update_back_button():
    btn = globals().get('right_column_back_button')
    if btn is None or not btn.winfo_exists():
        return
    # Toggle visibility via fg colour — never pack/unpack so layout stays stable.
    btn.config(fg='white' if _list_nav_stack else BACKGROUND_COLOR)

def _go_back_list():
    """Pop and invoke the top of the navigation stack."""
    if _list_nav_stack:
        restore_fn = _list_nav_stack.pop()
        _update_back_button()
        restore_fn()

def _close_list(column, keep_focus=False):
    """Close the current list view and clear the column."""
    global current_list_title
    _list_nav_stack.clear()
    _update_back_button()
    _was_search = list_loaded in ["search", "search_add"]
    current_list_title = ""
    _insert_list_title_row(column)  # hides the header frame
    list_unload(column)
    try:
        column.config(state=tk.NORMAL)
        column.delete(1.0, tk.END)
        column.config(state=tk.DISABLED)
    except Exception:
        pass
    update_list_scrollbar()
    # Clear the toolbar search entry if a search list was closed
    if _was_search and not keep_focus:
        try:
            search_ops.search_term = ""
            if search_bar_entry and search_bar_entry.winfo_exists():
                search_bar_entry.delete(0, tk.END)
                search_bar_entry.insert(0, SEARCH_BAR_PLACEHOLDER)
                search_bar_entry.configure(fg="gray50")
                root.focus()
        except Exception:
            pass
    # Restore extra metadata if a theme is currently loaded
    if currently_playing.get("data") or currently_playing.get("type") == "youtube":
        update_extra_metadata(column)

def _insert_list_title_row(column):
    """Show, update, or hide the title header frame above right_column."""
    global list_title_label
    if right_column_header is None:
        return
    if current_list_title:
        # Truncate using right_column's width (always rendered) BEFORE packing,
        # so the label never has the full long text and can't push the frame wider.
        _do_truncate_header_title()
        if not right_column_header.winfo_ismapped():
            right_column_header.pack(fill="x", before=right_column_row)
        list_title_label = right_column_header_label
    else:
        if right_column_header.winfo_ismapped():
            right_column_header.pack_forget()
        list_title_label = None

_truncate_after_id = [None]  # debounce handle for _truncate_header_title

def _truncate_header_title(event=None):
    """Schedule header-title truncation, debounced to avoid Configure feedback loops."""
    if _truncate_after_id[0] is not None:
        try:
            right_column_header.after_cancel(_truncate_after_id[0])
        except Exception:
            pass
    _truncate_after_id[0] = right_column_header.after(25, _do_truncate_header_title)

def _do_truncate_header_title():
    """Actually compute and apply ellipsis truncation to the header label."""
    _truncate_after_id[0] = None
    if not current_list_title or right_column_header_label is None:
        return
    font_obj = list_header_font
    if font_obj is None:
        return
    # Use right_column's width as reference — it's always rendered with the correct width.
    # right_column_header.winfo_width() returns 1 until the frame is laid out, so
    # we can't rely on it here (especially before the header is packed the first time).
    ref_width = right_column.winfo_width() if right_column and right_column.winfo_exists() else 0
    if ref_width < 20:
        _set_header_label(current_list_title)
        return
    close_btn_est = scl(80, "UI")
    back_btn_est = scl(32, "UI")  # back button always occupies space
    available_w = max(20, ref_width - close_btn_est - back_btn_est)
    text = current_list_title
    if font_obj.measure(text) <= available_w:
        _set_header_label(text)
        return
    for i in range(len(text) - 1, 0, -1):
        truncated = text[:i] + "\u2026"
        if font_obj.measure(truncated) <= available_w:
            _set_header_label(truncated)
            return
    _set_header_label("\u2026")

def _set_header_label(text):
    """Set header label text only if it differs, preventing spurious Configure events."""
    if right_column_header_label and right_column_header_label.cget("text") != text:
        right_column_header_label.config(text=text)

def update_list_scrollbar():
    """Sync the custom scrollbar thumb to reflect the current list offset, showing/hiding as needed."""
    if right_column_scrollbar is None:
        return
    needs_scroll = False
    if list_loaded and current_list_content:
        list_size = len(current_list_content)
        entries_count = get_list_entries_count()
        if list_size > entries_count:
            needs_scroll = True
            first = current_list_offset / list_size
            last = min(1.0, (current_list_offset + entries_count) / list_size)
            right_column_scrollbar.set(first, last)
    if needs_scroll:
        if not right_column_scrollbar.winfo_ismapped():
            right_column_scrollbar.pack(side="right", fill="y")
    else:
        if right_column_scrollbar.winfo_ismapped():
            right_column_scrollbar.pack_forget()

def on_list_scrollbar_set(action, *args):
    """Handle scrollbar drag/click to change the list offset."""
    global current_list_offset
    if not list_loaded or not current_list_content:
        return
    list_size = len(current_list_content)
    entries_count = get_list_entries_count()
    max_offset = max(0, list_size - entries_count)
    if action == "moveto":
        fraction = float(args[0])
        current_list_offset = max(0, min(max_offset, round(fraction * list_size)))
    elif action == "scroll":
        amount = int(args[0])
        unit = args[1]
        if unit == "pages":
            current_list_offset = max(0, min(max_offset, current_list_offset + amount * entries_count))
        else:
            current_list_offset = max(0, min(max_offset, current_list_offset + amount))
    refresh_current_list()

def create_persistent_list_buttons(column, target_count=None):
    """Create persistent buttons that will be reused for any list display."""
    global persistent_buttons, button_to_index_map
    
    if target_count is None:
        target_count = get_list_entries_count()
    
    # Clear any existing buttons
    for btn in persistent_buttons:
        try:
            btn.destroy()
        except:
            pass
    
    persistent_buttons = []
    button_to_index_map = {}
    
    # Create buttons based on target count
    entries_count = target_count
    for i in range(entries_count):
        btn = tk.Button(column, text="", borderwidth=0, pady=0,
                       bg="black", fg="white", font=("Consolas", scl(11, "UI")),
                       command=lambda idx=i: handle_persistent_button_click(idx))
        
        # Add all the event bindings
        btn.bind("<Button-3>", lambda e, idx=i: handle_persistent_right_click(e, idx))
        btn.bind("<MouseWheel>", lambda e: handle_list_scroll(e))
        btn.bind("<Button-4>", lambda e: handle_btn_scroll_up(e))
        btn.bind("<Button-5>", lambda e: handle_btn_scroll_down(e))
        btn.bind("<Enter>", lambda e, idx=i: handle_persistent_button_enter(e, idx))
        btn.bind("<Leave>", lambda e, idx=i: handle_persistent_button_leave(e, idx))
        
        if list_loaded == "playlist":
            btn.bind("<Button-1>", lambda e, idx=i: handle_persistent_drag_start(e, idx))
            btn.bind("<B1-Motion>", lambda e: handle_drag_motion(e))
            btn.bind("<ButtonRelease-1>", lambda e: end_playlist_drag(e))
        
        persistent_buttons.append(btn)
    
    return persistent_buttons

def list_scroll_up():
    global current_list_offset
    if list_loaded:
        current_list_offset = max(0, current_list_offset - 1)
        refresh_current_list()

def list_scroll_down():
    global current_list_offset
    if list_loaded:
        list_size = len(current_list_content)
        entries_count = get_list_entries_count()
        max_offset = max(0, list_size - entries_count)
        current_list_offset = min(max_offset, current_list_offset + 1)
        refresh_current_list()

def refresh_current_list():
    """Refresh the current list display without changing the list type."""
    if list_loaded == "playlist":
        # Update the current list content from the actual playlist data
        global current_list_content, current_list_name_func
        
        # Check if fixed lightning round is active
        if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
            rounds = fixed_lightning_round_playlist_data.get("rounds", [])
            current_list_content = convert_fixed_rounds_to_dict(rounds)
            current_list_name_func = get_fixed_round_title
        else:
            current_list_content = convert_playlist_to_dict(playlist["playlist"])
            current_list_name_func = get_title
        
        entries_count = get_list_entries_count()
        current_count = len(persistent_buttons) if persistent_buttons else 0
        
        if current_count != entries_count:
            # Directly recreate buttons and layout
            if persistent_buttons:
                try:
                    column = persistent_buttons[0].master
                    create_persistent_list_buttons(column, entries_count)
                    
                    # Recreate layout
                    column.config(state=tk.NORMAL, wrap="none")
                    column.delete(1.0, tk.END)
                    for button_index in range(entries_count):
                        try:
                            column.window_create(tk.END, window=persistent_buttons[button_index])
                            column.insert(tk.END, "\n")
                        except tk.TclError:
                            pass
                    column.config(state=tk.DISABLED)
                except (IndexError, AttributeError, tk.TclError):
                    return
        
        # For playlist, just update the persistent buttons directly instead of calling show_playlist
        if persistent_buttons and current_list_content:
            start_index = current_list_offset
            end_index = min(len(current_list_content), start_index + entries_count)
            
            for button_index in range(entries_count):
                item_index = start_index + button_index
                if item_index < end_index:
                    update_persistent_button(button_index, item_index, current_list_name_func, current_list_content, current_list_selected)
                else:
                    update_persistent_button(button_index, -1, current_list_name_func, current_list_content, current_list_selected)
        else:
            show_playlist(update=True)
    elif list_loaded and current_list_content:
        # For other lists, update the display directly
        update_persistent_list_display()
    update_list_scrollbar()

def update_persistent_list_display():
    """Update the persistent buttons with current list content."""
    
    if not current_list_content or not current_list_name_func:
        return
    
    list_size = len(current_list_content)
    start_index = current_list_offset
    entries_count = get_list_entries_count()
    end_index = min(list_size, start_index + entries_count)
    
    # Update each persistent button
    for button_index in range(entries_count):
        list_index = start_index + button_index
        if list_index < end_index:
            update_persistent_button(button_index, list_index, current_list_name_func, current_list_content, current_list_selected)
        else:
            try:
                persistent_buttons[button_index].config(text="", state="disabled")
            except (tk.TclError, IndexError):
                pass

def get_display_width(text):
    """Calculate display width treating Unicode icons as 2 characters each."""
    width = 0
    for char in text:
        if char in ['⚡', '📁', stream_icon, '❌']:
            width += 2
        else:
            width += 1
    return width

def truncate_by_display_width(text, max_width):
    """Truncate text based on display width, treating Unicode icons as 2 characters."""
    if get_display_width(text) <= max_width:
        return text
    
    # Find the truncation point
    current_width = 0
    for i, char in enumerate(text):
        char_width = 2 if char in ['⚡', '📁', stream_icon, '❌'] else 1
        if current_width + char_width > max_width:
            return text[:i]
        current_width += char_width
    
    return text

def update_persistent_button(button_index, item_index, name_func, content_dict, selected):
    """Update a single persistent button with new content."""
    
    if button_index >= len(persistent_buttons):
        return
    
    btn = persistent_buttons[button_index]
    
    try:
        if not btn.winfo_exists():
            return
    except tk.TclError:
        return
    
    button_to_index_map[btn] = item_index
    
    items_list = list(content_dict.items())
    if item_index < len(items_list) and item_index >= 0:
        key, value = items_list[item_index]
        index_prefix = str(item_index + 1) + ": " if current_list_show_numbers else ""
        title_part = name_func(key, value)

        max_total_width = 47
        available_width = max_total_width - get_display_width(index_prefix)
        
        if get_display_width(title_part) > available_width:
            keep_width = available_width - 1  # Account for "…" (1 character width)
            if keep_width > 0:
                half_width = keep_width // 2
                # Find truncation points that respect character boundaries
                left_part = truncate_by_display_width(title_part, half_width)
                
                # For right part, work backwards from the end
                right_width = keep_width - get_display_width(left_part)
                right_part = ""
                if right_width > 0:
                    temp_width = 0
                    for i in range(len(title_part) - 1, -1, -1):
                        char = title_part[i]
                        char_width = 2 if char in ['⚡', '📁'] else 1
                        if temp_width + char_width > right_width:
                            break
                        temp_width += char_width
                        right_part = char + right_part
                
                title_part = left_part + "…" + right_part
            else:
                title_part = truncate_by_display_width(title_part, available_width)
        
        name = index_prefix + title_part
        
        # Update button appearance
        if item_index == selected:
            font = ("Consolas", scl(11, "UI"), "bold")
            bg = HIGHLIGHT_COLOR
        elif not disable_shortcuts and item_index == list_index:
            font = ("Consolas", scl(11, "UI"))
            bg = HIGHLIGHT_COLOR
        else:
            font = ("Consolas", scl(11, "UI"))
            bg = "black"
        
        try:
            btn.config(text=name, font=font, bg=bg, fg="white", state="normal")
        except tk.TclError:
            return
    else:
        try:
            btn.config(text="", state="disabled")
        except tk.TclError:
            return

def handle_persistent_button_click(button_index):
    """Handle click on a persistent button."""
    try:
        if button_index < len(persistent_buttons):
            btn = persistent_buttons[button_index]
            if btn in button_to_index_map and btn.winfo_exists():
                actual_index = button_to_index_map[btn]
                if list_func:
                    list_func(actual_index)
    except (tk.TclError, IndexError):
        pass

def handle_persistent_right_click(event, button_index):
    """Handle right click on a persistent button."""
    try:
        if button_index < len(persistent_buttons):
            btn = persistent_buttons[button_index]
            if btn in button_to_index_map and btn.winfo_exists():
                actual_index = button_to_index_map[btn]
                if hasattr(handle_persistent_right_click, 'right_click_func') and handle_persistent_right_click.right_click_func:
                    handle_persistent_right_click.right_click_func(actual_index)
    except (tk.TclError, IndexError):
        pass

def handle_persistent_button_enter(event, button_index):
    """Handle mouse enter on persistent button."""
    if button_index < len(persistent_buttons):
        btn = persistent_buttons[button_index]
        if btn in button_to_index_map:
            actual_index = button_to_index_map[btn]
            on_button_enter(event, actual_index)

def handle_persistent_button_leave(event, button_index):
    """Handle mouse leave on persistent button."""
    if button_index < len(persistent_buttons):
        btn = persistent_buttons[button_index]
        if btn in button_to_index_map:
            actual_index = button_to_index_map[btn]
            on_button_leave(event, actual_index)

def handle_persistent_drag_start(event, button_index):
    """Handle drag start on persistent button."""
    if button_index < len(persistent_buttons):
        btn = persistent_buttons[button_index]
        if btn in button_to_index_map:
            actual_index = button_to_index_map[btn]
            start_playlist_drag(event, actual_index)

def list_set_loaded(type):
    global list_loaded
    list_loaded = type

def list_unload(column):
    global persistent_buttons
    # Clean up persistent buttons when switching away from playlist
    if list_loaded == "playlist" and persistent_buttons:
        for btn in persistent_buttons:
            try:
                btn.destroy()
            except:
                pass
        persistent_buttons = []
    
    list_set_loaded(None)
    update_list_scrollbar()
    update_extra_metadata()

def list_move(amount):
    global list_index, current_list_offset
    if list_loaded and current_list_content:
        # Move selection with wrapping
        old_index = list_index
        list_size = len(current_list_content)
        
        if amount > 0:  # Moving down
            list_index = (list_index + 1) % list_size
        else:  # Moving up
            list_index = (list_index - 1) % list_size
        
        entries_count = get_list_entries_count()
        if list_index < current_list_offset:
            current_list_offset = list_index
            refresh_current_list()
        elif list_index >= current_list_offset + entries_count:
            current_list_offset = list_index - entries_count + 1
            refresh_current_list()
        elif old_index != list_index:
            refresh_current_list()
    else:
        left_column.yview_scroll(amount, "units")
        middle_column.yview_scroll(amount, "units")
        right_column.yview_scroll(amount, "units")

def list_select():
    global _list_action_from_keyboard
    if list_loaded:
        _list_action_from_keyboard = True
        try:
            list_func(list_index)
        finally:
            _list_action_from_keyboard = False



def show_list(type, column, content, name_func, btn_func, selected, update = True, right_click_func=None, items_per_page=None, title=None, show_numbers=True):
    global list_index, list_func, current_list_offset, current_list_content, current_list_name_func, current_list_title, current_list_show_numbers
    
    # Always resolve the new title upfront so we can detect changes
    new_title = title or ""

    list_size = len(content)
    buttons_need_recreation = False
    
    if list_loaded == type and not update:
        list_unload(column)
        return
    elif list_loaded != type:
        list_set_loaded(type)
        if selected < 0:
            list_index = 0
        else:
            list_index = selected
        list_func = btn_func
        current_list_offset = 0
        buttons_need_recreation = True
        
        # For playlist, center on current playing item
        if type == "playlist":
            entries_count = get_list_entries_count()
            # Use fixed round index if active, otherwise regular playlist index
            if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
                current_playing = fixed_lightning_round_playlist_data.get("current_index", -1)
            else:
                current_playing = playlist.get("current_index", -1)
            if current_playing >= 0:
                current_list_offset = max(0, current_playing - entries_count // 2)
                max_offset = max(0, list_size - entries_count)
                current_list_offset = min(current_list_offset, max_offset)
    elif list_index >= list_size:
        list_index = 0
    elif list_index < 0:
        list_index = list_size - 1
    
    # Store current list data
    current_list_content = content
    current_list_name_func = name_func
    
    global current_list_selected
    current_list_selected = selected
    current_list_show_numbers = show_numbers
    
    if type == "playlist":
        global playlist_page_offset
        playlist_page_offset = current_list_offset

    list_func = btn_func
    handle_persistent_right_click.right_click_func = right_click_func

    # Apply title and update header visibility
    current_list_title = new_title
    _insert_list_title_row(column)

    # Only clear and recreate layout when switching list types
    if buttons_need_recreation:
        column.config(state=tk.NORMAL, wrap="none", spacing1=0, spacing3=0)
        column.delete(1.0, tk.END)
        
        entries_count = get_list_entries_count()
        if not persistent_buttons or len(persistent_buttons) != entries_count:
            create_persistent_list_buttons(column, entries_count)
        else:
            pass  # Button count matches, no recreation needed
        
        # Add buttons to layout
        for button_index in range(entries_count):
            try:
                column.window_create(tk.END, window=persistent_buttons[button_index])
                column.insert(tk.END, "\n")
            except tk.TclError:
                # Button was destroyed, recreate persistent buttons
                create_persistent_list_buttons(column, entries_count)
                column.window_create(tk.END, window=persistent_buttons[button_index])
                column.insert(tk.END, "\n")
        
        column.config(state=tk.DISABLED, spacing1=0, spacing3=0)
    
    # Calculate display boundaries
    entries_count = get_list_entries_count()
    start_index = current_list_offset
    end_index = min(list_size, start_index + entries_count)
    
    if start_index >= list_size:
        current_list_offset = max(0, list_size - entries_count)
        start_index = current_list_offset
        end_index = min(list_size, start_index + entries_count)
    
    # Update each persistent button with current content (no layout changes needed)
    for button_index in range(entries_count):
        item_index = start_index + button_index
        if item_index < end_index:
            update_persistent_button(button_index, item_index, name_func, content, selected)
        else:
            update_persistent_button(button_index, -1, name_func, content, selected)
    
    if buttons_need_recreation:
        # Don't steal focus from the search bar entry
        is_search = type in ("search", "search_add")
        if not (is_search and search_bar_entry and search_bar_entry.winfo_exists()):
            column.focus_set()
    update_list_scrollbar()

# Drag and drop variables
drag_start_index = None
drag_current_y = None

hovered_button_index = None
external_drag_active = False

def start_playlist_drag(event, index):
    """Start dragging a playlist item."""
    global drag_start_index, drag_current_y
    
    # Don't allow dragging for fixed lightning rounds
    if fixed_lightning_round_playlist_data and fixed_lightning_round_playlist_data.get("rounds"):
        return
    
    # Clear any existing highlighting
    clear_drop_highlight()
    
    drag_start_index = index
    drag_current_y = event.y_root
    
    # Highlight the source item being dragged
    highlight_drag_source(index)

def handle_drag_motion(event):
    """Handle dragging motion - can be called from any button."""
    global drag_current_y
    if drag_start_index is None:
        return
    
    drag_current_y = event.y_root
    
    # Update cursor to show dragging is active
    try:
        event.widget.configure(cursor="hand2")
    except (tk.TclError, AttributeError):
        pass
    
    # Calculate and highlight drop target position
    try:
        # Get the widget under the mouse cursor
        widget_under_mouse = root.winfo_containing(event.x_root, event.y_root)
        
        # Clear only target highlights (preserve source highlight)
        clear_target_highlights()
        
        # If we're over a button, highlight it
        if widget_under_mouse and hasattr(widget_under_mouse, 'cget'):
            try:
                button_text = widget_under_mouse.cget('text')
                # Extract index from button text (format: "1: Title Name")
                if ':' in button_text:
                    index_str = button_text.split(':')[0].strip()
                    if index_str.isdigit():
                        target_index = int(index_str) - 1  # Convert to 0-based
                        
                        if target_index != drag_start_index and 0 <= target_index < len(playlist["playlist"]):
                            # Store original colors and highlight
                            highlighted_buttons[target_index] = {
                                'widget': widget_under_mouse,
                                'original_bg': widget_under_mouse.cget('bg'),
                                'original_fg': widget_under_mouse.cget('fg'),
                                'is_target': True
                            }
                            widget_under_mouse.configure(bg=HIGHLIGHT_COLOR, fg="white")
            except (tk.TclError, AttributeError, ValueError):
                pass
            
    except (ValueError, tk.TclError, AttributeError):
        pass

# Global variables to track highlight tags
current_highlight_tag = None
current_source_tag = None
highlighted_buttons = {}  # Track highlighted button widgets

def highlight_drag_source(source_index):
    """Highlight the source item being dragged to look like it's pressed."""
    
    if list_loaded != "playlist":
        return
        
    try:
        highlight_button_at_index(source_index, "white", "black", is_source=True)
        
    except (tk.TclError, AttributeError, ValueError):
        pass


def highlight_button_at_index(target_index, bg_color, fg_color, is_source=False):
    """Highlight the button widget at the specified playlist index."""
    
    try:
        # Find all button widgets in the right_column
        for widget_name in right_column.children:
            widget = right_column.nametowidget(widget_name)
            if hasattr(widget, 'configure') and hasattr(widget, 'cget'):
                try:
                    button_text = widget.cget('text')
                    if button_text.startswith(f"{target_index + 1}:"):
                        # Store original colors
                        if target_index not in highlighted_buttons:
                            highlighted_buttons[target_index] = {
                                'widget': widget,
                                'original_bg': widget.cget('bg'),
                                'original_fg': widget.cget('fg'),
                                'is_source': is_source,
                                'is_target': not is_source
                            }
                        # Apply highlight
                        widget.configure(bg=bg_color, fg=fg_color)
                        break
                except (tk.TclError, AttributeError):
                    continue
    except (tk.TclError, AttributeError):
        pass

def clear_button_highlights():
    """Clear all button highlighting and restore original colors."""
    
    try:
        for index, button_data in highlighted_buttons.items():
            widget = button_data['widget']
            if widget and hasattr(widget, 'configure'):
                try:
                    # Restore original colors
                    widget.configure(
                        bg=button_data['original_bg'],
                        fg=button_data['original_fg']
                    )
                except (tk.TclError, AttributeError):
                    pass
        highlighted_buttons.clear()
    except (tk.TclError, AttributeError):
        pass

def clear_target_highlights():
    """Clear only target button highlights, preserve source highlight."""
    
    try:
        # Find and clear only target highlights
        targets_to_remove = []
        for index, button_data in highlighted_buttons.items():
            if button_data.get('is_target', False):
                widget = button_data['widget']
                if widget and hasattr(widget, 'configure'):
                    try:
                        # Restore original colors
                        widget.configure(
                            bg=button_data['original_bg'],
                            fg=button_data['original_fg']
                        )
                        targets_to_remove.append(index)
                    except (tk.TclError, AttributeError):
                        pass
        
        # Remove cleared targets from the dictionary
        for index in targets_to_remove:
            del highlighted_buttons[index]
            
    except (tk.TclError, AttributeError):
        pass

def clear_drop_highlight():
    """Clear any drop target and source highlighting."""
    global current_highlight_tag, current_source_tag
    try:
        # Clear button highlights
        clear_button_highlights()
        
        # Clear any remaining text highlights
        if current_highlight_tag:
            right_column.tag_delete(current_highlight_tag)
            current_highlight_tag = None
        if current_source_tag:
            right_column.tag_delete(current_source_tag)
            current_source_tag = None
    except (tk.TclError, AttributeError):
        pass

def on_button_enter(event, index):
    """Handle mouse entering a button during drag operation."""
    global hovered_button_index
    
    hovered_button_index = index
    
    # Always highlight on hover, unless it's a special button we shouldn't change
    try:
        current_bg = event.widget.cget('bg')
        current_fg = event.widget.cget('fg')
        
        is_current_index = (index == playlist.get("current_index", -1))
        is_drag_source = (drag_start_index is not None and index == drag_start_index)
        
        if not (is_current_index or is_drag_source):
            if index not in highlighted_buttons:
                highlighted_buttons[index] = {
                    'widget': event.widget,
                    'original_bg': current_bg,
                    'original_fg': current_fg
                }
            
            # Apply hover highlight
            event.widget.configure(bg="gray26", fg="white")
        
    except (tk.TclError, AttributeError):
        pass

def on_button_leave(event, index):
    """Handle mouse leaving a button during drag operation."""
    global hovered_button_index
    
    # Clear hover tracking when leaving button
    if hovered_button_index == index:
        hovered_button_index = None
    
    # Restore original colors when leaving (unless it's current index or drag source)
    is_current_index = (index == playlist.get("current_index", -1))
    is_drag_source = (drag_start_index is not None and index == drag_start_index)
    
    if not (is_current_index or is_drag_source) and index in highlighted_buttons:
        try:
            button_data = highlighted_buttons[index]
            event.widget.configure(
                bg=button_data['original_bg'],
                fg=button_data['original_fg']
            )
            del highlighted_buttons[index]
        except (tk.TclError, AttributeError, KeyError):
            pass


def end_playlist_drag(event):
    """End dragging and reorder playlist if needed."""
    global drag_start_index, drag_current_y
    
    if drag_start_index is None:
        return
    
    # Calculate drop position based on mouse position - use same method as visual highlighting
    try:
        # Get the widget under the mouse cursor (same as visual highlighting)
        widget_under_mouse = root.winfo_containing(event.x_root, event.y_root)
        drop_index = None
        
        # If we're over a button, get its index
        if widget_under_mouse and hasattr(widget_under_mouse, 'cget'):
            try:
                button_text = widget_under_mouse.cget('text')
                # Extract index from button text (format: "1: Title Name")
                if ':' in button_text:
                    index_str = button_text.split(':')[0].strip()
                    if index_str.isdigit():
                        display_index = int(index_str) - 1  # Convert to 0-based
                        if list_loaded == "playlist":
                            drop_index = display_index  # display_index already includes pagination offset
                        else:
                            drop_index = display_index
            except (tk.TclError, AttributeError, ValueError):
                pass
        
        # If no button found, try fallback text position method
        if drop_index is None:
            try:
                text_widget = right_column
                x_rel = event.x_root - text_widget.winfo_rootx()
                y_rel = event.y_root - text_widget.winfo_rooty()
                
                if (0 <= x_rel <= text_widget.winfo_width() and 
                    0 <= y_rel <= text_widget.winfo_height()):
                    
                    text_index = text_widget.index(f"@{x_rel},{y_rel}")
                    drop_line = int(text_index.split('.')[0]) - 1  # Convert to 0-based line index
                    
                    if list_loaded == "playlist":
                        # Each line corresponds to a playlist item, add the pagination offset
                        drop_index = max(0, min(drop_line + playlist_page_offset, len(playlist["playlist"]) - 1))
                    else:
                        if "items above" in text_widget.get("1.0", "2.0"):
                            drop_line = max(0, drop_line - 1)
                        
                        drop_index = max(0, min(drop_line, len(playlist["playlist"]) - 1))
            except (ValueError, tk.TclError):
                pass
        
        if (drop_index is not None and 
            drop_index != drag_start_index and 
            0 <= drop_index < len(playlist["playlist"])):
            
            # Reorder the playlist
            item = playlist["playlist"].pop(drag_start_index)
            playlist["playlist"].insert(drop_index, item)
            
            if playlist["current_index"] == drag_start_index:
                playlist["current_index"] = drop_index
            elif drag_start_index < playlist["current_index"] <= drop_index:
                playlist["current_index"] -= 1
            elif drop_index <= playlist["current_index"] < drag_start_index:
                playlist["current_index"] += 1
            
            # Refresh the playlist display
            show_playlist(True)
    
    except Exception as e:
        print(f"Drag and drop error: {e}")
    
    # Clear drop target highlighting
    clear_drop_highlight()
    
    # Reset drag state
    drag_start_index = None
    drag_current_y = None
    
    # Reset cursor
    try:
        event.widget.configure(cursor="")
        right_column.configure(cursor="")
    except (tk.TclError, AttributeError):
        pass


def add_single_line(column, line, title, newline=True):
    column.insert(tk.END, title + ": ", "bold")
    column.insert(tk.END, line, "white")
    if newline:
        column.insert(tk.END, "\n", "white")
    else:
        column.insert(tk.END, "   ", "white")

def open_shortcut_editor():
    """Interactive keyboard shortcut viewer and editor."""

    _SECTION_NAMES = {
        "playlist":   "Playlist",
        "queue":      "Queue",
        "popups":     "Popups",
        "toggles":    "Toggles",
        "theme":      "Theme",
        "hidden":     "Hidden / Controls",
        "scoreboard": "Scoreboard",
        "directory":  "Directory",
        "file":       "File",
    }
    _MODIFIER_KEYSYMS = {
        "Shift_L", "Shift_R", "Control_L", "Control_R",
        "Alt_L", "Alt_R", "Meta_L", "Meta_R",
        "Super_L", "Super_R", "Caps_Lock", "Num_Lock", "Scroll_Lock",
    }

    def _collect_shortcuttable():
        """Walk registry and return {section_key: [items]} for items with shortcut=True."""
        result = {}
        for section_key, items in _get_menu_registry().items():
            section_items = []
            for entry in items:
                if entry == "---" or not isinstance(entry, dict):
                    continue
                if entry.get("shortcut"):
                    section_items.append(entry)
                for sub in entry.get("submenu", []):
                    if isinstance(sub, dict) and sub.get("shortcut"):
                        section_items.append(sub)
            if section_items:
                result[section_key] = section_items
        return result

    shortcuttable = _collect_shortcuttable()
    flat  = get_flat_registry()
    draft = dict(shortcuts_config)   # working copy — committed only on Save

    BG         = BACKGROUND_COLOR
    FG         = "white"
    DIM        = "#888888"
    CAPTURE_BG = "#1e3a6e"
    CAPTURE_FG = "#ffdd44"
    BTN_BG     = "#2a2a2a"
    SAVE_BG    = "#1c5c1c"
    CLEAR_BG   = "#5c1c1c"

    win = tk.Toplevel()
    win.title("Keyboard Shortcuts")
    win.configure(bg=BG)
    win.resizable(False, True)
    get_window_position_and_setup(win)

    # ── search bar ───────────────────────────────────────────────────────────
    search_frame = tk.Frame(win, bg=BG)
    search_frame.pack(fill="x", padx=8, pady=(8, 0))
    tk.Label(search_frame, text="🔍", bg=BG, fg=DIM,
             font=("Arial", scl(10))).pack(side="left")
    search_var = tk.StringVar()
    search_entry = tk.Entry(search_frame, textvariable=search_var, bg="#1a1a1a",
                            fg=FG, insertbackground=FG, relief="flat",
                            font=("Arial", scl(10)), bd=4)
    search_entry.pack(side="left", fill="x", expand=True, padx=4)

    # ── scrollable area ──────────────────────────────────────────────────────
    scroll_frame = tk.Frame(win, bg=BG)
    scroll_frame.pack(fill="both", expand=True, padx=8, pady=(4, 0))

    canvas = tk.Canvas(scroll_frame, bg=BG, highlightthickness=0)
    vsb    = tk.Scrollbar(scroll_frame, orient="vertical", command=canvas.yview)
    canvas.configure(yscrollcommand=vsb.set)
    vsb.pack(side="right", fill="y")
    canvas.pack(side="left", fill="both", expand=True)

    inner = tk.Frame(canvas, bg=BG)
    cwin  = canvas.create_window((0, 0), window=inner, anchor="nw")

    inner.bind("<Configure>", lambda e: canvas.configure(scrollregion=canvas.bbox("all")))
    canvas.bind("<Configure>", lambda e: canvas.itemconfig(cwin, width=e.width))

    # Bind scroll wheel only while mouse is over the scroll area
    def _scroll(e):
        canvas.yview_scroll(-1 if e.delta > 0 else 1, "units")
    scroll_frame.bind("<Enter>", lambda e: canvas.bind_all("<MouseWheel>", _scroll))
    scroll_frame.bind("<Leave>", lambda e: canvas.unbind_all("<MouseWheel>"))

    # ── state ────────────────────────────────────────────────────────────────
    capturing_id    = [None]
    row_frames      = {}   # item_id → tk.Frame
    key_labels      = {}   # item_id → key tk.Label
    section_hdrs    = {}   # section_key → header tk.Frame
    row_search_text = {}   # item_id → lower-case label text

    # ── helpers ──────────────────────────────────────────────────────────────
    def _effective_key(item_id):
        # draft[item_id] = ""  means explicitly cleared (no key)
        # item_id not in draft means fall back to DEFAULT_SHORTCUTS
        if item_id in draft:
            return draft[item_id] or None
        return DEFAULT_SHORTCUTS.get(item_id) or None

    def _display_key(item_id):
        k = _effective_key(item_id)
        if not k:
            return ""
        return _shortcut_display_name(k) or k

    def _all_shortcuttable_ids():
        return {item["id"] for items in shortcuttable.values()
                for item in items if item.get("id")}

    def _conflict_for(new_key, exclude_id):
        for aid in _all_shortcuttable_ids():
            if aid == exclude_id:
                continue
            if _effective_key(aid) == new_key:
                item = flat.get(aid, {})
                return item.get("label") or aid.replace("_", " ").title()
        return None

    # ── row filter ────────────────────────────────────────────────────────────
    def _apply_filter(*_):
        q = search_var.get().lower().strip()
        for section_key, hdr in section_hdrs.items():
            section_visible = False
            for item in shortcuttable.get(section_key, []):
                item_id = item.get("id")
                if not item_id:
                    continue
                rf = row_frames.get(item_id)
                if not rf:
                    continue
                match = not q or q in row_search_text.get(item_id, "")
                if match:
                    rf.pack(fill="x", padx=8, pady=1)
                    section_visible = True
                else:
                    rf.pack_forget()
            if section_visible:
                hdr.pack(fill="x", pady=(8, 1))
            else:
                hdr.pack_forget()
        canvas.after(10, lambda: canvas.configure(scrollregion=canvas.bbox("all")))

    search_var.trace_add("write", _apply_filter)

    # ── capture mode ─────────────────────────────────────────────────────────
    def _set_row_colors(item_id, bg, key_fg):
        rf = row_frames.get(item_id)
        kl = key_labels.get(item_id)
        if rf:
            rf.configure(bg=bg)
            for child in rf.winfo_children():
                try:
                    child.configure(bg=bg)
                except tk.TclError:
                    pass
        if kl:
            kl.configure(bg=bg, fg=key_fg)

    def _exit_capture(item_id):
        capturing_id[0] = None
        win.unbind("<KeyPress>")
        _set_row_colors(item_id, BG, FG)
        if item_id in key_labels:
            key_labels[item_id].configure(text=_display_key(item_id))

    def _enter_capture(item_id):
        prev = capturing_id[0]
        if prev:
            _exit_capture(prev)
        if prev == item_id:
            return   # clicking active row again cancels capture
        capturing_id[0] = item_id
        _set_row_colors(item_id, CAPTURE_BG, CAPTURE_FG)
        key_labels[item_id].configure(text="press key…")
        win.bind("<KeyPress>", _on_key_capture)
        win.focus_force()

    def _on_key_capture(event):
        item_id = capturing_id[0]
        if not item_id:
            return
        if event.keysym == "Escape":
            _exit_capture(item_id)
            return
        if event.keysym in _MODIFIER_KEYSYMS:
            return
        if event.char and event.char.isprintable() and len(event.char) == 1:
            new_key = event.char
        elif event.keysym in ("BackSpace", "Delete", "Return", "Tab"):
            new_key = event.keysym
        else:
            return
        conflict = _conflict_for(new_key, item_id)
        if conflict:
            kl = key_labels[item_id]
            kl.configure(text=f"used by: {conflict}", fg="#ff6666", bg=CAPTURE_BG)
            win.after(1600, lambda: _exit_capture(item_id))
            return
        draft[item_id] = new_key
        _exit_capture(item_id)

    def _reset_one(item_id):
        """Remove override — falls back to default (or blank if no default)."""
        draft.pop(item_id, None)
        if capturing_id[0] == item_id:
            _exit_capture(item_id)
        elif item_id in key_labels:
            key_labels[item_id].configure(text=_display_key(item_id))

    def _clear_one(item_id):
        """Explicitly unassign — no key even if there's a default."""
        if capturing_id[0] == item_id:
            _exit_capture(item_id)
        if item_id in DEFAULT_SHORTCUTS:
            draft[item_id] = ""   # explicit override: no key
        else:
            draft.pop(item_id, None)
        if item_id in key_labels:
            key_labels[item_id].configure(text="", fg=FG, bg=BG)

    # ── build rows ────────────────────────────────────────────────────────────
    fnt_section = ("Arial", scl(9),  "bold")
    fnt_row     = ("Arial", scl(10))
    fnt_key     = ("Courier New", scl(10), "bold")
    fnt_dim     = ("Arial", scl(8))

    for section_key, items in shortcuttable.items():
        section_title = _SECTION_NAMES.get(section_key,
                                           section_key.replace("_", " ").title())
        sh = tk.Frame(inner, bg=BG)
        sh.pack(fill="x", pady=(8, 1))
        section_hdrs[section_key] = sh
        tk.Label(sh, text=section_title.upper(), font=fnt_section,
                 bg=BG, fg=DIM).pack(side="left", padx=8)
        tk.Frame(sh, bg=DIM, height=1).pack(side="left", fill="x", expand=True, padx=4, pady=6)

        for item in items:
            item_id    = item.get("id")
            if not item_id:
                continue
            label_text = item.get("label") or item_id.replace("_", " ").title()
            row_search_text[item_id] = label_text.lower()

            is_fixed    = item_id in FIXED_SHORTCUTS
            default_key = DEFAULT_SHORTCUTS.get(item_id)
            if is_fixed:
                fixed_key, _fixed_lbl, _fixed_note = FIXED_SHORTCUTS[item_id]
                def_display = _shortcut_display_name(fixed_key) or fixed_key
            else:
                def_display = (_shortcut_display_name(default_key) or default_key) if default_key else ""

            row = tk.Frame(inner, bg=BG)
            row.pack(fill="x", padx=8, pady=1)
            row_frames[item_id] = row

            tk.Label(row, text=label_text, font=fnt_row, bg=BG, fg=FG,
                     anchor="w").pack(side="left", fill="x", expand=True)

            if is_fixed:
                # Fixed row: bright key display + "hardcoded" label on the right, no edit controls
                tk.Label(row, text="hardcoded", font=fnt_dim, bg=BG, fg=DIM,
                         width=9, anchor="e").pack(side="left")
                tk.Label(row, text=def_display, font=fnt_key,
                         bg=BG, fg=FG, width=6, anchor="center",
                         relief="groove").pack(side="left", padx=(4, 2))
                # Spacer to align with the two buttons on editable rows
                tk.Label(row, text="", bg=BG, width=4).pack(side="left", padx=(0, 2))
            else:
                tk.Label(row, text=f"({def_display})" if def_display else "",
                         font=fnt_dim, bg=BG, fg=DIM, width=6, anchor="e").pack(side="left")

                kl = tk.Label(row, text=_display_key(item_id), font=fnt_key,
                              bg=BG, fg=FG, width=6, anchor="center",
                              relief="groove", cursor="hand2")
                kl.pack(side="left", padx=(4, 2))
                key_labels[item_id] = kl
                kl.bind("<Button-1>",  lambda e, i=item_id: _enter_capture(i))
                row.bind("<Button-1>", lambda e, i=item_id: _enter_capture(i))

                tk.Button(row, text="×", font=fnt_row, bg=BTN_BG, fg="#cc4444",
                          relief="flat", bd=0, cursor="hand2",
                          command=lambda i=item_id: _clear_one(i)).pack(side="left", padx=(0, 1))
                tk.Button(row, text="↺", font=fnt_row, bg=BTN_BG, fg=DIM,
                          relief="flat", bd=0, cursor="hand2",
                          command=lambda i=item_id: _reset_one(i)).pack(side="left", padx=(0, 2))

    # ── fixed-only section: keys with no registry entry ──────────────────────
    registry_ids = set(row_frames.keys())
    extra_fixed  = [(fid, fdata) for fid, fdata in FIXED_SHORTCUTS.items()
                    if fid not in registry_ids]
    if extra_fixed:
        sh = tk.Frame(inner, bg=BG)
        sh.pack(fill="x", pady=(8, 1))
        section_hdrs["_fixed_extra"] = sh
        tk.Label(sh, text="ALWAYS-ON KEYS", font=fnt_section,
                 bg=BG, fg=DIM).pack(side="left", padx=8)
        tk.Frame(sh, bg=DIM, height=1).pack(side="left", fill="x", expand=True, padx=4, pady=6)

        for fid, (fkey, flabel, fnote) in extra_fixed:
            fkey_display = _shortcut_display_name(fkey) or fkey
            hint_text    = fnote or "hardcoded"
            row_search_text[fid] = flabel.lower()
            row = tk.Frame(inner, bg=BG)
            row.pack(fill="x", padx=8, pady=1)
            row_frames[fid] = row

            tk.Label(row, text=flabel, font=fnt_row, bg=BG, fg=FG,
                     anchor="w").pack(side="left", fill="x", expand=True)
            tk.Label(row, text=hint_text, font=fnt_dim, bg=BG, fg=DIM,
                     width=9, anchor="e").pack(side="left")
            tk.Label(row, text=fkey_display, font=fnt_key,
                     bg=BG, fg=FG, width=6, anchor="center",
                     relief="groove").pack(side="left", padx=(4, 2))
            tk.Label(row, text="", bg=BG, width=4).pack(side="left", padx=(0, 2))

        # Register extra entries into the section filtering dict
        shortcuttable["_fixed_extra"] = [{"id": fid} for fid, _ in extra_fixed]
        _SECTION_NAMES["_fixed_extra"] = "Always-on Keys"

    # ── bottom bar ────────────────────────────────────────────────────────────
    bar = tk.Frame(win, bg=BG)
    bar.pack(fill="x", padx=8, pady=8)

    def _reset_all():
        if not messagebox.askyesno("Reset All Shortcuts",
                                   "Reset all shortcuts to their defaults?",
                                   parent=win):
            return
        draft.clear()
        if capturing_id[0]:
            _exit_capture(capturing_id[0])
        for iid, kl in key_labels.items():
            kl.configure(text=_display_key(iid), fg=FG, bg=BG)

    def _clear_all():
        if not messagebox.askyesno("Clear All Shortcuts",
                                   "Remove all shortcut assignments, including defaults?",
                                   parent=win):
            return
        if capturing_id[0]:
            _exit_capture(capturing_id[0])
        for iid in _all_shortcuttable_ids():
            if iid in FIXED_SHORTCUTS:
                continue   # hardcoded — cannot clear
            if iid in DEFAULT_SHORTCUTS:
                draft[iid] = ""
            else:
                draft.pop(iid, None)
        for iid, kl in key_labels.items():
            kl.configure(text="", fg=FG, bg=BG)

    def _save():
        global shortcuts_config
        if capturing_id[0]:
            _exit_capture(capturing_id[0])
        shortcuts_config = {k: v for k, v in draft.items()
                            if v != DEFAULT_SHORTCUTS.get(k)}
        rebuild_shortcut_dispatch()
        bind_shortcuts()
        save_config()

    def _cancel():
        if capturing_id[0]:
            _exit_capture(capturing_id[0])
        canvas.unbind_all("<MouseWheel>")
        win.destroy()

    win.protocol("WM_DELETE_WINDOW", _cancel)

    left_bar = tk.Frame(bar, bg=BG)
    left_bar.pack(side="left")
    tk.Button(left_bar, text="Reset All to Defaults", font=fnt_row,
              bg=BTN_BG, fg="white", relief="flat", bd=0,
              padx=8, pady=4, command=_reset_all).pack(side="left", padx=(0, 4))
    tk.Button(left_bar, text="Clear All", font=fnt_row,
              bg=CLEAR_BG, fg="white", relief="flat", bd=0,
              padx=8, pady=4, command=_clear_all).pack(side="left")

    tk.Button(bar, text="Cancel", font=fnt_row,
              bg=BTN_BG, fg="white", relief="flat", bd=0,
              padx=12, pady=4, command=_cancel).pack(side="right", padx=4)
    tk.Button(bar, text="Save", font=fnt_row,
              bg=SAVE_BG, fg="white", relief="flat", bd=0,
              padx=16, pady=4, command=_save).pack(side="right", padx=4)

    win.update_idletasks()
    x, y = win.winfo_x(), win.winfo_y()
    win.geometry(f"480x640+{x}+{y}")
    win.minsize(460, 400)
    win.maxsize(700, 1000)

