# Volume Control
def set_volume(value):
    """Sets the volume based on value input (0 to 100)."""
    global volume_level
    volume_level = int(value)
    if streaming.currently_streaming:
        volume_adjustment = fixed_current_round.get("volume_adjustment", 0) if fixed_current_round else 0
        _stream_volume_level = int(volume_level * (1 + ((stream_volume_boost + volume_adjustment) / 100)))
        player.audio_set_volume(_stream_volume_level)
    else:
        player.audio_set_volume(volume_level)
    if music_loaded:
        if disable_video_audio or volume_level == 0:
            vol = 0.0
        else:
            # dB-based curve: perceptually linear across the full scale.
            # BGM_DB_RANGE controls how many dB separate silence (0%) from full (100%).
            # 40dB is standard for audio faders; increase for a steeper drop-off.
            BGM_DB_RANGE = 45
            vol = bgm_volume * (10 ** ((volume_level / 200 - 1) * BGM_DB_RANGE / 20))
        pygame.mixer.music.set_volume(vol)  # Adjust volume
    update_volume_display()

def update_volume_display():
    """Update the volume label display."""
    volume_label.config(text=str(volume_level))

def increase_volume():
    """Increase volume by 5."""
    global volume_level
    volume_level = min(200, volume_level + 5)
    set_volume(volume_level)

def decrease_volume():
    """Decrease volume by 5."""
    global volume_level
    volume_level = max(0, volume_level - 5)
    set_volume(volume_level)

def increase_volume_small(event=None):
    """Increase volume by 1 (used for right-click)."""
    global volume_level
    volume_level = min(200, volume_level + 1)
    set_volume(volume_level)
    return "break"

def decrease_volume_small(event=None):
    """Decrease volume by 1 (used for right-click)."""
    global volume_level
    volume_level = max(0, volume_level - 1)
    set_volume(volume_level)
    return "break"

