def toggle_autoplay():
    global autoplay_toggle
    if special_repeat_track_mode:
        toggle_special_repeat()
        return
    autoplay_toggle += 1
    if autoplay_toggle == 4:
        autoplay_toggle = 0
    _update_autoplay_button()

