BUZZ_TOAST_MAX_ALPHA = 0.9
_buzz_toast_wins = []   # list of dicts: {win, base_y, cx, h}

def _show_buzz_toast(rank, name):
    """Show a rising, fading toast on-screen when a player buzzes in. Multiple stack upward smoothly."""
    try:
        # Mirror push_player_colors: file is authoritative, in-memory overrides
        merged_colors = {}
        try:
            import json as _json
            _sc_path = os.path.join(web_server._SCOREBOARD_DATA, 'scoreboard_colors.json')
            if os.path.exists(_sc_path):
                with open(_sc_path, 'r', encoding='utf-8') as _f:
                    merged_colors.update(_json.load(_f))
        except Exception:
            pass
        merged_colors.update(web_server._player_colors)
        clr = merged_colors.get(name) or {}
        bg       = clr.get('bg',   OVERLAY_BACKGROUND_COLOR)
        fg       = clr.get('text', OVERLAY_TEXT_COLOR)
        border_c = fg
    except Exception:
        bg       = OVERLAY_BACKGROUND_COLOR
        fg       = OVERLAY_TEXT_COLOR
        border_c = fg

    rank_labels = {1: '1st \u2013 BUZZ IN', 2: '2nd \u2013 BUZZ IN', 3: '3rd \u2013 BUZZ IN'}
    rank_str = rank_labels.get(rank, f'#{rank} \u2013 BUZZ IN')

    mx, my, mw, mh = _get_mpv_window_rect()
    _sw = root.winfo_screenwidth()
    _sh = root.winfo_screenheight()
    mpv_frac = max(0.25, min(1.0, min(mw / max(_sw, 1), mh / max(_sh, 1))))

    win = tk.Toplevel(root)
    win.overrideredirect(True)
    win.attributes('-topmost', True)
    win.attributes('-alpha', 0.0)
    win.configure(bg=border_c)

    border_px = max(1, int(scl(3) * mpv_frac))
    outer = tk.Frame(win, bg=border_c, padx=border_px, pady=border_px)
    outer.pack()
    inner = tk.Frame(outer, bg=bg, padx=int(scl(40) * mpv_frac), pady=int(scl(20) * mpv_frac))
    inner.pack()
    tk.Label(inner, text=rank_str,
             font=('Segoe UI', max(9, int(scl(24, 'UI') * mpv_frac)), 'bold'),
             fg=fg, bg=bg).pack()
    tk.Label(inner, text=name,
             font=('Segoe UI', max(14, int(scl(48, 'UI') * mpv_frac)), 'bold'),
             fg=fg, bg=bg).pack()

    win.update_idletasks()
    w  = win.winfo_width()
    h  = win.winfo_height()

    _pp = bonus_settings.get('buzzer', BONUS_SETTINGS_DEFAULT['buzzer']).get(
        'player_buzz_popup_properties', BONUS_SETTINGS_DEFAULT['buzzer']['player_buzz_popup_properties'])
    margin  = int(scl(int(_pp.get('margin',     40))) * mpv_frac)
    gap     = int(scl(int(_pp.get('gap',        10))) * mpv_frac)
    rise_px = int(scl(int(_pp.get('rise_px',    50))) * mpv_frac)
    PUSH_MS    = int(_pp.get('push_ms',    220))
    PUSH_STEPS = int(_pp.get('push_steps', 18))

    cx      = mx + (mw - w) // 2
    base_y  = my + mh - h - margin

    entry = {'win': win, 'base_y': base_y, 'cx': cx, 'h': h}
    _buzz_toast_wins.append(entry)

    # --- push existing toasts up smoothly ---
    push_amount = h + gap
    PUSH_MS = 220
    PUSH_STEPS = 18
    push_step_ms = max(1, PUSH_MS // PUSH_STEPS)

    # snapshot existing toasts (all except the new one)
    existing = [e for e in _buzz_toast_wins if e is not entry]
    for e in existing:
        e['base_y'] -= push_amount   # update their target base_y

    def _push_others(step=0):
        if step > PUSH_STEPS:
            return
        t = step / PUSH_STEPS
        ease = t * (2 - t)  # ease-out
        for e in existing:
            if not e['win'].winfo_exists():
                continue
            cur_y = int((e['base_y'] + push_amount) - push_amount * ease)
            e['win'].geometry(f"+{e['cx']}+{cur_y}")
        if step < PUSH_STEPS:
            root.after(push_step_ms, lambda: _push_others(step + 1))
        else:
            for e in existing:
                if e['win'].winfo_exists():
                    e['win'].geometry(f"+{e['cx']}+{e['base_y']}")

    root.after(10, _push_others)

    # --- new toast: rise + fade in ---
    _pp = bonus_settings.get('buzzer', BONUS_SETTINGS_DEFAULT['buzzer']).get(
        'player_buzz_popup_properties', BONUS_SETTINGS_DEFAULT['buzzer']['player_buzz_popup_properties'])
    FADE_IN_MS  = int(_pp.get('fade_in_ms',  220))
    HOLD_MS     = int(_pp.get('hold_ms',     2400))
    FADE_OUT_MS = int(_pp.get('fade_out_ms', 350))
    STEPS       = int(_pp.get('steps',       18))
    _max_alpha  = float(_pp.get('max_alpha', BUZZ_TOAST_MAX_ALPHA))
    step_ms     = max(1, FADE_IN_MS // STEPS)
    out_step_ms = max(1, FADE_OUT_MS // STEPS)

    win.geometry(f'+{cx}+{base_y + rise_px}')

    def _fade_in(step=0):
        if not win.winfo_exists():
            return
        try:
            t = step / STEPS
            win.attributes('-alpha', t * _max_alpha)
            win.geometry(f'+{cx}+{int(base_y + rise_px * (1.0 - t))}')
            if step < STEPS:
                root.after(step_ms, lambda: _fade_in(step + 1))
            else:
                win.attributes('-alpha', _max_alpha)
                win.geometry(f'+{cx}+{base_y}')
                root.after(HOLD_MS, _fade_out)
        except Exception:
            pass

    def _fade_out(step=0):
        if not win.winfo_exists():
            return
        try:
            win.attributes('-alpha', _max_alpha * (1.0 - step / STEPS))
            if step < STEPS:
                root.after(out_step_ms, lambda: _fade_out(step + 1))
            else:
                try:
                    _buzz_toast_wins.remove(entry)
                except ValueError:
                    pass
                win.destroy()
        except Exception:
            pass

    root.after(10, _fade_in)


def _play_buzz_sound(rank, name):
    """Play a buzzer sound on the host machine when a player buzzes in."""
    if name != 'Test':
        send_scoreboard_command(f"[BUZZ_ORDER]{rank}:{name}")
    _buz = bonus_settings.get("buzzer", BONUS_SETTINGS_DEFAULT["buzzer"])
    if name != 'Test':
        if _buz.get("player_buzz_popup", True):
            root.after(0, lambda: _show_buzz_toast(rank, name))
    def _make_wav_segments(segments):
        import wave, struct, math, io, random
        rate = 44100
        all_frames = bytearray()
        for seg in segments:
            f1   = float(seg.get('f1', 220))
            f2   = float(seg.get('f2', f1))
            f_end = seg.get('f_end', None)
            wv   = seg.get('wave', _SQ)
            duty = float(seg.get('duty', 0.5))
            dur  = int(seg.get('dur', 300))
            vol  = float(seg.get('vol', 0.7))
            gap  = int(seg.get('gap', 0))
            atk  = int(seg.get('atk', 5))
            rel  = float(seg.get('rel', 0.75))
            n         = int(rate * dur / 1000)
            attack_n  = max(1, int(rate * atk / 1000))
            rel_start = int(n * rel)
            phase1 = 0.0
            phase2 = 0.0
            for i in range(n):
                t     = i / max(1, n - 1)
                cur_f1 = f1 + (f_end - f1) * t if f_end is not None else f1
                cur_f2 = f2
                p1 = phase1 % 1.0
                p2 = phase2 % 1.0
                if wv == _SQ:
                    s1 = 1.0 if p1 < duty else -1.0
                    s2 = 1.0 if p2 < duty else -1.0
                elif wv == _TRI:
                    s1 = (4*p1 - 1) if p1 < 0.5 else (3 - 4*p1)
                    s2 = (4*p2 - 1) if p2 < 0.5 else (3 - 4*p2)
                elif wv == _SAW:
                    s1 = p1 * 2.0 - 1.0
                    s2 = p2 * 2.0 - 1.0
                elif wv == _SIN:
                    s1 = math.sin(phase1 * 2 * math.pi)
                    s2 = math.sin(phase2 * 2 * math.pi)
                elif wv == _NOI:
                    s1 = s2 = random.uniform(-1.0, 1.0)
                else:
                    s1 = s2 = 0.0
                sample_f = (s1 + s2) * 0.5
                if i < attack_n:
                    env = i / attack_n
                elif i >= rel_start:
                    env = 1.0 - (i - rel_start) / max(1, n - rel_start)
                else:
                    env = 1.0
                val = int(sample_f * env * vol * 32767)
                all_frames += struct.pack('<h', max(-32768, min(32767, val)))
                phase1 += cur_f1 / rate
                phase2 += cur_f2 / rate
            if gap > 0:
                all_frames += b'\x00\x00' * int(rate * gap / 1000)
        buf = io.BytesIO()
        with wave.open(buf, 'wb') as w:
            w.setnchannels(1)
            w.setsampwidth(2)
            w.setframerate(rate)
            w.writeframes(bytes(all_frames))
        return buf.getvalue()

    def _beep():
        try:
            import winsound
            _buz_cfg = bonus_settings.get("buzzer", BONUS_SETTINGS_DEFAULT["buzzer"])
            if not _buz_cfg.get("sound", True):
                return
            p = BUZZ_PRESETS[_buzz_preset_index]
            if p[0] == 'No Sound':
                return
            segs = p[1] if rank == 1 else p[2]
            if volume_level <= 0:
                vol_scale = 0.0
            else:
                BGM_DB_RANGE = 45
                vol_scale = 10 ** ((volume_level / 200 - 1) * BGM_DB_RANGE / 20)
            sound_volume = float(_buz_cfg.get("sound_volume", 1.0))
            scaled = [{**s, 'vol': s.get('vol', 0.7) * vol_scale * sound_volume} for s in segs]
            wav = _make_wav_segments(scaled)
            winsound.PlaySound(wav, winsound.SND_MEMORY)
        except Exception:
            pass
    threading.Thread(target=_beep, daemon=True).start()

web_server.set_buzz_callback(_play_buzz_sound)

def _on_skip_grant_changed(name):
    if name:
        send_scoreboard_command(f"[SKIP_GRANT]{name}")
    else:
        send_scoreboard_command("[SKIP_GRANT_CLEAR]")

web_server.set_skip_grant_callback(_on_skip_grant_changed)
scan_directory(True)
create_first_row_buttons()
rebuild_shortcut_dispatch()
threading.Thread(target=load_default_char_images, daemon=True).start()

# Clean up any leftover updater files from previous updates
def cleanup_updater_files():
    """Remove updater.exe and updater.log files if they exist."""
    files_to_clean = ["updater.exe", "updater.log"]
    for filename in files_to_clean:
        if os.path.exists(filename):
            try:
                os.remove(filename)
                print(f"Cleaned up: {filename}")
            except Exception as e:
                print(f"Could not clean up {filename}: {e}")

# Clean up updater files on startup
cleanup_updater_files()

# Add debounced resize handler to refresh list display when window resize is complete
resize_timer_id = None

def on_window_resize(event):
    """Handle window resize events with debouncing - only update after resize is complete."""
    global resize_timer_id
    
    # Only handle resize events from the root window
    if event.widget != root or not list_loaded:
        return
    
    # Cancel any pending resize update
    if resize_timer_id is not None:
        root.after_cancel(resize_timer_id)
    
    # Schedule a new update after 500ms of no resize events (resize finished)
    resize_timer_id = root.after(500, refresh_list_on_resize)

def refresh_list_on_resize():
    """Refresh the current list display with updated button count."""
    global resize_timer_id
    
    # Clear the timer ID since we're executing now
    resize_timer_id = None
    
    if list_loaded and current_list_content is not None:
        current_button_count = len(persistent_buttons) if persistent_buttons else 0
        new_entries_count = get_list_entries_count()
        
        if current_button_count != new_entries_count:
            # Get current list type and refresh it
            # Force recreation of buttons by temporarily clearing list_loaded
            temp_loaded = list_loaded
            list_set_loaded("")
            show_list(temp_loaded, right_column, current_list_content, current_list_name_func,
                      list_func, current_list_selected, update=True, title=current_list_title)

# Bind resize event to root window
root.bind("<Configure>", on_window_resize)

check_download_ui_updates = cache_download.check_download_ui_updates

root.after(1000, create_new_session)

# Start updating the seek bar
root.after(1000, update_seek_bar)
# root.after(1000, check_video_end)  # replaced by mpv end-file event callback (_on_end_file)
# Set initial volume
root.after(1000, set_volume, volume_level)
root.after(1000, cleanup_old_update_exes)
root.after(3000, check_for_updates_on_startup)
root.after(1000, update_living_playlists)
root.after(500, check_download_ui_updates)  # Start checking for download UI updates

def on_app_close():
    """Safely destroy hidden root-parented widgets before closing to avoid TclError."""
    # Cancel any pending tooltip after() callback so it can't fire on a destroyed widget
    if _menu_tooltip_after[0]:
        try:
            root.after_cancel(_menu_tooltip_after[0])
        except Exception:
            pass
        _menu_tooltip_after[0] = None
    if _menu_tooltip_win[0]:
        try:
            _menu_tooltip_win[0].destroy()
        except Exception:
            pass
        _menu_tooltip_win[0] = None

    for name in ("difficulty_dropdown",):
        widget = globals().get(name)
        if widget is not None:
            try:
                widget.unbind_all("<<ComboboxSelected>>")
                widget.destroy()
            except Exception:
                pass
    # quit() exits the mainloop cleanly before destroy() tears down the widgets
    try:
        web_server.stop()
    except Exception:
        pass
    try:
        save_config()
    except Exception:
        pass
    if AUTO_EXIT_SCOREBOARD and is_scoreboard_running():
        send_scoreboard_command("quit")
    try:
        root.quit()
    except Exception:
        pass
    try:
        root.destroy()
    except Exception:
        pass

root.protocol("WM_DELETE_WINDOW", on_app_close)

# Start the mpv click poller (drains _mpv_click_queue on the main thread)
root.after(50, _poll_mpv_clicks)

# Auto-open tutorial on first launch (tutorial_shown is False until user closes it once)
if not tutorial_shown:
    root.after(500, show_tutorial_popup)

# Restore saved collapsed state (applied after UI is fully rendered)
if globals().get('_pending_restore_collapsed'):
    root.after(100, toggle_player_collapse)

root.mainloop()